# CAPITULO 1: FEATURE ENGINEERING AVANZADO (Pattern Recognition)
# ==================================================


def _ema_series(series: pd.Series, period: int) -> pd.Series:
    values = series.to_numpy(dtype=float)
    if values.size == 0:
        return pd.Series(values, index=series.index)
    if TALIB_AVAILABLE:
        result = talib.EMA(values, timeperiod=period)
        return pd.Series(result, index=series.index)
    alpha = 2.0 / (period + 1.0)
    ema = np.empty_like(values, dtype=float)
    ema[:] = np.nan
    ema[0] = values[0]
    for i in range(1, len(values)):
        ema[i] = alpha * values[i] + (1.0 - alpha) * ema[i - 1]
    return pd.Series(ema, index=series.index)


def _rsi_series(series: pd.Series, period: int = 14) -> pd.Series:
    values = series.to_numpy(dtype=float)
    n = len(values)
    if n == 0:
        return pd.Series(values, index=series.index)
    if TALIB_AVAILABLE:
        result = talib.RSI(values, timeperiod=period)
        return pd.Series(result, index=series.index)
    delta = np.diff(values)
    gains = np.where(delta > 0, delta, 0.0)
    losses = np.where(delta < 0, -delta, 0.0)
    rsi = np.full(n, np.nan, dtype=float)
    if n <= period:
        return pd.Series(rsi, index=series.index)
    avg_gain = np.nanmean(gains[:period])
    avg_loss = np.nanmean(losses[:period])
    rs = avg_gain / (avg_loss + 1e-10)
    rsi[period] = 100.0 - (100.0 / (1.0 + rs))
    for i in range(period + 1, n):
        avg_gain = (avg_gain * (period - 1) + gains[i - 1]) / period
        avg_loss = (avg_loss * (period - 1) + losses[i - 1]) / period
        rs = avg_gain / (avg_loss + 1e-10)
        rsi[i] = 100.0 - (100.0 / (1.0 + rs))
    return pd.Series(rsi, index=series.index)


def _atr_series(high: pd.Series, low: pd.Series,
                close: pd.Series, period: int = 14) -> pd.Series:
    h = high.to_numpy(dtype=float)
    l = low.to_numpy(dtype=float)
    c = close.to_numpy(dtype=float)
    n = len(c)
    if n == 0:
        return pd.Series(c, index=high.index)
    prev_close = np.roll(c, 1)
    prev_close[0] = c[0]
    tr = np.maximum(h - l, np.maximum(np.abs(h - prev_close), np.abs(l - prev_close)))
    atr = np.full(n, np.nan, dtype=float)
    if n >= period:
        atr[period - 1] = np.nanmean(tr[:period])
        for i in range(period, n):
            atr[i] = (atr[i - 1] * (period - 1) + tr[i]) / period
    return pd.Series(atr, index=high.index)


def _atr_last_from_arrays(high: np.ndarray, low: np.ndarray,
                          close: np.ndarray, period: int = 14) -> float:
    if close.size == 0:
        return 0.0
    prev_close = np.roll(close, 1)
    prev_close[0] = close[0]
    tr = np.maximum(high - low, np.maximum(np.abs(high - prev_close), np.abs(low - prev_close)))
    if tr.size == 0:
        return 0.0
    if tr.size < period:
        val = float(np.nanmean(tr))
        return val if np.isfinite(val) else 0.0
    val = float(np.nanmean(tr[-period:]))
    return val if np.isfinite(val) else 0.0


class FeatureExtractor:
    """
    Extrae EXACTAMENTE 15 características numéricas estables y normalizadas.
    Diseñado para aprendizaje online (SGDClassifier) con datos reales en binarias.
    """

    def __init__(self):
        self.feature_names = [
            'dist_ema_20',          # 0
            'dist_ema_50',          # 1
            'rsi',                  # 2
            'volatility',           # 3
            'vol_spike',            # 4
            'close_lag1',           # 5
            'close_lag2',           # 6
            'high_lag1',            # 7
            'low_lag1',             # 8
            'body_lag1',            # 9
            'price_change_t1',      # 10
            'price_change_t2',      # 11
            'ema_slope',            # 12
            'price_vs_ema_range',   # 13
            'volume_avg_diff'       # 14
        ]

    def calculate_features(self, df: pd.DataFrame) -> np.ndarray:
        # --- VALIDACIÓN FUERTE ---
        if df is None or len(df) < 60:
            return np.zeros((1, 15), dtype=np.float32)

        df = df.copy()

        # Asegurar tipos
        for col in ['open', 'high', 'low', 'close', 'volume']:
            df[col] = df[col].astype(float)

        # ===============================
        # 1️⃣ TENDENCIA (EMA)
        # ===============================
        df['ema_20'] = _ema_series(df['close'], 20)
        df['ema_50'] = _ema_series(df['close'], 50)

        df['dist_ema_20'] = (df['close'] - df['ema_20']) / \
            (df['ema_20'] + 1e-10)
        df['dist_ema_50'] = (df['close'] - df['ema_50']) / \
            (df['ema_50'] + 1e-10)

        # Pendiente relativa (no absoluta)
        df['ema_slope'] = df['ema_20'].diff() / (df['ema_20'] + 1e-10)

        # ===============================
        # 2️⃣ MOMENTUM (RSI)
        # ===============================
        df['rsi'] = _rsi_series(df['close'], 14).clip(0, 100)

        # ===============================
        # 3️⃣ VOLATILIDAD REAL (ATR)
        # ===============================
        df['atr'] = _atr_series(df['high'], df['low'], df['close'], 14)

        df['volatility'] = df['atr'] / (df['close'] + 1e-10)

        # ===============================
        # 4️⃣ VOLUMEN (SMART MONEY)
        # ===============================
        df['vol_sma'] = df['volume'].rolling(20).mean()
        df['vol_spike'] = df['volume'] / (df['vol_sma'] + 1e-10)
        df['volume_avg_diff'] = (
            df['volume'] - df['vol_sma']) / (df['vol_sma'] + 1e-10)

        # ===============================
        # 5️⃣ CONTEXTO TEMPORAL (LAGS)
        # ===============================
        df['close_lag1'] = (df['close'].shift(
            1) - df['close']) / (df['close'] + 1e-10)
        df['close_lag2'] = (df['close'].shift(
            2) - df['close']) / (df['close'] + 1e-10)

        df['high_lag1'] = (df['high'].shift(1) - df['close']
                           ) / (df['close'] + 1e-10)
        df['low_lag1'] = (df['low'].shift(1) - df['close']) / \
            (df['close'] + 1e-10)

        df['body_lag1'] = (df['close'].shift(
            1) - df['open'].shift(1)) / (df['close'] + 1e-10)

        df['price_change_t1'] = df['close'].pct_change(1)
        df['price_change_t2'] = df['close'].pct_change(2)

        # ===============================
        # 6️⃣ PRECISIÓN DE ENTRADA
        # ===============================
        df['price_vs_ema_range'] = abs(
            df['close'] - df['ema_20']) / (df['atr'] + 1e-10)

        # ===============================
        # 7️⃣ SELECCIÓN FINAL (FIJA)
        # ===============================
        features = df[self.feature_names].fillna(
            0.0).tail(1).values.astype(np.float32)

        # Validación crítica
        if features.shape != (1, 15):
            raise ValueError(
                f"FeatureExtractor ERROR: shape inválido {
                    features.shape}")

        return features

