class AIEngineContinuous:
    """
    Motor IA continuo con aprendizaje REAL por batch.
    Aprende SOLO de resultados reales (WIN / LOSS).
    Optimizado para binarias (una operación a la vez).
    """

    def __init__(self, config):
        self.config = config
        self.logger = logging.getLogger(__name__)
        self._last_trade_id = None

        self.extractor = FeatureExtractor()
        self.model_path = datos_rel("modelo_continuo.pkl")
        self.scaler_path = datos_rel("scaler_continuo.pkl")

        from sklearn.linear_model import SGDClassifier
        from sklearn.preprocessing import StandardScaler

        self.model = SGDClassifier(
            loss='log_loss',
            penalty='l2',
            alpha=1e-4,
            learning_rate='optimal',
            warm_start=True,
            max_iter=1
        )

        self.scaler = StandardScaler()
        self._lock = threading.RLock()

        self._is_initialized = False
        self._last_features = None
        self._last_direction = None  # CALL / PUT

        # Batch learning
        self.batch_size = 5
        self.trade_buffer = deque(maxlen=self.batch_size)

        self.logger.info(
            f"🧠 AIEngineContinuous listo | Batch Learning REAL ({
                self.batch_size} ops)"
        )
        self._try_load_persisted_state()

    def _try_load_persisted_state(self) -> None:
        try:
            import joblib
            model_loaded = False
            scaler_loaded = False
            if os.path.exists(self.model_path):
                self.model = joblib.load(self.model_path)
                model_loaded = True
            if os.path.exists(self.scaler_path):
                self.scaler = joblib.load(self.scaler_path)
                scaler_loaded = True
            if model_loaded and scaler_loaded:
                self._is_initialized = True
                self.logger.info("✅ IA cargada desde disco (modelo+scaler)")
        except Exception as e:
            self.logger.debug(f"No se pudo cargar IA persistida: {e}")

    # ==================================================
    # PREDICCIÓN
    # =====================================
    def predict_latest(self, df: pd.DataFrame) -> Tuple[float, dict]:
        """
        Retorna confianza (0–100) y metadata.
        🚫 La IA NUNCA habilita trading si confianza < UMBRAL (default 85%)
        """
        try:
            # ==============================
            # VALIDACIÓN DF
            # ==============================
            required = {"open", "high", "low", "close"}
            if not required.issubset(df.columns):
                self.logger.error("[IA] DF inválido → columnas OHLC faltantes")
                self._last_direction = None
                return 0.0, {"estado": "DF_INVALIDO"}

            # ==============================
            # EXTRACCIÓN FEATURES
            # ==============================
            features = self.extractor.calculate_features(df)

            if features is None or np.isnan(features).any():
                self.logger.warning("[IA] Features inválidas → WAIT")
                self._last_direction = None
                return 0.0, {"estado": "WAIT"}

            # Guardar features SOLO si luego hay trade válido
            self._last_features = features.copy()
            self._feedback_consumed = False
            # Generar ID único para este ciclo de predicción
            self._pending_trade_id = int(time.time() * 1000000)
            
            # ==============================
            # MODELO NO ENTRENADO → BLOQUEO TOTAL
            # ==============================
            with self._lock:
                if not self._is_initialized:
                    self.logger.info(
                        "[IA] Estado: NO ENTRENADO | WAIT (sin operación)"
                    )
                    self._last_direction = None
                    return 0.0, {
                        "modelo": "SGD-Batch",
                        "estado": "NO_ENTRENADO",
                        "confidence": 0.0,
                        "direccion": None
                    }

            # ==============================
            # PREDICCIÓN REAL
            # ==============================
            with self._lock:
                X_scaled = self.scaler.transform(features)
                proba_call = float(self.model.predict_proba(X_scaled)[0, 1])

            confidence_raw = round(proba_call * 100, 2)

            # ==============================
            # 🔥 FILTRO CRÍTICO DE CONFIANZA
            # ==============================
            UMBRAL_OPERACION = float(
                getattr(
                    self.config,
                    "UMBRAL_IA_DIRECCION",
                    getattr(self.config, "UMBRAL_COMPRA", 85.0)
                )
            )

            direccion = None
            confidence = confidence_raw

            if confidence_raw >= UMBRAL_OPERACION:
                direccion = "CALL"
            elif (100 - confidence_raw) >= UMBRAL_OPERACION:
                direccion = "PUT"
                confidence = round(100 - confidence_raw, 2)
            else:
                self._last_direction = None
                self.logger.info(
                    f"[IA] Confianza insuficiente ({confidence_raw:.2f}%) "
                    f"< {UMBRAL_OPERACION}% → WAIT"
                )
                return confidence_raw, {
                    "estado": "WAIT",
                    "confidence": confidence_raw,
                    "direccion": None
                }

            # ==============================
            # CONFIRMACIÓN FINAL
            # ==============================
            self._last_direction = direccion
            self.last_confidence = confidence / 100.0

            self.logger.info(
                f"[IA] Predicción VALIDADA | "
                f"Confianza={confidence:.2f}% | "
                f"Dirección={direccion} | "
                f"Entrenada={self._is_initialized} | "
                f"Buffer={len(self.trade_buffer)}"
            )

            return confidence, {
                "modelo": "SGD-Batch",
                "estado": "OK",
                "confidence": confidence,
                "direccion": direccion
            }

        except Exception as e:
            self.logger.error(
                f"❌ Error predict_latest IA: {e}",
                exc_info=True
            )
            self._last_direction = None
            return 0.0, {"estado": "ERROR"}

    def is_initialized(self) -> bool:
        return bool(self._is_initialized)

    def cold_start_training(self, df: pd.DataFrame):
        """
        Entrenamiento inicial con datos históricos (COLD START).
        Simula operaciones binarias reales (CALL / PUT).
        """
        try:
            self.logger.info(
                "🧊 Iniciando entrenamiento en frío (histórico)...")

        # ==================================================
        # VALIDACIONES CRÍTICAS (PROBLEMA 5 SOLUCIONADO)
        # ==================================================
            if df is None or len(df) < 100:
                if not getattr(self.config, 'FORZAR_DATOS_REALES', True):
                    self.logger.warning("Datos insuficientes. Generando datos sintéticos para inicialización...")
                    # Generar datos sintéticos para inicializar
                    fechas = pd.date_range(end=datetime.now(), periods=200, freq='min')
                    base_price = 100.0
                    prices = [base_price]
                    for _ in range(199):
                        change = np.random.uniform(-0.001, 0.001)
                        prices.append(prices[-1] * (1 + change))
                    
                    df = pd.DataFrame({
                        'open': prices,
                        'high': [p * 1.0001 for p in prices],
                        'low': [p * 0.9999 for p in prices],
                        'close': prices,
                        'volume': 1000
                    }, index=fechas)
                else:
                    raise ValueError(
                        "DataFrame vacío o insuficiente para cold start y FORZAR_DATOS_REALES=True")

            required = {"open", "high", "low", "close"}
            if not required.issubset(df.columns):
                raise ValueError(
                    f"DF no contiene columnas OHLC válidas. "
                    f"Requeridas={required}, Recibidas={set(df.columns)}"
                )

            if not hasattr(self.model, "partial_fit"):
                raise RuntimeError(
                    f"Modelo {type(self.model).__name__} "
                    "no soporta entrenamiento incremental (partial_fit)"
                )

        # ==================================================
        # DATASET SINTÉTICO PARA ARRANQUE
        # ==================================================
            features = []
            targets = []

            ventana_size = 60
            expiracion_velas = 1
            ruido_minimo = 1e-5  # evita velas planas / ruido

            for i in range(ventana_size, len(df) - expiracion_velas):

                ventana = df.iloc[i - ventana_size: i]
                X = self.extractor.calculate_features(ventana)

                if X is None or np.isnan(X).any():
                    continue

                precio_entrada = float(df["close"].iloc[i])
                precio_cierre = float(df["close"].iloc[i + expiracion_velas])
                delta = precio_cierre - precio_entrada

                # Ignorar movimientos insignificantes
                if abs(delta) < ruido_minimo:
                    continue

                # ==================================================
                # TARGET BINARIO REAL (CALL / PUT BALANCEADO)
                # ==================================================
                if i % 2 == 0:
                    # CALL
                    target = 1 if delta > 0 else 0
                else:
                    # PUT
                    target = 1 if delta < 0 else 0

                features.append(X[0])
                targets.append(target)

            # ==================================================
            # VALIDACIÓN FINAL DE SAMPLES
            # ==================================================
            if len(features) < self.batch_size:
                self.logger.warning(
                    f"⚠️ Cold start abortado: samples insuficientes "
                    f"({len(features)} < {self.batch_size})"
                )
                return

            # ==================================================
            # ENTRENAMIENTO INICIAL (INCREMENTAL PARA REFLEJAR EN VIVO)
            # ==================================================
            X_all = np.array(features, dtype=np.float32)
            y_all = np.array(targets, dtype=np.int32)

            chunk = int(
                getattr(
                    self.config,
                    "COLDSTART_CHUNK_SIZE",
                    2000) or 2000)
            chunk = max(200, min(chunk, len(y_all)))
            idx = 0
            while idx < len(y_all):
                time.sleep(0.01)
                
                end = min(len(y_all), idx + chunk)
                X = X_all[idx:end]
                y = y_all[idx:end]
                with self._lock:
                    if hasattr(self.scaler, "partial_fit"):
                        self.scaler.partial_fit(X)
                    else:
                        self.scaler.fit(X)
                    X_scaled = self.scaler.transform(X)
                    if not self._is_initialized:
                        self.model.partial_fit(X_scaled, y, classes=[0, 1])
                        self._is_initialized = True
                    else:
                        self.model.partial_fit(X_scaled, y)
                idx = end

            # ==================================================
            # PERSISTENCIA
            # ==================================================
            self.save_model()
            self.save_scaler()

            winrate = round(float(y_all.mean()) * 100, 2)

            self.logger.info(
                "❄️ Cold Start COMPLETADO | "
                f"Samples={len(y_all)} | "
                f"WinRate Simulado={winrate}% | "
                "Estado=LISTO PARA APRENDIZAJE EN VIVO"
            )

        except Exception as e:
            self.logger.error(
                f"❌ Error en cold_start_training: {e}",
                exc_info=True
            )

            # ==================================================
            # FEEDBACK REAL (WIN / LOSS)
            # ==================================================

    def set_trade_direction(self, direction: str):
        """
        Set the direction for the current trade (for learning purposes).
        Should be called when a trade is executed.
        """
        self._last_direction = direction.upper() if direction else None
        self.logger.debug(
            f"[IA] Dirección de trade establecida: {
                self._last_direction}")

    def learn_from_result(
            self, is_win: bool, direction: str = None, account_type: str = "PRACTICE", trade_id: int = None):
        """
        Aprende SOLO cuando hay resultado real (WIN / LOSS).
        Debe llamarse exactamente UNA VEZ al cerrar la operación.
        """
        with self._lock:
            # ==================================================
            # 🔒 VALIDACIONES CRÍTICAS DE PRODUCCIÓN
            # ==================================================
            # 🔒 BLOQUEO DE FEEDBACK DUPLICADO
            
            # Usar trade_id pasado o el pendiente
            current_trade_id = trade_id if trade_id is not None else getattr(self, "_pending_trade_id", None)
            
            # Si no hay ID, generar uno (fallback, aunque idealmente debería venir de predict_latest)
            if current_trade_id is None:
                current_trade_id = int(time.time() * 1000)

            if current_trade_id == self._last_trade_id:
                self.logger.error(
                    "[IA] ❌ Feedback duplicado detectado (mismo ID) → BLOQUEADO")
                return

            self._last_trade_id = current_trade_id
            
            # 1️⃣ Dirección explícita y válida
            if direction:
                self._last_direction = direction.upper()

            if self._last_direction not in ("CALL", "PUT"):
                self.logger.error(
                    "[IA] ❌ Feedback bloqueado → dirección inválida"
                )
                return

            # 2️⃣ Features deben existir
            if self._last_features is None:
                self.logger.warning(
                    "[IA] ⚠️ Feedback ignorado → sin features previas"
                )
                return

            # 3️⃣ Proteger contra doble feedback (check booleano adicional)
            if getattr(self, "_feedback_consumed", False):
                self.logger.error(
                    "[IA] ❌ Feedback duplicado detectado (consumed flag) → BLOQUEADO"
                )
                return

            # 4️⃣ Validar tipo de cuenta
            if account_type not in ("PRACTICE", "REAL"):
                self.logger.error(
                    f"[IA] ❌ Tipo de cuenta inválido: {account_type}"
                )
                return

            try:
                # ==================================================
                # 🎯 TARGET REAL PARA BINARIAS
                # ==================================================
                # 1 = IA acertó
                # 0 = IA falló
                target = 1 if is_win else 0

                # Guardar sample
                self.trade_buffer.append(
                    (self._last_features.copy(), target)
                )

                # Marcar feedback como consumido
                self._feedback_consumed = True
                self._pending_trade_id = None

                # ==================================================
                # 📊 LOG DE AUDITORÍA (PRACTICE / REAL)
                # ==================================================
                self.logger.info(
                    f"🧠 IA FEEDBACK | "
                    f"Cuenta={account_type} | "
                    f"Resultado={'WIN' if is_win else 'LOSS'} | "
                    f"Dirección={self._last_direction} | "
                    f"Target={target} | "
                    f"Buffer={len(self.trade_buffer)}/{self.batch_size}"
                )

                # ==================================================
                # 🚀 DISPARAR BATCH LEARNING
                # ==================================================
                if len(self.trade_buffer) >= self.batch_size:
                    self.logger.info("📊 Ejecutando Batch Learning IA...")
                    self._execute_batch_learning()

            except Exception as e:
                self.logger.error(
                    f"❌ Error learn_from_result IA: {e}",
                    exc_info=True
                )

       # ==================================================
       # BATCH LEARNING REAL
       # ==================================================

    def register_trade_context(self, features, direction, trade_id):
        with self._lock:
            self._last_features = features
            self._last_direction = direction
            self._pending_trade_id = trade_id

    def _execute_batch_learning(self):
        """
        Entrenamiento REAL con resultados acumulados.
        Evita sobreajuste y ruido.
        """
        try:
            # Flatten features if they are 2D (1, 15) -> (15,)
            X = np.array([x[0].flatten() if hasattr(x[0], 'flatten')
                         else x[0] for x in self.trade_buffer])
            y = np.array([x[1] for x in self.trade_buffer])

            # Ensure X is 2D
            if len(X.shape) == 1:
                X = X.reshape(1, -1)
            elif len(X.shape) == 3:
                X = X.reshape(X.shape[0], -1)

            # Primera vez → ajustar scaler y modelo
            if not self._is_initialized:
                self.scaler.fit(X)
                X_scaled = self.scaler.transform(X)
                self.model.partial_fit(X_scaled, y, classes=[0, 1])
                self._is_initialized = True
            else:
                X_scaled = self.scaler.transform(X)
                self.model.partial_fit(X_scaled, y)

            wins = int(y.sum())
            losses = len(y) - wins

            self.logger.info(
                f"📊 BATCH IA COMPLETADO | Ops={
                    len(y)} | Wins={wins} | Losses={losses}"
            )

            # Limpiar buffer para el próximo ciclo
            self.trade_buffer.clear()

        except Exception as e:
            self.logger.error(
                f"❌ Error en batch learning IA: {e}",
                exc_info=True)

    def save_model(self):
        """Guarda el modelo entrenado en disco."""
        with self._lock:
            try:
                os.makedirs(os.path.dirname(self.model_path), exist_ok=True)
                if hasattr(self.model, "save"):
                    self.model.save(self.model_path)
                else:
                    import joblib
                    joblib.dump(self.model, self.model_path)

                self.logger.info(f"💾 Modelo IA guardado en {self.model_path}")
            except Exception as e:
                self.logger.error(
                    f"❌ Error guardando modelo IA: {e}",
                    exc_info=True)

    def save_scaler(self):
        """Guarda el scaler del modelo."""
        with self._lock:
            try:
                os.makedirs(os.path.dirname(self.scaler_path), exist_ok=True)
                import joblib
                joblib.dump(self.scaler, self.scaler_path)
                self.logger.info(f"💾 Scaler guardado en {self.scaler_path}")
            except Exception as e:
                self.logger.error(
                    f"❌ Error guardando scaler IA: {e}",
                    exc_info=True)

# ==================================================
# CAPITULO 2:CLASE INDICADORES (CON TDI Y EMAS ESPECÍFICAS)
# ==================================================


class IndicatorsPropios:
    """Indicadores técnicos completos incluyendo TDI manual."""
    @staticmethod
    def SMA(series: pd.Series, period: int) -> pd.Series:
        return series.rolling(window=period).mean()

    @staticmethod
    def EMA(series: pd.Series, period: int) -> pd.Series:
        return _ema_series(series, period)

    @staticmethod
    def RSI(series: pd.Series, period: int = 13) -> pd.Series:
        """RSI estándar. Nota: TDI usa periodo 13 por defecto."""
        return _rsi_series(series, period)

    @staticmethod
    def TDI(df: pd.DataFrame, rsi_period: int = 13,
            signal_period: int = 2, base_period: int = 34) -> dict:
        """
        Calcula el Traders Dynamic Index (TDI).
        Retorna: 'green_line', 'red_line', 'yellow_base'
        """
        rsi = IndicatorsPropios.RSI(df['close'], rsi_period)
        # Línea Verde (RSI Precio)
        green_line = rsi
        # Línea Roja (Señal - Media de RSI)
        red_line = IndicatorsPropios.SMA(rsi, signal_period)
        # Línea Amarilla (Base - Volatilidad)
        yellow_base = IndicatorsPropios.SMA(rsi, base_period)
        return {
            'green': green_line.iloc[-1],
            'red': red_line.iloc[-1],
            'yellow': yellow_base.iloc[-1],
            'rsi': rsi.iloc[-1]
        }

    @staticmethod
    def TDI_DIVERGENCIA(df: pd.DataFrame, rsi_period: int = 13) -> dict:
        if df is None or len(df) < 50:
            return {'bullish': False, 'bearish': False, 'bull_bars': None, 'bear_bars': None}
        close = df['close'].astype(float)
        rsi = IndicatorsPropios.RSI(close, rsi_period)
        green = rsi.values
        import numpy as np
        from scipy.signal import find_peaks
        c = close.values
        peaks_price, _ = find_peaks(c)
        peaks_tdi, _ = find_peaks(green)
        trough_price, _ = find_peaks(-c)
        trough_tdi, _ = find_peaks(-green)
        bear = False
        bull = False
        bear_bars = None
        bull_bars = None
        if len(peaks_price) >= 2 and len(peaks_tdi) >= 2:
            p1, p2 = peaks_price[-2], peaks_price[-1]
            t1c, t2c = c[p1], c[p2]
            t1g, t2g = green[peaks_tdi[-2]], green[peaks_tdi[-1]]
            if t2c > t1c and t2g < t1g:
                bear = True
                bear_bars = len(c) - p2
        if len(trough_price) >= 2 and len(trough_tdi) >= 2:
            p1, p2 = trough_price[-2], trough_price[-1]
            b1c, b2c = c[p1], c[p2]
            b1g, b2g = green[trough_tdi[-2]], green[trough_tdi[-1]]
            if b2c < b1c and b2g > b1g:
                bull = True
                bull_bars = len(c) - p2
        return {'bullish': bull, 'bearish': bear, 'bull_bars': bull_bars, 'bear_bars': bear_bars}
    @staticmethod
    def get_analysis_pack(df: pd.DataFrame) -> dict:
        """
        Paquete de análisis completo para el motor.
        Incluye EMAS 21/50, TDI y Precio.
        """
        if df is None or len(df) < 50:
            return None
        close = df['close']
        ema_21 = IndicatorsPropios.EMA(close, 21).iloc[-1]
        ema_50 = IndicatorsPropios.EMA(close, 50).iloc[-1]
        ema_200 = IndicatorsPropios.EMA(close, 200).iloc[-1]
        precio_actual = close.iloc[-1]
        # PRICE ACTION SIMPLE (Dirección de la vela)
        vela_anterior = df.iloc[-2]
        vela_actual = df.iloc[-1]
        es_vela_verde = vela_actual['close'] > vela_actual['open']
        # TDI
        tdi_data = IndicatorsPropios.TDI(df)
        div = IndicatorsPropios.TDI_DIVERGENCIA(df)
        return {
            'precio': precio_actual,
            'ema_21': ema_21,
            'ema_50': ema_50,
            'ema_200': ema_200,
            'tdi_green': tdi_data['green'],
            'tdi_red': tdi_data['red'],
            'tdi_yellow': tdi_data['yellow'],
            'rsi': tdi_data['rsi'],
            'es_vela_verde': es_vela_verde,
            'tdi_div_bull': div.get('bullish', False),
            'tdi_div_bear': div.get('bearish', False),
            'tdi_div_bull_bars': div.get('bull_bars'),
            'tdi_div_bear_bars': div.get('bear_bars')
        }


# Instancia global
ind_tec = IndicatorsPropios()


def cumple_filtro_aprendizaje(
        config, direccion: str, indicadores: dict) -> bool:
    if not bool(getattr(config, "FILTRO_APRENDIZAJE_HABILITADO", True)):
        return True
    if not isinstance(indicadores, dict):
        return False
    dir_up = (direccion or "").upper()
    if dir_up not in ("CALL", "PUT"):
        return False

    alineacion = indicadores.get(
        "alineacion_tf") or indicadores.get("alineacion")
    if not isinstance(alineacion, dict) or not bool(
            alineacion.get("alineado", False)):
        return False
    a_dir = str(alineacion.get("direccion", "")).upper()
    if a_dir in ("CALL", "PUT") and a_dir != dir_up:
        return False
    for k in ("tf_1m", "tf_5m", "tf_15m"):
        v = str(alineacion.get(k, "")).upper()
        if v in ("CALL", "PUT") and v != dir_up:
            return False

    def _get(*keys, default=None):
        for k in keys:
            if k in indicadores:
                return indicadores.get(k, default)
            low = str(k).lower()
            if low in indicadores:
                return indicadores.get(low, default)
        return default

    close = _get("close", default=None)
    ema50 = _get("ema_50", "EMA_50", default=None)
    ema200 = _get("ema_200", "EMA_200", default=None)
    try:
        close_v = float(close) if close is not None else None
    except Exception:
        close_v = None
    try:
        ema50_v = float(ema50) if ema50 is not None else None
        ema200_v = float(ema200) if ema200 is not None else None
    except Exception:
        return False
    if not (ema50_v and ema200_v):
        return False
    if dir_up == "CALL":
        if not (ema50_v > ema200_v):
            return False
        if close_v is not None and not (close_v > ema50_v):
            return False
    else:
        if not (ema50_v < ema200_v):
            return False
        if close_v is not None and not (close_v < ema50_v):
            return False

    tdi_dir = _get("TDI_direccion", "tdi_direccion", default=None)
    try:
        tdi_dir_v = float(tdi_dir) if tdi_dir is not None else None
    except Exception:
        tdi_dir_v = None
    if tdi_dir_v is None or tdi_dir_v == 0:
        tdi_price = _get(
            "tdi_precio_linea",
            "tdi_green",
            "linea_precio",
            default=None)
        tdi_signal = _get(
            "tdi_senal_linea",
            "tdi_red",
            "linea_senal",
            default=None)
        if tdi_price is None or tdi_signal is None:
            return False
        try:
            tdi_price_v = float(tdi_price)
            tdi_signal_v = float(tdi_signal)
        except Exception:
            return False
        if tdi_price_v > tdi_signal_v:
            tdi_dir_v = 1.0
        elif tdi_price_v < tdi_signal_v:
            tdi_dir_v = -1.0
        else:
            tdi_dir_v = 0.0
    if dir_up == "CALL" and tdi_dir_v <= 0:
        return False
    if dir_up == "PUT" and tdi_dir_v >= 0:
        return False
    return True


def detectar_patron_wm(df: pd.DataFrame, config) -> dict:
    try:
        if df is None or len(df) < 60:
            return {'valido': False}
        if not all(c in df.columns for c in ("high", "low", "close", "open")):
            return {'valido': False}

        lookback = int(getattr(config, "WM_LOOKBACK", 140) or 140)
        w = int(getattr(config, "WM_PIVOT_WINDOW", 3) or 3)
        min_sep = int(getattr(config, "WM_MIN_SEPARACION", 6) or 6)
        tol_atr = float(getattr(config, "WM_TOL_ATR", 0.6) or 0.6)
        break_atr = float(getattr(config, "WM_BREAK_ATR", 0.15) or 0.15)
        sweep_atr = float(getattr(config, "WM_SWEEP_ATR", 1.2) or 1.2)
        recencia = int(getattr(config, "WM_RECIENCIA_BARS", 14) or 14)
        retest_window = int(getattr(config, "WM_RETEST_WINDOW", 10) or 10)
        estricto = bool(getattr(config, "FILTRO_WM_ESTRICTO", True))
        exigir_liquidez = bool(getattr(config, "WM_EXIGIR_LIQUIDEZ", True))
        exigir_confirmacion = bool(
            getattr(
                config,
                "WM_EXIGIR_CONFIRMACION",
                True))
        exigir_mm_ciclo = bool(getattr(config, "WM_EXIGIR_CICLO_MM", True))
        bb_dist_atr = float(getattr(config, "WM_BB_DIST_ATR", 0.25) or 0.25)
        extremo_dist_atr = float(
            getattr(
                config,
                "WM_EXTREMO_DIST_ATR",
                0.35) or 0.35)
        confirm_body_atr = float(
            getattr(
                config,
                "WM_CONFIRM_BODY_ATR",
                0.15) or 0.15)
        confirm_close_neck_atr = float(
            getattr(
                config,
                "WM_CONFIRM_NECK_ATR",
                0.05) or 0.05)

        n = len(df)
        start = max(0, n - lookback)

        open_ = df["open"].to_numpy(dtype=float)
        high = df["high"].to_numpy(dtype=float)
        low = df["low"].to_numpy(dtype=float)
        close = df["close"].to_numpy(dtype=float)

        prev_close = np.roll(close, 1)
        prev_close[0] = close[0]
        tr1 = high - low
        tr2 = np.abs(high - prev_close)
        tr3 = np.abs(low - prev_close)
        tr = np.maximum(tr1, np.maximum(tr2, tr3))
        atr = _atr_last_from_arrays(high, low, close, 14)
        if atr <= 0:
            atr = max(
                1e-8, float(np.nanmean(tr[-20:])) if len(tr) >= 20 else float(np.nanmean(tr)))
        if atr <= 0:
            atr = max(1e-8, float(close[-1]) * 0.001)

        bb_ok = False
        bb_upper = None
        bb_lower = None
        try:
            close_s = pd.Series(close)
            sma20 = close_s.rolling(20).mean().iloc[-1]
            std20 = close_s.rolling(20).std().iloc[-1]
            if sma20 is not None and std20 is not None and not (
                    pd.isna(sma20) or pd.isna(std20)):
                bb_upper = float(sma20 + 2.0 * std20)
                bb_lower = float(sma20 - 2.0 * std20)
        except Exception:
            bb_upper = None
            bb_lower = None

        pivots = []
        for i in range(max(w, start), n - w):
            hi = high[i]
            lo = low[i]
            hwin = high[i - w:i + w + 1]
            lwin = low[i - w:i + w + 1]
            if hi == np.max(hwin):
                pivots.append({"i": i, "p": float(hi), "t": "H"})
            if lo == np.min(lwin):
                pivots.append({"i": i, "p": float(lo), "t": "L"})
        pivots.sort(key=lambda x: x["i"])

        if len(pivots) < 5:
            return {'valido': False}

        last_close = float(close[-1])
        tol = atr * tol_atr
        tol_small = tol * 0.25
        break_dist = atr * break_atr
        liq_dist_bb = atr * bb_dist_atr
        liq_dist_ext = atr * extremo_dist_atr

        def _between(a, b):
            return [p for p in pivots if a < p["i"] < b]

        def _detect_m():
            highs = [p for p in pivots if p["t"] == "H"]
            lows = [p for p in pivots if p["t"] == "L"]
            if len(highs) < 2 or len(lows) < 1:
                return None
            h2 = highs[-1]
            if n - 1 - h2["i"] > recencia:
                return None
            h1 = None
            for prev in reversed(highs[:-1]):
                if h2["i"] - prev["i"] >= min_sep:
                    h1 = prev
                    break
            if h1 is None:
                return None
            mids = [p for p in _between(h1["i"], h2["i"]) if p["t"] == "L"]
            if not mids:
                return None
            neckline = min(p["p"] for p in mids)
            basic = abs(h2["p"] - h1["p"]) <= tol
            sweep = (
                h2["p"] > (
                    h1["p"] +
                    tol_small)) and (
                (h2["p"] -
                 h1["p"]) <= (
                    atr *
                    sweep_atr))
            broke = last_close < (neckline - break_dist)
            moved = last_close < (h2["p"] - (atr * 0.2))
            if not (basic or sweep):
                return None
            if not (broke or moved):
                return None

            retest = False
            if broke:
                j0 = max(0, n - retest_window)
                recent_high = float(np.max(high[j0:]))
                if recent_high >= (neckline - (atr * 0.05)
                                   ) and last_close < neckline:
                    retest = True

            tipo = "M_DOBLE_TECHO"
            if sweep and not broke:
                tipo = "M_BARRIDA_LIQUIDEZ"
            if sweep and broke:
                tipo = "M_BARRIDA_LIQUIDEZ_BREAK"
            if retest:
                tipo = "M_RETEST_LIQUIDEZ_OB"

            return {
                "valido": True,
                "direccion": "PUT",
                "tipo": tipo,
                "h1_i": h1["i"],
                "h1_p": h1["p"],
                "h2_i": h2["i"],
                "h2_p": h2["p"],
                "neckline": neckline,
                "atr": atr,
                "broke_neckline": bool(broke),
                "sweep": bool(sweep),
                "retest": bool(retest),
            }

        def _detect_w():
            lows = [p for p in pivots if p["t"] == "L"]
            highs = [p for p in pivots if p["t"] == "H"]
            if len(lows) < 2 or len(highs) < 1:
                return None
            l2 = lows[-1]
            if n - 1 - l2["i"] > recencia:
                return None
            l1 = None
            for prev in reversed(lows[:-1]):
                if l2["i"] - prev["i"] >= min_sep:
                    l1 = prev
                    break
            if l1 is None:
                return None
            mids = [p for p in _between(l1["i"], l2["i"]) if p["t"] == "H"]
            if not mids:
                return None
            neckline = max(p["p"] for p in mids)
            basic = abs(l2["p"] - l1["p"]) <= tol
            sweep = (
                l2["p"] < (
                    l1["p"] -
                    tol_small)) and (
                (l1["p"] -
                 l2["p"]) <= (
                    atr *
                    sweep_atr))
            broke = last_close > (neckline + break_dist)
            moved = last_close > (l2["p"] + (atr * 0.2))
            if not (basic or sweep):
                return None
            if not (broke or moved):
                return None

            retest = False
            if broke:
                j0 = max(0, n - retest_window)
                recent_low = float(np.min(low[j0:]))
                if recent_low <= (neckline + (atr * 0.05)
                                  ) and last_close > neckline:
                    retest = True

            tipo = "W_DOBLE_PISO"
            if sweep and not broke:
                tipo = "W_BARRIDA_LIQUIDEZ"
            if sweep and broke:
                tipo = "W_BARRIDA_LIQUIDEZ_BREAK"
            if retest:
                tipo = "W_RETEST_LIQUIDEZ_OB"

            return {
                "valido": True,
                "direccion": "CALL",
                "tipo": tipo,
                "l1_i": l1["i"],
                "l1_p": l1["p"],
                "l2_i": l2["i"],
                "l2_p": l2["p"],
                "neckline": neckline,
                "atr": atr,
                "broke_neckline": bool(broke),
                "sweep": bool(sweep),
                "retest": bool(retest),
            }

        m = _detect_m()
        wpat = _detect_w()
        patron = None
        if m and wpat:
            patron = m if (
                n -
                1 -
                m.get(
                    "h2_i",
                    0)) <= (
                n -
                1 -
                wpat.get(
                    "l2_i",
                    0)) else wpat
        elif m:
            patron = m
        elif wpat:
            patron = wpat
        else:
            return {'valido': False}

        try:
            if patron.get("direccion") == "CALL":
                l2_p = float(patron.get("l2_p"))
                l2_i = int(patron.get("l2_i"))
                if bb_lower is not None:
                    bb_ok = l2_p <= (bb_lower + liq_dist_bb)
                ext_low = float(np.min(low[start:])) if n - \
                    start >= 10 else float(np.min(low))
                ext_ok = l2_p <= (ext_low + liq_dist_ext)
                liq_ok = bool(bb_ok or ext_ok)
            else:
                h2_p = float(patron.get("h2_p"))
                h2_i = int(patron.get("h2_i"))
                if bb_upper is not None:
                    bb_ok = h2_p >= (bb_upper - liq_dist_bb)
                ext_high = float(
                    np.max(high[start:])) if n - start >= 10 else float(np.max(high))
                ext_ok = h2_p >= (ext_high - liq_dist_ext)
                liq_ok = bool(bb_ok or ext_ok)
        except Exception:
            liq_ok = False

        mm_ok = True
        ciclo = None
        try:
            if estricto and exigir_mm_ciclo:
                mm = MarketMakerStrategy()
                simbolo = str(
                    getattr(
                        config,
                        "ACTIVO",
                        "UNKNOWN") or "UNKNOWN")
                ciclo = mm.analizar_ciclo_intradia(df, simbolo)
                rec = str(
                    (ciclo or {}).get(
                        "recomendacion",
                        "ESPERAR")).upper()
                dir_ = str(patron.get("direccion", "")).upper()
                mm_ok = rec == dir_
                if not bool((ciclo or {}).get("cerca_extremo", False)) and not bool(
                        (ciclo or {}).get("stop_hunt_detectado", False)):
                    mm_ok = False
        except Exception:
            mm_ok = False if (estricto and exigir_mm_ciclo) else True

        confirm_ok = True
        try:
            if estricto and exigir_confirmacion:
                o = float(open_[-1])
                c = float(close[-1])
                h = float(high[-1])
                l = float(low[-1])
                body = abs(c - o)
                ok_body = body >= (atr * confirm_body_atr)
                if patron.get("direccion") == "CALL":
                    neck = float(patron.get("neckline", c))
                    confirm_ok = ok_body and (c > o) and (
                        c >= (neck - (atr * confirm_close_neck_atr)))
                else:
                    neck = float(patron.get("neckline", c))
                    confirm_ok = ok_body and (c < o) and (
                        c <= (neck + (atr * confirm_close_neck_atr)))
        except Exception:
            confirm_ok = False if (estricto and exigir_confirmacion) else True

        patron["liq_ok"] = bool(liq_ok)
        patron["mm_ok"] = bool(mm_ok)
        patron["confirm_ok"] = bool(confirm_ok)
        patron["bb_upper"] = bb_upper
        patron["bb_lower"] = bb_lower
        patron["ciclo_mm"] = ciclo if isinstance(ciclo, dict) else None

        if estricto:
            if exigir_liquidez and not patron["liq_ok"]:
                patron["valido"] = False
                patron["razon"] = "SIN_ZONA_LIQUIDEZ"
                return patron
            if exigir_mm_ciclo and not patron["mm_ok"]:
                patron["valido"] = False
                patron["razon"] = "CICLO_MM_NO_COINCIDE"
                return patron
            if exigir_confirmacion and not patron["confirm_ok"]:
                patron["valido"] = False
                patron["razon"] = "SIN_CONFIRMACION_VELA"
                return patron

        return patron
    except Exception:
        return {'valido': False}

# ==================================================
# CAPITULO 4:MOTOR DE TRADING INTEGRADO (TDI + EMA 21/50 + IA)
# ==================================================


class MotorTradingIntegrado:
    """
    Motor central REAL de decisión de trading.

    ✔ Combina IA + Técnico
    ✔ Confianza dinámica REAL (0–100)
    ✔ NO obtiene datos
    ✔ NO escanea mercado
    ✔ NO ejecuta automáticamente
    ✔ SOLO decide CALL / PUT / WAIT
    """

    def __init__(self, config, iq_bridge, ai_engine):
        self.config = config
        self.iq_bridge = iq_bridge
        self.ai_engine = ai_engine
        self.logger = logging.getLogger(__name__)

        # Executor humano (único permitido para real)
        self.executor_humano = HumanMouseExecutor()

        # Fallback seguro
        self.umbral_compra = float(
            getattr(
                config,
                "UMBRAL_COMPRA",
                85.0) or 85.0)
        self.umbral_ia = float(
            getattr(
                config,
                "UMBRAL_IA_DIRECCION",
                75.0) or 75.0)
        self.umbral_tecnico = float(
            getattr(
                config,
                "UMBRAL_TECNICO_DIRECCION",
                75.0) or 75.0)

    # ==========================================================
    # VALIDACIONES TÉCNICAS
    # ==========================================================

    def verificar_tendencia_ema_50_200(self, data: dict) -> str:
        precio = data.get("precio")
        e50 = data.get("ema_50")
        e200 = data.get("ema_200")

        if None in (precio, e50, e200):
            return "NEUTRAL"

        if precio > e50 > e200:
            return "CALL"
        if precio < e50 < e200:
            return "PUT"
        return "NEUTRAL"

    def verificar_tdi_signal(self, data: dict) -> str:
        green = data.get("tdi_green")
        red = data.get("tdi_red")
        rsi = data.get("rsi")

        if None in (green, red, rsi):
            return "NEUTRAL"

        if not 32 < rsi < 68:
            return "NEUTRAL"

        if green > red:
            return "CALL"
        if green < red:
            return "PUT"
        return "NEUTRAL"

    # ==========================================================
    # DECISIÓN CENTRAL
    # ==========================================================

    def procesar_senal(
        self,
        nn_prediction: float,
        data: dict,
        expiracion_segundos: int
    ) -> dict:
        """
        Combina IA + EMA + TDI
        Retorna decisión pura (NO ejecuta).
        """

        nn_prediction = float(nn_prediction)
        ia_direccion = "CALL" if nn_prediction > 0 else (
            "PUT" if nn_prediction < 0 else None)
        ia_fuerza = max(0.0, min(100.0, abs(nn_prediction)))
        ia_score = 0.0
        if ia_direccion in ("CALL", "PUT"):
            ia_score = (ia_fuerza / 100.0) * \
                (1.0 if ia_direccion == "CALL" else -1.0)

        trend_ema = self.verificar_tendencia_ema_50_200(data)
        trend_tdi = self.verificar_tdi_signal(data)

        # Score técnico granular (0-100)
        score_ema = 0.0
        score_tdi = 0.0

        # 1. Análisis EMA (0-50 pts) usando 50/200
        if trend_ema in ("CALL", "PUT"):
            score_ema = 25.0
            e50 = data.get("ema_50", 0)
            e200 = data.get("ema_200", 0)
            precio = data.get("precio", 1.0)
            if e50 and e200 and precio:
                diff_rel = abs(e50 - e200) / precio
                bonus_fuerza = min(25.0, diff_rel * 10000.0)
                score_ema += bonus_fuerza

        # 2. Análisis TDI (0-50 pts)
        if trend_tdi in ("CALL", "PUT"):
            # Base por señal TDI válida
            score_tdi = 25.0

            # Bonificación por ángulo/separación (fuerza del cruce)
            green = data.get("tdi_green", 0)
            red = data.get("tdi_red", 0)

            if green and red:
                diff_tdi = abs(green - red)
                # Separación típica 1-5 pts. Multiplicamos para escalar a 25.
                bonus_tdi = min(25.0, diff_tdi * 5.0)
                score_tdi += bonus_tdi

        tecnico_fuerza_base = score_ema + score_tdi
        tecnico_fuerza_base = max(0.0, min(100.0, tecnico_fuerza_base))

        w_ia = float(getattr(self.config, "PESO_NEURONAL", 0.60) or 0.60)
        w_tec = float(getattr(self.config, "PESO_TECNICO", 0.40) or 0.40)
        if w_ia < 0:
            w_ia = abs(w_ia)
        if w_tec < 0:
            w_tec = abs(w_tec)
        total_w = w_ia + w_tec
        if total_w <= 0:
            w_ia, w_tec, total_w = 0.60, 0.40, 1.0
        w_ia /= total_w
        w_tec /= total_w

        confianza_info = (ia_fuerza * w_ia) + (tecnico_fuerza_base * w_tec)

        ia_raw = None
        try:
            if isinstance(data, dict) and data.get(
                    "ia_confianza_raw") is not None:
                ia_raw = float(data.get("ia_confianza_raw"))
        except Exception:
            ia_raw = None
        if ia_raw is None:
            ia_raw = ia_fuerza
        self.logger.info(
            f"[MOTOR] IA_RAW={ia_raw:.2f}% | IA_USADA={ia_fuerza:.2f}% | "
            f"DIR={ia_direccion or 'NEUTRAL'} | EMA={trend_ema} | TDI={trend_tdi}"
        )

        if ia_direccion is None:
            return {
                "accion": "WAIT",
                "confianza": round(confianza_info, 2),
                "motivo": "IA_NEUTRAL",
                "ia_confianza": ia_fuerza,
                "tecnico_confianza": tecnico_fuerza_base,
                "ia_score": ia_score,
                "tecnico_score": 0.0
            }
        if ia_fuerza < self.umbral_ia:
            return {
                "accion": "WAIT",
                "confianza": round(confianza_info, 2),
                "motivo": "IA_BAJO_UMBRAL",
                "ia_confianza": ia_fuerza,
                "tecnico_confianza": tecnico_fuerza_base,
                "ia_score": ia_score,
                "tecnico_score": 0.0
            }

        try:
            div_bull = bool(data.get("tdi_div_bull", False))
            div_bear = bool(data.get("tdi_div_bear", False))
            bull_bars = data.get("tdi_div_bull_bars")
            bear_bars = data.get("tdi_div_bear_bars")
            precio = float(data.get("precio", 0) or 0)
            e50 = float(data.get("ema_50", 0) or 0)
            df_mm = data.get("df_5m")
            atr_val = None
            if isinstance(df_mm, pd.DataFrame) and len(df_mm) >= 20:
                closes = df_mm["close"].to_numpy(dtype=float)
                highs = df_mm["high"].to_numpy(dtype=float)
                lows = df_mm["low"].to_numpy(dtype=float)
                atr_val = _atr_last_from_arrays(highs, lows, closes, 14)
            dist_ema50 = abs(precio - e50)
            if ia_direccion == "CALL":
                if div_bear and (bear_bars is None or bear_bars <= 12):
                    return {
                        "accion": "WAIT",
                        "confianza": round(confianza_info, 2),
                        "motivo": "TDI_DIVERGENCIA_BAJISTA",
                        "ia_confianza": ia_fuerza,
                        "tecnico_confianza": tecnico_fuerza_base,
                        "ia_score": ia_score,
                        "tecnico_score": 0.0
                    }
                if atr_val is not None and atr_val > 0 and dist_ema50 > atr_val * 2.0 and div_bear:
                    return {
                        "accion": "WAIT",
                        "confianza": round(confianza_info, 2),
                        "motivo": "TENDENCIA_TARDE_CALL",
                        "ia_confianza": ia_fuerza,
                        "tecnico_confianza": tecnico_fuerza_base,
                        "ia_score": ia_score,
                        "tecnico_score": 0.0
                    }
            elif ia_direccion == "PUT":
                if div_bull and (bull_bars is None or bull_bars <= 12):
                    return {
                        "accion": "WAIT",
                        "confianza": round(confianza_info, 2),
                        "motivo": "TDI_DIVERGENCIA_ALCISTA",
                        "ia_confianza": ia_fuerza,
                        "tecnico_confianza": tecnico_fuerza_base,
                        "ia_score": ia_score,
                        "tecnico_score": 0.0
                    }
                if atr_val is not None and atr_val > 0 and dist_ema50 > atr_val * 2.0 and div_bull:
                    return {
                        "accion": "WAIT",
                        "confianza": round(confianza_info, 2),
                        "motivo": "TENDENCIA_TARDE_PUT",
                        "ia_confianza": ia_fuerza,
                        "tecnico_confianza": tecnico_fuerza_base,
                        "ia_score": ia_score,
                        "tecnico_score": 0.0
                    }
        except Exception:
            pass

        # Filtro Market Maker básico: volatilidad/sesión/barrido de extremos
        try:
            df_mm = None
            if isinstance(data, dict):
                df_mm = data.get("df_5m")
            if df_mm is not None and isinstance(df_mm, pd.DataFrame) and len(df_mm) >= 60:
                closes = df_mm["close"].to_numpy(dtype=float)
                highs = df_mm["high"].to_numpy(dtype=float)
                lows = df_mm["low"].to_numpy(dtype=float)
                atr = _atr_last_from_arrays(highs, lows, closes, 14)
                if np.isfinite(atr) and atr > 0:
                    last_range = float(highs[-1] - lows[-1])
                    if last_range > atr * 2.5:
                        return {
                            "accion": "WAIT",
                            "confianza": round(confianza_info, 2),
                            "motivo": "MM_VOLAT_EXCESIVA",
                            "ia_confianza": ia_fuerza,
                            "tecnico_confianza": tecnico_fuerza_base,
                            "ia_score": ia_score,
                            "tecnico_score": 0.0
                        }
                    hora = datetime.now().hour
                    if (0 <= hora < 6) and bool(getattr(self.config, "WM_EXIGIR_CICLO_MM", True)):
                        return {
                            "accion": "WAIT",
                            "confianza": round(confianza_info, 2),
                            "motivo": "MM_SESION_ASIA",
                            "ia_confianza": ia_fuerza,
                            "tecnico_confianza": tecnico_fuerza_base,
                            "ia_score": ia_score,
                            "tecnico_score": 0.0
                        }
                    hod = float(highs.tail(48).max())
                    lod = float(lows.tail(48).min())
                    precio = float(closes.iloc[-1])
                    dist_hod = abs(hod - precio)
                    dist_lod = abs(precio - lod)
                    near_extreme = min(dist_hod, dist_lod) <= atr * getattr(self.config, "WM_BB_DIST_ATR", 0.25)
                    if near_extreme and bool(getattr(self.config, "WM_EXIGIR_CONFIRMACION", True)):
                        if dist_hod < dist_lod and ia_direccion != "PUT":
                            return {
                                "accion": "WAIT",
                                "confianza": round(confianza_info, 2),
                                "motivo": "MM_NEAR_HOD_OPUESTA_REQUERIDA",
                                "ia_confianza": ia_fuerza,
                                "tecnico_confianza": tecnico_fuerza_base,
                                "ia_score": ia_score,
                                "tecnico_score": 0.0
                            }
                        if dist_lod < dist_hod and ia_direccion != "CALL":
                            return {
                                "accion": "WAIT",
                                "confianza": round(confianza_info, 2),
                                "motivo": "MM_NEAR_LOD_OPUESTA_REQUERIDA",
                                "ia_confianza": ia_fuerza,
                                "tecnico_confianza": tecnico_fuerza_base,
                                "ia_score": ia_score,
                                "tecnico_score": 0.0
                            }
        except Exception:
            pass

        alineaciones = 0
        if ia_direccion in ("CALL", "PUT"):
            alineaciones += 1
        if trend_ema == ia_direccion:
            alineaciones += 1
        if trend_tdi == ia_direccion:
            alineaciones += 1

        if alineaciones < 3:
            self.logger.info(
                f"[MOTOR] ALINEACIÓN DÉBIL ({alineaciones}/3) | IA={ia_direccion} | EMA={trend_ema} | TDI={trend_tdi}"
            )
            return {
                "accion": "WAIT",
                "confianza": round(confianza_info, 2),
                "motivo": "ALINEACION_INSUFICIENTE",
                "ia_confianza": ia_fuerza,
                "tecnico_confianza": tecnico_fuerza_base,
                "ia_score": ia_score,
                "tecnico_score": 0.0
            }

        # -------------------------
        # Score técnico REAL (Alineado con IA)
        # -------------------------
        tecnico_score = 0.0
        if trend_ema == ia_direccion:
            tecnico_score += score_ema
        if trend_tdi == ia_direccion:
            tecnico_score += score_tdi
        tecnico_score = max(0.0, min(100.0, float(tecnico_score)))
        tecnico_score_signed = (tecnico_score / 100.0) * \
            (1.0 if ia_direccion == "CALL" else -1.0)
        if tecnico_score < self.umbral_tecnico:
            return {
                "accion": "WAIT",
                "confianza": round(confianza_info, 2),
                "motivo": "TECNICO_BAJO_UMBRAL",
                "ia_confianza": ia_fuerza,
                "tecnico_confianza": tecnico_score,
                "ia_score": ia_score,
                "tecnico_score": tecnico_score_signed
            }

        # -------------------------
        # Confianza final REAL
        # -------------------------
        confianza_final = (ia_fuerza * w_ia) + (tecnico_score * w_tec)

        if confianza_final < self.umbral_compra:
            return {
                "accion": "WAIT",
                "confianza": round(confianza_final, 2),
                "motivo": "CONFIANZA_INSUFICIENTE",
                "ia_confianza": ia_fuerza,
                "tecnico_confianza": tecnico_score,
                "ia_score": ia_score,
                "tecnico_score": tecnico_score_signed
            }

        return {
            "accion": ia_direccion,
            "confianza": round(confianza_final, 2),
            "motivo": "IA_TECNICO_ALINEADOS",
            "ia_confianza": ia_fuerza,
            "tecnico_confianza": tecnico_score,
            "ia_score": ia_score,
            "tecnico_score": tecnico_score_signed
        }

    # ==========================================================
    # API PÚBLICA
    # ==========================================================

    def validar_confluencia_timeframes(
        self, df_1m: pd.DataFrame, df_5m: pd.DataFrame, df_15m: pd.DataFrame, expiracion_segundos: int = 300
    ) -> dict:
        """
        Valida que la señal coincida en 1M, 5M y 15M (IA + Técnico en cada uno).
        """
        # 1. Analizar 5M (Principal)
        res_5m = self.calcular_senal_final(df_5m, expiracion_segundos)
        accion_5m = res_5m.get("accion", "WAIT")

        if accion_5m not in ("CALL", "PUT"):
            return res_5m  # Si 5M no da señal, retornamos lo que diga (WAIT)

        # 2. Analizar 1M
        res_1m = self.calcular_senal_final(df_1m, expiracion_segundos)
        accion_1m = res_1m.get("accion", "WAIT")

        # 3. Analizar 15M
        res_15m = self.calcular_senal_final(df_15m, expiracion_segundos)
        accion_15m = res_15m.get("accion", "WAIT")

        if accion_5m in ("CALL", "PUT") and accion_5m == accion_1m == accion_15m:
            motivo_orig = res_5m.get("motivo", "")
            res_5m["motivo"] = f"{motivo_orig} | CONFLUENCIA_COMPLETA_1M_5M_15M"
            return res_5m
        return {
            "accion": "WAIT",
            "confianza": res_5m.get("confianza", 0),
            "motivo": f"SIN_CONFLUENCIA_1M_5M_15M [1M:{accion_1m}|5M:{accion_5m}|15M:{accion_15m}]",
            "tipo_senal": "DEBIL",
            "ia_score": res_5m.get("ia_score", 0),
            "tecnico_score": res_5m.get("tecnico_score", 0),
            "ia_confianza": res_5m.get("ia_confianza", 0),
            "tecnico_confianza": res_5m.get("tecnico_confianza", 0),
            "patron_wm": res_5m.get("patron_wm")
        }

    def calcular_senal_final(
        self,
        df,
        expiracion_segundos: int = 300,
        ema_fast=None,
        ema_slow=None,
        score_tecnico=None
    ) -> dict:
        """
        Punto único de entrada del motor
        """

        try:
            if df is None or df.empty or len(df) < 50:
                return self._wait("DATOS_INSUFICIENTES")

            analysis = ind_tec.get_analysis_pack(df)
            if not analysis:
                return self._wait("ANALISIS_FALLIDO")

            # IA real
            nn_pred = 0.0
            ia_confianza_raw = 0.0
            if self.ai_engine and hasattr(self.ai_engine, "predict_latest"):
                try:
                    res = self.ai_engine.predict_latest(df)
                    if isinstance(res, tuple) and len(
                            res) >= 2 and isinstance(res[1], dict):
                        conf_dir = float(res[0])
                        dir_ia = res[1].get("direccion")
                        ia_confianza_raw = conf_dir
                        if dir_ia == "CALL":
                            nn_pred = conf_dir
                        elif dir_ia == "PUT":
                            nn_pred = -conf_dir
                        else:
                            nn_pred = 0.0
                    else:
                        raw = float(res)
                        ia_confianza_raw = raw
                        if abs(raw - 50.0) < 1e-9:
                            nn_pred = 0.0
                        elif raw > 50.0:
                            nn_pred = raw
                        else:
                            nn_pred = -(100.0 - raw)
                except Exception as e:
                    self.logger.warning(f"IA falló → neutral: {e}")

            if isinstance(analysis, dict):
                analysis = dict(analysis)
                analysis["ia_confianza_raw"] = ia_confianza_raw

            # Adjuntar DF para filtros de entrada (MM)
            if isinstance(analysis, dict):
                analysis["df_5m"] = df
            decision = self.procesar_senal(
                nn_prediction=nn_pred,
                data=analysis,
                expiracion_segundos=expiracion_segundos
            )

            confianza = decision.get("confianza", 0.0)
            patron_wm = {'valido': False}
            if decision.get("accion") in ("CALL", "PUT") and bool(
                    getattr(self.config, "FILTRO_WM_HABILITADO", True)):
                patron_wm = detectar_patron_wm(df, self.config)
                # Ajustes no acumulativos, mantenemos confianza base
                
                if not (isinstance(patron_wm, dict)
                        and patron_wm.get("valido")):
                    return {
                        "accion": "WAIT",
                        "confianza": confianza,
                        "motivo": "FILTRO_WM_SIN_PATRON",
                        "tipo_senal": "DEBIL",
                        "ia_score": decision.get("ia_score", 0.0),
                        "tecnico_score": decision.get("tecnico_score", 0.0),
                        "ia_confianza": (decision.get("ia_confianza", 0.0) or 0.0) or ia_confianza_raw,
                        "tecnico_confianza": decision.get("tecnico_confianza", 0.0),
                        "patron_wm": patron_wm
                    }
                if str(patron_wm.get("direccion", "")).upper() != str(
                        decision.get("accion", "")).upper():
                    return {
                        "accion": "WAIT",
                        "confianza": confianza,
                        "motivo": f"FILTRO_WM_NO_COINCIDE_{patron_wm.get('tipo', '')}",
                        "tipo_senal": "DEBIL",
                        "ia_score": decision.get("ia_score", 0.0),
                        "tecnico_score": decision.get("tecnico_score", 0.0),
                        "ia_confianza": (decision.get("ia_confianza", 0.0) or 0.0) or ia_confianza_raw,
                        "tecnico_confianza": decision.get("tecnico_confianza", 0.0),
                        "patron_wm": patron_wm
                    }

            # Clasificación
            umbral_destacada = getattr(
                self.config, 'UMBRAL_SEÑAL_DESTACADA', 85.0)
            umbral_confirmada = getattr(
                self.config, 'UMBRAL_SEÑAL_CONFIRMADA', 92.0)

            if confianza >= umbral_confirmada:
                tipo = "CONFIRMADA"
            elif confianza >= umbral_destacada:
                tipo = "DESTACADA"
            elif confianza >= 70:
                tipo = "FUERTE"
            elif confianza >= 55:
                tipo = "MODERADA"
            else:
                tipo = "DEBIL"

            return {
                "accion": decision.get("accion"),
                "confianza": confianza,
                "motivo": decision.get("motivo"),
                "tipo_senal": tipo,
                "ia_score": decision.get("ia_score", 0.0),
                "tecnico_score": decision.get("tecnico_score", 0.0),
                "ia_confianza": (decision.get("ia_confianza", 0.0) or 0.0) or ia_confianza_raw,
                "tecnico_confianza": decision.get("tecnico_confianza", 0.0),
                "patron_wm": patron_wm
            }

        except Exception as e:
            self.logger.error(
                "Error crítico MotorTradingIntegrado",
                exc_info=True)
            return self._wait(f"ERROR_MOTOR: {e}")

    # ==========================================================
    # EJECUCIÓN HUMANA
    # ==========================================================

    def ejecutar_trade(self, par: str, decision: dict,
                       expiracion_segundos: int):
        if decision.get("accion") not in ("CALL", "PUT"):
            return None

        if not self.iq_bridge or not self.iq_bridge.api:
            self.logger.error("API no disponible")
            return None

        monto = self.config.calcular_monto_operacion()
        duracion_min = expiracion_segundos // 60

        return self.executor_humano.ejecutar_orden_humana(
            api=self.iq_bridge.api,
            simbolo=par,
            direccion=decision["accion"],
            monto=monto,
            duracion=duracion_min
        )

    # ==========================================================
    # UTIL
    # ==========================================================

    def _wait(self, motivo):
        return {
            "accion": "WAIT",
            "confianza": 0.0,
            "motivo": motivo,
            "tipo_senal": "DEBIL",
            "ia_score": 0.0,
            "tecnico_score": 0.0,
            "ia_confianza": 0.0,
            "tecnico_confianza": 0.0
        }

# ==================================================
# CAPITULO 5: CONFIGURACIÓN TRADING (COMPLETA)
# ==================================================


def obtener_velas_seguras(iq, par, timeframe, cantidad, cache=None):
    try:
        ahora = time.time()

        if cache is not None:
            clave = f"{par}_{timeframe}_{cantidad}"
            if clave in cache:
                return cache[clave]

        velas = iq.get_candles(par, timeframe, cantidad, ahora)

        if velas is None or len(velas) < cantidad:
            return None

        if cache is not None:
            cache[clave] = velas

        return velas
    except Exception as e:
        logger.debug(f"Error velas {par} TF {timeframe}: {e}")
        return None


def par_valido_multi_tf(iq, par, config, cache=None):
    tf_map = config.IQ_TIMEFRAME_MAP

    if config.USAR_TF_1M:
        velas = obtener_velas_seguras(
            iq, par, tf_map["1"], config.MIN_CANDLES_REQUERIDAS, cache
        )
        if velas is None:
            return False

    if config.USAR_TF_5M:
        velas = obtener_velas_seguras(
            iq, par, tf_map["5"], config.MIN_CANDLES_REQUERIDAS, cache
        )
        if velas is None:
            return False

    return True


def filtrar_pares_validos_multi_tf(iq, config):
    cache = {}
    pares_validos = []

    for par in config.PARES_TRADING:
        if par_valido_multi_tf(iq, par, config, cache):
            pares_validos.append(par)

    logger.info(
        f"🧠 Pares válidos multi-TF: {len(pares_validos)} / {len(config.PARES_TRADING)}"
    )
    return pares_validos


