class BalanceManager:
    """
    Gestor de balance para cálculo de interés compuesto y gestión de capital.
    Se integra con la instancia global del bridge para obtener el balance real.
    """

    def __init__(self, bridge=None):
        self.bridge = bridge
        self.last_balance = 0.0
        self.last_update = 0
        self.cache_ttl = 15  # segundos

    def get_balance(self):
        """Obtiene el balance actual, priorizando datos en tiempo real"""
        try:
            # Intentar obtener bridge global si no se proporcionó
            if not self.bridge:
                global _iq_bridge_singleton
                if '_iq_bridge_singleton' in globals() and _iq_bridge_singleton:
                    self.bridge = _iq_bridge_singleton

            if self.bridge and hasattr(self.bridge, 'balance_actual'):
                # Actualizar si el cache expiró
                if time.time() - self.last_update > self.cache_ttl:
                    if hasattr(self.bridge, 'api') and self.bridge.api:
                        try:
                            bal = self.bridge.api.get_balance()
                            if bal:
                                self.bridge.balance_actual = float(bal)
                                self.last_update = time.time()
                        except BaseException:
                            pass

                self.last_balance = float(self.bridge.balance_actual)
                return self.last_balance

            return 0.0
        except Exception as e:
            logger.error(f"Error obteniendo balance: {e}")
            return self.last_balance


