    def _normalizar_rutas_datos(self) -> None:
        try:
            asegurar_directorio_datos()
            attrs = [
                "RUTA_MODELO_NEURONAL",
                "RUTA_ESCALADOR_NEURONAL",
                "RUTA_HISTORIAL_SENALES",
            ]
            for a in attrs:
                v = getattr(self, a, None)
                if isinstance(v, str) and (v.lower().endswith(
                        ".pkl") or v.lower().endswith(".pth")):
                    if os.path.dirname(v) in ("", "."):
                        setattr(self, a, datos_rel(os.path.basename(v)))
            for perfil_attr in ("PERFIL_REGULAR", "PERFIL_OTC"):
                perfil = getattr(self, perfil_attr, None)
                if not isinstance(perfil, dict):
                    continue
                for k in ("modelo_path", "escalador_path", "historial_path"):
                    v = perfil.get(k)
                    if isinstance(v, str) and (v.lower().endswith(
                            ".pkl") or v.lower().endswith(".pth")):
                        if os.path.dirname(v) in ("", "."):
                            perfil[k] = datos_rel(os.path.basename(v))
                cache_path = perfil.get("cache_path")
                if isinstance(cache_path, str) and os.path.dirname(
                        cache_path) in ("", ".") and cache_path.startswith("cache_"):
                    perfil["cache_path"] = os.path.join(
                        DATOS_DIR, cache_path) + os.sep
            if isinstance(getattr(self, "RUTA_CACHE_DATOS", None), str):
                if self.RUTA_CACHE_DATOS.startswith("cache_"):
                    self.RUTA_CACHE_DATOS = os.path.join(
                        DATOS_DIR, self.RUTA_CACHE_DATOS) + os.sep
            for d in (
                getattr(self, "RUTA_CACHE_DATOS", None),
                (getattr(self, "PERFIL_REGULAR", {}) or {}).get("cache_path"),
                (getattr(self, "PERFIL_OTC", {}) or {}).get("cache_path"),
                os.path.join(DATOS_DIR, "cache_historico"),
            ):
                try:
                    if isinstance(d, str) and d:
                        os.makedirs(d, exist_ok=True)
                except Exception:
                    pass
        except Exception:
            pass

    def obtener_min_datos(self) -> int:
        return getattr(self, "MIN_DATOS_POR_PAR", 50)

    def calcular_monto_operacion(self):
        """Calcula el monto de operación según configuración"""
        if self.MODO_PAPER_TRADING or self.TIPO_CUENTA == "PRACTICE":
            return float(self.MONTO_OPERACION or 1.0)

        if self.SISTEMA_COMPUESTO_HABILITADO and self.CAPITAL_INICIAL > 0:
            # Usar porcentaje del capital actual
            try:
                # Usar la clase interna BalanceManager si está definida, o una
                # lógica simple
                if 'BalanceManager' in globals():
                    bm = BalanceManager(
                        self.iq_bridge if hasattr(
                            self, 'iq_bridge') else None)
                    capital_actual = bm.get_balance()
                else:
                    # Fallback si BalanceManager no está definido globalmente
                    capital_actual = float(
                        getattr(
                            self,
                            'CAPITAL_INICIAL',
                            0.0) or 0.0)
                    if hasattr(self, 'iq_bridge') and self.iq_bridge:
                        capital_actual = float(
                            getattr(
                                self.iq_bridge,
                                'balance_actual',
                                capital_actual) or capital_actual)

                monto = capital_actual * (self.PORCENTAJE_INVERSION / 100.0)
                return max(float(self.MONTO_OPERACION or 1.0),
                           min(monto, capital_actual * 0.1))
            except Exception as e:
                logger.error(f"Error calculando monto: {e}")
                return float(self.MONTO_OPERACION or 1.0)

        return float(self.MONTO_OPERACION or 1.0)

