class MarketModeResolver:
    """
    Resolutor de modo de mercado que determina automáticamente
    si usar perfil REGULAR (días hábiles) u OTC (fines de semana).
    """

    def __init__(self, config: ConfiguracionTrading):
        self.config = config
        self._ultimo_perfil = None
        self._ultima_verificacion = None
        self._cache_duracion = timedelta(minutes=5)  # Cachear por 5 minutos

    def es_horario_forex(self) -> bool:
        """Verifica si el mercado Forex está abierto (Lunes 00:00 a Viernes 22:00 UTC)"""
        from datetime import timezone
        ahora = datetime.now(timezone.utc)
        dia_semana = ahora.weekday()  # 0=Lunes, 6=Domingo
        hora = ahora.hour
        # Forex cerrado: Viernes después de 22:00 UTC hasta Domingo 22:00 UTC
        if dia_semana == 4 and hora >= 22:  # Viernes después de 22:00
            return False
        if dia_semana == 5:  # Sábado completo
            return False
        if dia_semana == 6 and hora < 22:  # Domingo antes de 22:00
            return False
        return True

    def es_horario_otc(self) -> bool:
        """Verifica si es horario para operar OTC (cuando Forex está cerrado)"""
        return not self.es_horario_forex()

    def obtener_modo_actual(self) -> str:
        """Determina el modo actual: 'REGULAR' u 'OTC'"""
        if self.es_horario_otc():
            return "OTC"
        return "REGULAR"

    def resolver(self, forzar_actualizacion: bool = False) -> Dict[str, Any]:
        """
        Resuelve el modo de mercado actual y devuelve la configuración apropiada.
        """
        ahora = datetime.now()
        # Usar cache si está disponible y no ha expirado
        if not forzar_actualizacion and self._ultima_verificacion:
            if ahora - self._ultima_verificacion < self._cache_duracion:
                if self._ultimo_perfil:
                    return self._ultimo_perfil
        modo = self.obtener_modo_actual()
        # Obtener configuración del perfil correspondiente
        if modo == "OTC":
            perfil_config = self.config.PERFIL_OTC
        else:
            perfil_config = self.config.PERFIL_REGULAR
        resultado = {
            "modo": modo,
            "perfil": perfil_config["nombre"],
            "descripcion": perfil_config["descripcion"],
            "pares": perfil_config["pares"],
            "dias_historicos": perfil_config["dias_historicos"],
            "horas_historico": perfil_config.get("horas_historico"),
            "modelo_path": perfil_config["modelo_path"],
            "escalador_path": perfil_config["escalador_path"],
            "historial_path": perfil_config["historial_path"],
            "cache_path": perfil_config["cache_path"],
            "min_datos": perfil_config["min_datos"],
            "epoch_cantidad": perfil_config["epoch_cantidad"],
            "intervalo_reentrenamiento": perfil_config["intervalo_reentrenamiento_horas"],
            "es_forex_abierto": self.es_horario_forex(),
            "es_otc_activo": self.es_horario_otc(),
            "timestamp": ahora.isoformat()
        }
        # Cachear resultado
        self._ultimo_perfil = resultado
        self._ultima_verificacion = ahora
        # Actualizar configuración global si cambió el modo
        if self.config.PERFIL_ACTIVO != modo:
            logger.info(
                f"Cambio de modo detectado: {
                    self.config.PERFIL_ACTIVO} -> {modo}")
            self.config.cambiar_perfil(modo)
        return resultado

    def obtener_rango_fechas(
            self, perfil: str = None) -> Tuple[datetime, datetime]:
        """
        Calcula el rango de fechas para obtener datos históricos según el perfil.
        Returns:
            Tuple (fecha_inicio, fecha_fin)
        """
        if perfil is None:
            perfil = self.obtener_modo_actual()
        ahora = datetime.now()
        if perfil == "OTC":
            # Para OTC: últimas 24 horas
            horas = self.config.PERFIL_OTC.get("horas_historico", 24)
            fecha_inicio = ahora - timedelta(hours=horas)
        else:
            # Para REGULAR: últimos 90 días
            dias = self.config.PERFIL_REGULAR["dias_historicos"]
            fecha_inicio = ahora - timedelta(days=dias)
        return (fecha_inicio, ahora)

    def filtrar_datos_por_perfil(
            self, df: pd.DataFrame, perfil: str = None) -> pd.DataFrame:
        """
        Filtra un DataFrame para incluir solo datos válidos según el perfil.
        Para REGULAR: Solo días hábiles (Lunes-Viernes)
        Para OTC: Todos los datos del período
        """
        if df is None or df.empty:
            return df
        if perfil is None:
            perfil = self.obtener_modo_actual()
        if perfil == "REGULAR":
            # Filtrar solo días hábiles
            if 'time' in df.columns:
                df = df[df['time'].dt.weekday < 5]
            elif df.index.name == 'time' or isinstance(df.index, pd.DatetimeIndex):
                df = df[df.index.weekday < 5]
        return df

    def info(self) -> str:
        """Retorna información del estado actual del mercado"""
        modo = self.resolver()
        return (f"=== ESTADO DEL MERCADO ===\n"
                f"Modo: {modo['modo']}\n"
                f"Forex abierto: {
                    'Sí' if modo['es_forex_abierto'] else 'No'}\n"
                f"OTC activo: {'Sí' if modo['es_otc_activo'] else 'No'}\n"
                f"Pares disponibles: {len(modo['pares'])}\n"
                f"Días históricos: {modo['dias_historicos']}\n"
                f"Modelo: {modo['modelo_path']}")


