class GeneradorDatosSinteticos:
    def __init__(self):
        self.seed = 42
        np.random.seed(self.seed)
        random.seed(self.seed)

    def generar_datos_Binary(self, simbolo: str, timeframe: str,
                             fecha_inicio: datetime, fecha_fin: datetime) -> pd.DataFrame:
        """Genera datos sintéticos realistas de Binary"""
        try:
            # Configurar parámetros base según el par
            if simbolo == "EURUSD":
                precio_base = 1.1000
                volatilidad = 0.0015
            elif simbolo == "USDJPY":
                precio_base = 110.00
                volatilidad = 0.008
            elif simbolo == "GBPUSD":
                precio_base = 1.3000
                volatilidad = 0.002
            else:
                precio_base = 1.0000
                volatilidad = 0.0015
            # Calcular número de puntos según timeframe
            if timeframe == "5":
                delta_minutos = 5
            else:
                delta_minutos = 5
            # Generar timestamps
            timestamps = []
            fecha_actual = fecha_inicio
            while fecha_actual <= fecha_fin:
                timestamps.append(fecha_actual)
                fecha_actual += timedelta(minutes=delta_minutos)
            num_puntos = len(timestamps)
            logger.info(
                f"Generando {num_puntos} puntos de datos para {simbolo} ({timeframe})")
            # Generar datos OHLCV sintéticos
            datos = []
            precio_actual = precio_base
            for i, timestamp in enumerate(timestamps):
                # Agregar tendencia y ciclos
                tendencia = math.sin(i * 0.01) * volatilidad * 5
                ruido = np.random.normal(0, volatilidad)
                cambio = tendencia + ruido
                # Calcular OHLC
                open_price = precio_actual
                cambio_intrabar = np.random.normal(0, volatilidad * 0.5)
                high = open_price + abs(cambio_intrabar) + \
                    abs(np.random.normal(0, volatilidad * 0.3))
                low = open_price - abs(cambio_intrabar) - \
                    abs(np.random.normal(0, volatilidad * 0.3))
                close = open_price + cambio
                # Volumen sintético
                volume = random.randint(100, 1000)
                datos.append({
                    'time': timestamp,
                    'open': round(open_price, 5),
                    'high': round(high, 5),
                    'low': round(low, 5),
                    'close': round(close, 5),
                    'volume': volume
                })
                precio_actual = close
            df = pd.DataFrame(datos)
            df.set_index('time', inplace=True)
            logger.info(
                f"Generados {
                    len(df)} puntos de datos sintéticos para {simbolo}")
            return df
        except Exception as e:
            logger.error(f"Error generando datos sintéticos: {e}")
            return pd.DataFrame()

    def generar_datos_multiples_pares(self, pares: List[str], timeframe: str,
                                      fecha_inicio: datetime, fecha_fin: datetime) -> Dict[str, pd.DataFrame]:
        """Genera datos para múltiples pares de divisas"""
        datos_pares = {}
        for par in pares:
            datos_pares[par] = self.generar_datos_Binary(
                par, timeframe, fecha_inicio, fecha_fin)
        return datos_pares

    def generar_datos_sinteticos(
            self, simbolo: str, num_muestras: int = 500) -> pd.DataFrame:
        """Genera datos sintéticos simples para un par"""
        fecha_fin = datetime.now()
        fecha_inicio = fecha_fin - \
            timedelta(days=num_muestras * 5 // (24 * 12)
                      )  # Aprox 5 min timeframe
        return self.generar_datos_Binary(simbolo, "5", fecha_inicio, fecha_fin)

    def calcular_indicadores(self, datos: pd.DataFrame) -> dict:
        """
        Calcula indicadores técnicos a partir de datos OHLCV.
        Args:
            datos: DataFrame con columnas open, high, low, close, volume
        Returns:
            Diccionario con indicadores calculados
        """
        try:
            if datos is None or len(datos) < 20:
                return self._indicadores_default()
            close = datos['close'] if 'close' in datos.columns else datos.iloc[:, 3]
            high = datos['high'] if 'high' in datos.columns else datos.iloc[:, 1]
            low = datos['low'] if 'low' in datos.columns else datos.iloc[:, 2]
            # Calcular indicadores
            indicadores = {}
            # RSI
            rsi_series = _rsi_series(close, 14)
            rsi_val = rsi_series.iloc[-1] if len(rsi_series) else np.nan
            indicadores['RSI'] = float(rsi_val) if np.isfinite(rsi_val) else 50.0
            # EMAs
            ema9 = _ema_series(close, 9).iloc[-1]
            ema21 = _ema_series(close, 21).iloc[-1]
            indicadores['EMA_9'] = float(ema9) if np.isfinite(ema9) else 0.0
            indicadores['EMA_21'] = float(ema21) if np.isfinite(ema21) else 0.0
            # MACD
            ema12 = _ema_series(close, 12)
            ema26 = _ema_series(close, 26)
            macd = ema12 - ema26
            signal = _ema_series(macd, 9)
            macd_val = macd.iloc[-1]
            signal_val = signal.iloc[-1]
            hist_val = (macd - signal).iloc[-1]
            indicadores['MACD'] = float(macd_val) if np.isfinite(macd_val) else 0.0
            indicadores['MACD_signal'] = float(signal_val) if np.isfinite(signal_val) else 0.0
            indicadores['MACD_hist'] = float(hist_val) if np.isfinite(hist_val) else 0.0
            # Bollinger Bands
            sma20 = close.rolling(20).mean()
            std20 = close.rolling(20).std()
            indicadores['BB_upper'] = float((sma20 + 2 * std20).iloc[-1])
            indicadores['BB_lower'] = float((sma20 - 2 * std20).iloc[-1])
            indicadores['BB_width'] = float(
                (indicadores['BB_upper'] - indicadores['BB_lower']) / sma20.iloc[-1])
            # ATR
            atr_series = _atr_series(high, low, close, 14)
            atr_val = atr_series.iloc[-1] if len(atr_series) else np.nan
            indicadores['ATR'] = float(atr_val) if np.isfinite(atr_val) else 0.0
            # Stochastic
            low14 = low.rolling(14).min()
            high14 = high.rolling(14).max()
            indicadores['stoch_k'] = float(
                100 * (close.iloc[-1] - low14.iloc[-1]) / (high14.iloc[-1] - low14.iloc[-1] + 1e-10))
            # Tendencia
            indicadores['tendencia'] = 1 if indicadores['EMA_9'] > indicadores['EMA_21'] else -1
            # Momentum
            indicadores['momentum'] = float(
                close.iloc[-1] - close.iloc[-10] if len(close) > 10 else 0)
            # Fuerza de señal
            rsi_score = (indicadores['RSI'] - 50) / 50
            macd_score = 1 if indicadores['MACD_hist'] > 0 else -1
            indicadores['fuerza_senal'] = float(
                (rsi_score + macd_score + indicadores['tendencia']) / 3)
            # Precio actual
            indicadores['close'] = float(close.iloc[-1])
            return indicadores
        except Exception as e:
            logger.error(f"Error calculando indicadores: {e}")
            return self._indicadores_default()

    def _indicadores_default(self) -> dict:
        """Retorna indicadores por defecto"""
        return {
            'RSI': 50.0, 'EMA_9': 0, 'EMA_21': 0, 'MACD': 0, 'MACD_signal': 0,
            'MACD_hist': 0, 'BB_upper': 0, 'BB_lower': 0, 'BB_width': 0,
            'ATR': 0, 'stoch_k': 50, 'tendencia': 0, 'momentum': 0,
            'fuerza_senal': 0, 'close': 0
        }

    def generar_datos_binarios(self, simbolo: str, timeframe: str = "5",
                               fecha_inicio: datetime = None, fecha_fin: datetime = None,
                               num_muestras: int = 5000, payout: float = 0.82) -> pd.DataFrame:
        """
        Genera datos sinteticos realistas para OPCIONES BINARIAS.
        Incluye etiquetas CALL/PUT, payouts e indicadores tecnicos.
        Args:
            simbolo: Par de divisas (ej: EURUSD)
            timeframe: Timeframe en minutos (default: 5)
            fecha_inicio: Fecha de inicio (default: 90 dias atras)
            fecha_fin: Fecha fin (default: ahora)
            num_muestras: Numero de muestras a generar
            payout: Payout de la opcion binaria (default: 0.82 = 82%)
        Returns:
            DataFrame con datos para entrenar red neuronal de opciones binarias
        """
        try:
            logger.info(
                f"Generando {num_muestras} muestras de opciones binarias para {simbolo}")
            if fecha_inicio is None:
                fecha_inicio = datetime.now() - timedelta(days=90)
            if fecha_fin is None:
                fecha_fin = datetime.now()
            # Configurar parametros base segun el par
            params = {
                "EURUSD": {"precio_base": 1.0850, "volatilidad": 0.0008, "spread": 0.00010},
                "USDJPY": {"precio_base": 157.50, "volatilidad": 0.015, "spread": 0.010},
                "GBPUSD": {"precio_base": 1.2700, "volatilidad": 0.0012, "spread": 0.00015},
                "USDCHF": {"precio_base": 0.8850, "volatilidad": 0.0007, "spread": 0.00012},
                "AUDUSD": {"precio_base": 0.6250, "volatilidad": 0.0009, "spread": 0.00012},
                "USDCAD": {"precio_base": 1.4350, "volatilidad": 0.0008, "spread": 0.00012},
                "NZDUSD": {"precio_base": 0.5650, "volatilidad": 0.0010, "spread": 0.00015},
                "EURGBP": {"precio_base": 0.8550, "volatilidad": 0.0006, "spread": 0.00010},
                "EURJPY": {"precio_base": 170.80, "volatilidad": 0.018, "spread": 0.015},
                "GBPJPY": {"precio_base": 200.00, "volatilidad": 0.022, "spread": 0.020},
            }
            p = params.get(simbolo,
                           {"precio_base": 1.0000,
                            "volatilidad": 0.0010,
                            "spread": 0.00012})
            precio_base = p["precio_base"]
            volatilidad = p["volatilidad"]
            spread = p["spread"]
            delta_minutos = int(timeframe)
            # Generar timestamps
            timestamps = []
            fecha_actual = fecha_inicio
            while len(timestamps) < num_muestras + \
                    10:  # +10 para calcular labels
                # Solo horas de mercado activo (simulacion)
                hora = fecha_actual.hour
                if 7 <= hora <= 22:  # Horario de trading activo
                    timestamps.append(fecha_actual)
                fecha_actual += timedelta(minutes=delta_minutos)
            # Generar datos OHLCV con diferentes escenarios de mercado
            datos = []
            precio_actual = precio_base
            escenario_actual = "ranging"  # trending_up, trending_down, ranging, volatile
            cambio_escenario_counter = 0
            for i, timestamp in enumerate(timestamps[:num_muestras + 5]):
                # Cambiar escenario de mercado periodicamente
                cambio_escenario_counter += 1
                if cambio_escenario_counter > random.randint(20, 100):
                    escenario_actual = random.choice(
                        ["trending_up", "trending_down", "ranging", "volatile"])
                    cambio_escenario_counter = 0
                # Calcular cambio segun escenario
                if escenario_actual == "trending_up":
                    tendencia = volatilidad * 0.3
                    ruido = np.random.normal(0, volatilidad * 0.5)
                elif escenario_actual == "trending_down":
                    tendencia = -volatilidad * 0.3
                    ruido = np.random.normal(0, volatilidad * 0.5)
                elif escenario_actual == "volatile":
                    tendencia = 0
                    ruido = np.random.normal(0, volatilidad * 2)
                else:  # ranging
                    tendencia = math.sin(i * 0.05) * volatilidad * 0.2
                    ruido = np.random.normal(0, volatilidad * 0.7)
                cambio = tendencia + ruido
                # Calcular OHLC realista
                open_price = precio_actual
                close_price = open_price + cambio
                # High y Low realistas
                rango_hl = abs(cambio) + \
                    abs(np.random.normal(0, volatilidad * 0.5))
                if close_price > open_price:
                    high = close_price + rango_hl * 0.3
                    low = open_price - rango_hl * 0.7
                else:
                    high = open_price + rango_hl * 0.7
                    low = close_price - rango_hl * 0.3
                # Asegurar que high >= max(open, close) y low <= min(open,
                # close)
                high = max(high, open_price, close_price) + \
                    abs(np.random.normal(0, volatilidad * 0.1))
                low = min(low, open_price, close_price) - \
                    abs(np.random.normal(0, volatilidad * 0.1))
                # Volumen correlacionado con volatilidad
                base_volume = 500
                volume = int(base_volume * (1 + abs(cambio) /
                             volatilidad) * random.uniform(0.8, 1.2))
                datos.append({
                    'timestamp': timestamp,
                    'open': round(open_price, 5),
                    'high': round(high, 5),
                    'low': round(low, 5),
                    'close': round(close_price, 5),
                    'volume': volume,
                    'escenario': escenario_actual
                })
                precio_actual = close_price
            df = pd.DataFrame(datos)
            # Calcular indicadores tecnicos
            df = self._calcular_indicadores_binarios(df)
            # Generar etiquetas CALL/PUT basadas en precio a T+1 (5 minutos
            # despues)
            df['precio_expiracion'] = df['close'].shift(-1)
            df['direction_label'] = np.where(
                df['precio_expiracion'] > df['close'], 'CALL', 'PUT')
            df['resultado_binario'] = np.where(
                # 1=CALL gana, 0=PUT gana
                df['precio_expiracion'] > df['close'], 1, 0)
            # Agregar payout y calcular ganancia/perdida
            df['payout'] = payout
            df['ganancia_potencial'] = np.where(
                df['resultado_binario'] == 1,
                payout,  # Gana CALL
                -1.0     # Pierde
            )
            # Calcular probabilidad objetivo (para entrenamiento)
            # Basada en la fuerza de los indicadores
            df['probabilidad_call'] = 0.5  # Default
            # RSI influencia la probabilidad
            if 'RSI' in df.columns:
                # Sobreventa -> probable suba
                df.loc[df['RSI'] < 30, 'probabilidad_call'] = 0.65
                # Sobrecompra -> probable baja
                df.loc[df['RSI'] > 70, 'probabilidad_call'] = 0.35
            # Tendencia EMA influencia
            if 'EMA_21' in df.columns and 'EMA_50' in df.columns:
                df.loc[df['EMA_21'] > df['EMA_50'], 'probabilidad_call'] += 0.1
                df.loc[df['EMA_21'] < df['EMA_50'], 'probabilidad_call'] -= 0.1
            # Limitar probabilidad entre 0.2 y 0.8
            df['probabilidad_call'] = df['probabilidad_call'].clip(0.2, 0.8)
            # Agregar metadata
            df['simbolo'] = simbolo
            df['timeframe'] = timeframe
            df['tipo_datos'] = 'SINTETICO_BINARIO'
            df['spread'] = spread
            # Eliminar ultimas filas sin label
            df = df.dropna(subset=['precio_expiracion'])
            # Verificar distribucion balanceada
            call_ratio = (df['resultado_binario'] == 1).mean()
            logger.info(
                f"Generadas {
                    len(df)} muestras binarias para {simbolo}")
            logger.info(
                f"Distribucion: CALL={
                    call_ratio:.1%}, PUT={
                    1 -
                    call_ratio:.1%}")
            return df
        except Exception as e:
            logger.error(f"Error generando datos binarios: {e}")
            import traceback
            logger.error(traceback.format_exc())
            return pd.DataFrame()

    def _calcular_indicadores_binarios(self, df: pd.DataFrame) -> pd.DataFrame:
        """Calcula indicadores tecnicos para opciones binarias"""
        try:
            # EMA 21 y 50
            df['EMA_21'] = _ema_series(df['close'], 21)
            df['EMA_50'] = _ema_series(df['close'], 50)
            # RSI 14
            df['RSI'] = _rsi_series(df['close'], 14)
            # MACD
            ema12 = _ema_series(df['close'], 12)
            ema26 = _ema_series(df['close'], 26)
            df['MACD'] = ema12 - ema26
            df['MACD_signal'] = _ema_series(df['MACD'], 9)
            df['MACD_hist'] = df['MACD'] - df['MACD_signal']
            # Bollinger Bands
            df['BB_middle'] = df['close'].rolling(window=20).mean()
            bb_std = df['close'].rolling(window=20).std()
            df['BB_upper'] = df['BB_middle'] + (bb_std * 2)
            df['BB_lower'] = df['BB_middle'] - (bb_std * 2)
            df['BB_width'] = (
                df['BB_upper'] - df['BB_lower']) / df['BB_middle']
            # ATR (Average True Range) para volatilidad
            df['ATR'] = _atr_series(df['high'], df['low'], df['close'], 14)
            # Momentum
            df['momentum'] = df['close'] - df['close'].shift(10)
            df['momentum_pct'] = df['close'].pct_change(10) * 100
            # Stochastic
            low_14 = df['low'].rolling(window=14).min()
            high_14 = df['high'].rolling(window=14).max()
            df['stoch_k'] = 100 * (df['close'] - low_14) / (high_14 - low_14)
            df['stoch_d'] = df['stoch_k'].rolling(window=3).mean()
            # Tendencia (1=alcista, -1=bajista, 0=lateral)
            df['tendencia'] = np.where(df['EMA_21'] > df['EMA_50'], 1,
                                       np.where(df['EMA_21'] < df['EMA_50'], -1, 0))
            # Fuerza de la senal (combinacion de indicadores)
            df['fuerza_senal'] = (
                (df['RSI'] - 50) / 50 * 0.3 +  # RSI normalizado
                np.sign(df['MACD_hist']) * 0.3 +  # MACD direccion
                df['tendencia'] * 0.4  # Tendencia EMA
            )
            # Rellenar NaN con valores por defecto
            df = df.fillna(method='bfill').fillna(method='ffill')
            return df
        except Exception as e:
            logger.error(f"Error calculando indicadores: {e}")
            return df

    def generar_dataset_entrenamiento(self, pares: List[str] = None,
                                      num_muestras_por_par: int = 5000,
                                      payout: float = 0.82) -> pd.DataFrame:
        """
        Genera un dataset completo de entrenamiento para opciones binarias.
        Combina datos de multiples pares con etiquetas balanceadas.
        """
        if pares is None:
            pares = [
                "EURUSD",
                "USDJPY",
                "GBPUSD",
                "AUDUSD",
                "EURJPY",
                "GBPJPY"]
        logger.info(
            f"Generando dataset de entrenamiento para {
                len(pares)} pares...")
        todos_datos = []
        for par in pares:
            df_par = self.generar_datos_binarios(
                simbolo=par,
                num_muestras=num_muestras_por_par,
                payout=payout
            )
            if not df_par.empty:
                todos_datos.append(df_par)
        if todos_datos:
            dataset = pd.concat(todos_datos, ignore_index=True)
            # Mezclar datos para evitar sesgo temporal
            dataset = dataset.sample(
                frac=1, random_state=42).reset_index(
                drop=True)
            logger.info(
                f"Dataset de entrenamiento generado: {
                    len(dataset)} muestras totales")
            logger.info(
                f"Distribucion CALL/PUT: {
                    dataset['resultado_binario'].mean():.1%} / {
                    1 - dataset['resultado_binario'].mean():.1%}")
            return dataset
        return pd.DataFrame()
# ========== REPOSITORIO DE OPERACIONES EXITOSAS ==========
# CAPITULO 12:
# ==================================================


class OperationsRepository:
    """
    Sistema de almacenamiento de trades para autoaprendizaje.
    Guarda operaciones exitosas con sus condiciones de mercado para
    mejorar predicciones futuras.
    """

    def __init__(self, archivo_db: str = "trades_exitosos.json"):
        self.archivo_db = archivo_db
        self.trades: List[dict] = []
        self.cargar_trades()
        self.max_trades = 10000  # Maximo de trades a mantener

    def cargar_trades(self):
        """Carga trades guardados desde archivo JSON"""
        try:
            if os.path.exists(self.archivo_db):
                with open(self.archivo_db, 'r') as f:
                    data = json.load(f)
                self.trades = data.get('trades', [])
                logger.info(
                    f"Cargados {len(self.trades)} trades historicos desde {self.archivo_db}")
        except Exception as e:
            logger.warning(f"Error cargando trades: {e}")
            self.trades = []

    def guardar_trades(self):
        """Guarda trades en archivo JSON"""
        try:
            data = {
                'version': '2.0',
                'ultima_actualizacion': datetime.now().isoformat(),
                'total_trades': len(self.trades),
                # Mantener solo los ultimos
                'trades': self.trades[-self.max_trades:]
            }
            with open(self.archivo_db, 'w') as f:
                json.dump(data, f, indent=2, default=str)
            logger.info(
                f"Guardados {len(self.trades)} trades en {self.archivo_db}")
        except Exception as e:
            logger.error(f"Error guardando trades: {e}")

    def agregar_trade(self, trade: dict, exitoso: bool):
        """
        Agrega un trade al repositorio.
        Args:
            trade: Diccionario con datos del trade (simbolo, direccion, indicadores, etc.)
            exitoso: True si el trade fue ganador
        """
        try:
            indicadores_src = trade.get(
                'indicadores',
                {}) if isinstance(
                trade.get(
                    'indicadores',
                    None),
                dict) else {}

            def _get_indicator(*keys, default=0):
                for k in keys:
                    if k in indicadores_src:
                        return indicadores_src.get(k, default)
                    low = str(k).lower()
                    if low in indicadores_src:
                        return indicadores_src.get(low, default)
                    if k in trade:
                        return trade.get(k, default)
                    if low in trade:
                        return trade.get(low, default)
                return default

            direccion = (trade.get('direccion')
                         or trade.get('direction') or '').upper()
            if direccion not in ("CALL", "PUT"):
                direccion = 'UNKNOWN'

            # Crear fingerprint del trade
            alineacion_tf = indicadores_src.get('alineacion_tf')
            if not isinstance(alineacion_tf, dict):
                alineacion_tf = trade.get('alineacion_tf')
            if not isinstance(alineacion_tf, dict):
                alineacion_tf = None
            if not exitoso:
                return
            trade_record = {
                'id': len(self.trades) + 1,
                'timestamp': datetime.now().isoformat(),
                'simbolo': trade.get('simbolo', 'UNKNOWN'),
                'direccion': direccion,  # CALL o PUT
                'precio_entrada': trade.get('precio_entrada', 0),
                'precio_salida': trade.get('precio_salida', 0),
                'payout': trade.get('payout', 0.82),
                'exitoso': exitoso,
                'ganancia': trade.get('ganancia', 0),
                'alineacion_tf': alineacion_tf,
                # Indicadores al momento del trade
                'indicadores': {
                    'RSI': _get_indicator('RSI', 'rsi', default=50),
                    'MACD': _get_indicator('MACD', 'macd', default=0),
                    'MACD_hist': _get_indicator('MACD_hist', 'macd_hist', default=0),
                    'EMA_21': _get_indicator('EMA_21', 'ema_21', default=0),
                    'EMA_50': _get_indicator('EMA_50', 'ema_50', default=0),
                    'EMA_200': _get_indicator('EMA_200', 'ema_200', default=0),
                    'ema_21': _get_indicator('ema_21', 'EMA_21', default=0),
                    'ema_50': _get_indicator('ema_50', 'EMA_50', default=0),
                    'ema_200': _get_indicator('ema_200', 'EMA_200', default=0),
                    'tendencia': _get_indicator('tendencia', default=0),
                    'stoch_k': _get_indicator('stoch_k', default=50),
                    'ATR': _get_indicator('ATR', 'atr', default=0),
                    'BB_width': _get_indicator('BB_width', 'bb_width', default=0),
                    'momentum': _get_indicator('momentum', default=0),
                    'fuerza_senal': _get_indicator('fuerza_senal', default=0),
                    'TDI_rsi': _get_indicator('TDI_rsi', 'tdi_rsi', default=50),
                    'tdi_rsi': _get_indicator('tdi_rsi', 'TDI_rsi', default=50),
                    'tdi_precio_linea': _get_indicator('tdi_precio_linea', 'TDI_precio', default=50),
                    'tdi_senal_linea': _get_indicator('tdi_senal_linea', 'TDI_senal', default=50),
                    'wm_valido': bool(_get_indicator('wm_valido', default=False)),
                    'wm_tipo': _get_indicator('wm_tipo', default=None),
                    'wm_direccion': _get_indicator('wm_direccion', default=None),
                    'wm_liq_ok': bool(_get_indicator('wm_liq_ok', default=False)),
                    'wm_confirm_ok': bool(_get_indicator('wm_confirm_ok', default=False)),
                    'wm_mm_ok': bool(_get_indicator('wm_mm_ok', default=False)),
                    'wm_razon': _get_indicator('wm_razon', default=None),
                },
                'probabilidad_predicha': trade.get('probabilidad', 0.5),
                'escenario_mercado': trade.get('escenario', 'unknown')
            }
            self.trades.append(trade_record)
            
            # Limitar historial de trades en memoria para evitar fugas
            MAX_TRADES_MEMORY = 500
            if len(self.trades) > MAX_TRADES_MEMORY:
                self.trades = self.trades[-MAX_TRADES_MEMORY:]
                
            self.guardar_trades()
            logger.info(
                f"Trade {
                    'EXITOSO ✅' if exitoso else 'FALLIDO ❌'} registrado: {
                    trade_record['simbolo']} {
                    trade_record['direccion']}")
        except Exception as e:
            logger.error(f"Error agregando trade: {e}")

    def obtener_trades_exitosos(
            self, simbolo: str = None, direccion: str = None) -> List[dict]:
        """Obtiene trades exitosos filtrados por simbolo y/o direccion"""
        try:
            filtrados = [t for t in self.trades if t.get('exitoso', False)]
            if simbolo:
                filtrados = [
                    t for t in filtrados if t.get('simbolo') == simbolo]
            if direccion:
                filtrados = [
                    t for t in filtrados if t.get('direccion') == direccion]
            return filtrados
        except Exception as e:
            logger.error(f"Error obteniendo trades exitosos: {e}")
            return []

    def calcular_tasa_exito(self, simbolo: str = None) -> float:
        """Calcula la tasa de exito general o por simbolo"""
        try:
            trades = self.trades
            if simbolo:
                trades = [t for t in trades if t.get('simbolo') == simbolo]
            if not trades:
                return 0.5
            exitosos = sum(1 for t in trades if t.get('exitoso', False))
            return exitosos / len(trades)
        except Exception as e:
            logger.error(f"Error calculando tasa de exito: {e}")
            return 0.5

    def obtener_patrones_exitosos(self, simbolo: str = None) -> dict:
        """
        Analiza patrones en trades exitosos para autoaprendizaje.
        Retorna rangos de indicadores que han sido exitosos.
        """
        try:
            exitosos = self.obtener_trades_exitosos(simbolo)
            if len(exitosos) < 10:
                return {}
            # Extraer indicadores de trades exitosos
            patrones = {
                'RSI_optimo': {'min': 100, 'max': 0, 'promedio': 0},
                'MACD_hist_promedio': 0,
                'tendencia_preferida': 0,
                'stoch_k_optimo': {'min': 100, 'max': 0},
                'fuerza_senal_minima': 0
            }
            rsi_vals = [t['indicadores'].get('RSI', 50) for t in exitosos]
            patrones['RSI_optimo']['min'] = min(rsi_vals)
            patrones['RSI_optimo']['max'] = max(rsi_vals)
            patrones['RSI_optimo']['promedio'] = sum(rsi_vals) / len(rsi_vals)
            macd_vals = [
                t['indicadores'].get(
                    'MACD_hist',
                    0) for t in exitosos]
            patrones['MACD_hist_promedio'] = sum(macd_vals) / len(macd_vals)
            tendencia_vals = [
                t['indicadores'].get(
                    'tendencia',
                    0) for t in exitosos]
            patrones['tendencia_preferida'] = sum(
                tendencia_vals) / len(tendencia_vals)
            fuerza_vals = [
                t['indicadores'].get(
                    'fuerza_senal',
                    0) for t in exitosos]
            patrones['fuerza_senal_minima'] = min(
                fuerza_vals) if fuerza_vals else 0
            return patrones
        except Exception as e:
            logger.error(f"Error analizando patrones: {e}")
            return {}

    def comparar_con_historico(
            self, indicadores_actuales: dict, direccion: str, simbolo: str) -> float:
        """
        Compara indicadores actuales con trades exitosos historicos.
        Retorna un score de similitud (0-1) que indica probabilidad de exito.
        """
        try:
            exitosos = self.obtener_trades_exitosos(simbolo, direccion)
            if len(exitosos) < 5:
                return 0.5  # No hay suficientes datos
            # Calcular similitud con trades exitosos
            similitudes = []
            for trade in exitosos[-50:]:  # Ultimos 50 trades exitosos
                ind_hist = trade.get('indicadores', {})
                # Calcular distancia entre indicadores
                diffs = []
                # RSI (normalizado 0-100)
                rsi_diff = abs(indicadores_actuales.get(
                    'RSI', 50) - ind_hist.get('RSI', 50)) / 100
                diffs.append(rsi_diff)
                # Tendencia (-1 a 1)
                tend_diff = abs(indicadores_actuales.get(
                    'tendencia', 0) - ind_hist.get('tendencia', 0)) / 2
                diffs.append(tend_diff)
                # Stochastic (0-100)
                stoch_diff = abs(indicadores_actuales.get(
                    'stoch_k', 50) - ind_hist.get('stoch_k', 50)) / 100
                diffs.append(stoch_diff)
                # Calcular similitud (1 - distancia promedio)
                similitud = 1 - (sum(diffs) / len(diffs))
                similitudes.append(similitud)
            # Retornar promedio de similitudes ponderado
            if similitudes:
                # Dar mas peso a las similitudes mas altas
                similitudes.sort(reverse=True)
                top_similitudes = similitudes[:10]  # Top 10 mas similares
                return sum(top_similitudes) / len(top_similitudes)
            return 0.5
        except Exception as e:
            logger.error(f"Error comparando con historico: {e}")
            return 0.5

    def obtener_estadisticas(self) -> dict:
        """Retorna estadisticas generales del repositorio"""
        try:
            total = len(self.trades)
            exitosos = sum(1 for t in self.trades if t.get('exitoso', False))
            por_simbolo = {}
            for t in self.trades:
                sym = t.get('simbolo', 'UNKNOWN')
                if sym not in por_simbolo:
                    por_simbolo[sym] = {'total': 0, 'exitosos': 0}
                por_simbolo[sym]['total'] += 1
                if t.get('exitoso', False):
                    por_simbolo[sym]['exitosos'] += 1
            return {
                'total_trades': total,
                'trades_exitosos': exitosos,
                'tasa_exito_global': exitosos / total if total > 0 else 0,
                'por_simbolo': por_simbolo
            }
        except Exception as e:
            logger.error(f"Error obteniendo estadisticas: {e}")
            return {}
# ========== PREDICTOR ENSEMBLE CON CALIBRACION 85%+ ==========
# CAPITULO 13:
# ==================================================


class EnsemblePredictor:
    """
    Sistema de prediccion calibrado que combina:
    - Red neuronal (modelo PyTorch)
    - Indicadores tecnicos
    - Historial de trades exitosos
    - Estrategia Market Maker (Capitulos 1-10)
    Para alcanzar precision >= 85% en predicciones de opciones binarias.
    """

    def __init__(self, operations_repo: OperationsRepository = None):
        self.operations_repo = operations_repo or OperationsRepository()
        self.modelo_nn = None
        self.market_maker = None  # Se inicializa despues para evitar dependencia circular
        self.umbral_confianza = 0.92  # Solo operar si confianza >= 92%
        self.peso_nn = 0.40  # Peso de la red neuronal
        self.peso_indicadores = 0.25  # Peso de indicadores tecnicos
        self.peso_historico = 0.15  # Peso del historial
        self.peso_market_maker = 0.20  # Peso de estrategia Market Maker
        self.temperatura_calibracion = 1.5  # Para calibracion de probabilidad
        self.predicciones_correctas = 0
        self.predicciones_totales = 0

    def inicializar_market_maker(self):
        """Inicializa la estrategia Market Maker (llamar despues de crear la clase)"""
        try:
            # Se creara una instancia global de MarketMakerStrategy
            self.market_maker = True  # Marcador para usar MM cuando este disponible
            logger.info("Market Maker habilitado en EnsemblePredictor")
        except Exception as e:
            logger.warning(f"No se pudo inicializar Market Maker: {e}")

    def predecir(self, indicadores: dict, simbolo: str,
                 modelo_nn=None) -> dict:
        """
        Genera prediccion combinando multiples fuentes.
        Retorna direccion (CALL/PUT) y probabilidad calibrada.
        """
        try:
            # 1. Prediccion basada en indicadores tecnicos
            prob_indicadores, dir_indicadores = self._predecir_por_indicadores(
                indicadores)
            # 2. Prediccion basada en historial de trades exitosos
            prob_historico_call = self.operations_repo.comparar_con_historico(
                indicadores, 'CALL', simbolo
            )
            prob_historico_put = self.operations_repo.comparar_con_historico(
                indicadores, 'PUT', simbolo
            )
            # 3. Prediccion de red neuronal (si disponible)
            prob_nn = 0.5
            dir_nn = None
            if modelo_nn is not None:
                prob_nn = self._predecir_nn(indicadores, modelo_nn)
                dir_nn = 'CALL' if prob_nn >= 0.5 else 'PUT'

            if dir_nn in ('CALL', 'PUT') and dir_indicadores in (
                    'CALL', 'PUT') and dir_nn != dir_indicadores:
                logger.warning(
                    f"Conflicto IA vs técnico en {simbolo}: IA={dir_nn} (p={
                        prob_nn:.3f}) vs TECNICO={dir_indicadores} (p={
                        prob_indicadores:.3f})"
                )
                confianza_conflicto = max(
                    prob_nn, 1 - prob_nn) if dir_nn else 0.5
                return {
                    'direccion': dir_nn,
                    'confianza': confianza_conflicto,
                    'probabilidad_call': float(prob_nn),
                    'probabilidad_put': float(1 - prob_nn),
                    'operar': False,
                    'motivo': 'CONFLICTO_IA_TECNICO',
                    'componentes': {
                        'indicadores': prob_indicadores,
                        'historico_call': prob_historico_call,
                        'historico_put': prob_historico_put,
                        'nn': prob_nn,
                        'dir_indicadores': dir_indicadores,
                        'dir_nn': dir_nn
                    }
                }
            # Combinar predicciones con pesos
            if dir_indicadores == 'CALL':
                prob_final_call = (
                    prob_indicadores * self.peso_indicadores +
                    prob_historico_call * self.peso_historico +
                    prob_nn * self.peso_nn
                )
            else:
                prob_final_call = (
                    (1 - prob_indicadores) * self.peso_indicadores +
                    prob_historico_call * self.peso_historico +
                    prob_nn * self.peso_nn
                )
            # Normalizar
            prob_final_call = max(0.1, min(0.9, prob_final_call))
            # Calibrar probabilidad (temperature scaling)
            prob_calibrada = self._calibrar_probabilidad(prob_final_call)
            # Determinar direccion
            if prob_calibrada >= 0.5:
                direccion = 'CALL'
                confianza = prob_calibrada
            else:
                direccion = 'PUT'
                confianza = 1 - prob_calibrada
            # Verificar si cumple umbral de confianza
            operar = confianza >= self.umbral_confianza
            resultado = {
                'direccion': direccion,
                'confianza': confianza,
                'probabilidad_call': prob_calibrada,
                'probabilidad_put': 1 - prob_calibrada,
                'operar': operar,
                'motivo': 'ALINEADO' if operar else 'BAJA_CONFIANZA',
                'componentes': {
                    'indicadores': prob_indicadores,
                    'historico_call': prob_historico_call,
                    'historico_put': prob_historico_put,
                    'nn': prob_nn,
                    'dir_indicadores': dir_indicadores,
                    'dir_nn': dir_nn
                }
            }
            logger.info(
                f"Prediccion {simbolo}: {direccion} con {
                    confianza:.1%} confianza {
                    '(OPERAR)' if operar else '(NO OPERAR)'}")
            return resultado
        except Exception as e:
            logger.error(f"Error en prediccion ensemble: {e}")
            return {
                'direccion': 'CALL',
                'confianza': 0.5,
                'operar': False
            }

    def predecir_con_market_maker(self, df: pd.DataFrame, indicadores: dict, simbolo: str,
                                  modelo_nn=None, market_maker_strategy=None,
                                  df_diario: pd.DataFrame = None) -> dict:
        """
        Prediccion avanzada que combina IA + Market Maker.
        Usa datos de precios (DataFrame) para analisis de patrones.
        Objetivo: 85%+ precision en senales de 5 minutos.
        """
        try:
            # 1. Prediccion base (IA + Indicadores + Historico)
            pred_base = self.predecir(indicadores, simbolo, modelo_nn)
            # 2. Prediccion Market Maker (si disponible)
            pred_mm = None
            if market_maker_strategy is not None and len(df) >= 50:
                pred_mm = market_maker_strategy.generar_senal_mm(
                    df, df_diario, simbolo)
            # 3. Combinar predicciones
            if pred_mm is None or pred_mm.get('senal') == 'ESPERAR':
                # Solo usar prediccion base si MM no tiene senal
                return pred_base
            # Calcular pesos ajustados
            conf_base = pred_base.get('confianza', 0.5)
            conf_mm = pred_mm.get('confianza', 0.5)
            dir_base = pred_base.get('direccion', 'CALL')
            dir_mm = pred_mm.get('senal', 'CALL')
            # Si ambos coinciden, aumentar confianza significativamente
            if dir_base == dir_mm:
                confianza_final = min(
                    0.98, (conf_base * 0.5) + (conf_mm * 0.5) + 0.10)
                direccion_final = dir_base
                alineacion = 'TOTAL'
            else:
                # Conflicto: usar el de mayor confianza, pero reducir
                # ligeramente
                if conf_mm > conf_base:
                    direccion_final = dir_mm
                    confianza_final = conf_mm * 0.9  # Penalizar por conflicto
                else:
                    direccion_final = dir_base
                    confianza_final = conf_base * 0.9
                alineacion = 'CONFLICTO'
            # Verificar umbral
            operar = confianza_final >= self.umbral_confianza
            resultado = {
                'direccion': direccion_final,
                'confianza': confianza_final,
                'operar': operar,
                'alineacion': alineacion,
                'componentes': {
                    'prediccion_base': pred_base,
                    'market_maker': pred_mm
                },
                'razones_mm': pred_mm.get('razones', []) if pred_mm else [],
                'sesion': pred_mm.get('detalles', {}).get('sesion', 'UNKNOWN') if pred_mm else 'UNKNOWN'
            }
            if operar:
                logger.info(f"SENAL COMBINADA {simbolo}: {direccion_final} | "
                            f"Confianza: {confianza_final:.1%} | Alineacion: {alineacion}")
                if pred_mm and pred_mm.get('razones'):
                    logger.info(
                        f"  Razones MM: {', '.join(pred_mm['razones'][:3])}")
            return resultado
        except Exception as e:
            logger.error(f"Error en prediccion con Market Maker: {e}")
            # Fallback a prediccion base
            return self.predecir(indicadores, simbolo, modelo_nn)

    def _predecir_por_indicadores(
            self, indicadores: dict) -> Tuple[float, str]:
        """Predice basandose en indicadores tecnicos"""
        try:
            score = 0.5
            # RSI
            rsi = indicadores.get('RSI', 50)
            if rsi < 25:
                score += 0.15  # Sobreventa -> CALL
            elif rsi > 75:
                score -= 0.15  # Sobrecompra -> PUT
            elif rsi < 40:
                score += 0.05
            elif rsi > 60:
                score -= 0.05
            # MACD Histograma
            macd_hist = indicadores.get('MACD_hist', 0)
            if macd_hist > 0:
                score += 0.1
            else:
                score -= 0.1
            # Tendencia EMA
            tendencia = indicadores.get('tendencia', 0)
            score += tendencia * 0.1
            # Stochastic
            stoch_k = indicadores.get('stoch_k', 50)
            if stoch_k < 20:
                score += 0.1
            elif stoch_k > 80:
                score -= 0.1
            # Fuerza de senal
            fuerza = indicadores.get('fuerza_senal', 0)
            score += fuerza * 0.1
            # Normalizar score
            score = max(0.1, min(0.9, score))
            direccion = 'CALL' if score >= 0.5 else 'PUT'
            probabilidad = score if score >= 0.5 else (1 - score)
            return probabilidad, direccion
        except Exception as e:
            logger.error(f"Error prediccion por indicadores: {e}")
            return 0.5, 'CALL'

    def _predecir_nn(self, indicadores: dict, modelo) -> float:
        """Predice usando la red neuronal"""
        try:
            modelo_nn = modelo
            scaler = None
            if isinstance(modelo, dict):
                modelo_nn = modelo.get("model")
                scaler = modelo.get("scaler")
            elif isinstance(modelo, tuple) and len(modelo) >= 1:
                modelo_nn = modelo[0]
                scaler = modelo[1] if len(modelo) > 1 else None

            if not (TORCH_AVAILABLE and modelo_nn is not None):
                return 0.5

            import torch

            def _infer_in_features(m):
                try:
                    for mod in m.modules():
                        if hasattr(mod, "in_features"):
                            return int(mod.in_features)
                except Exception:
                    pass
                try:
                    for p in m.parameters():
                        if hasattr(p, "shape") and len(p.shape) == 2:
                            return int(p.shape[1])
                except Exception:
                    pass
                return None

            expected_n = _infer_in_features(modelo_nn) or int(
                getattr(self.operations_repo, "n_features", 8) or 8)

            def _val(key, default=0.0):
                if key in indicadores:
                    return indicadores.get(key, default)
                low = key.lower()
                if low in indicadores:
                    return indicadores.get(low, default)
                return default

            rsi = float(_val("RSI", 50.0))
            macd = float(_val("MACD", 0.0))
            macd_hist = float(_val("MACD_hist", 0.0))
            stoch_k = float(_val("stoch_k", 50.0))
            atr = float(_val("ATR", 0.0))
            momentum = float(_val("momentum", 0.0))
            tendencia = float(_val("tendencia", 0.0))
            fuerza_senal = float(_val("fuerza_senal", 0.0))
            bb_width = float(_val("BB_width", 0.0))

            rsi_zona = 1.0 if rsi > 70 else (-1.0 if rsi < 30 else 0.0)
            rsi_dist_50 = abs(rsi - 50.0)
            macd_cruce = 1.0 if (
                macd > 0 and macd_hist > 0) else (-1.0 if (macd < 0 and macd_hist < 0) else 0.0)
            stoch_d = float(_val("stoch_d", 50.0))
            stoch_cruce = 1.0 if stoch_k > stoch_d else -1.0
            stoch_diff = stoch_k - stoch_d
            volatilidad = min(max(atr * 100.0, 0.0), 5.0) if atr else 0.0

            feature_map = {
                "RSI": rsi,
                "RSI_zona": rsi_zona,
                "RSI_distancia_50": rsi_dist_50,
                "MACD": macd,
                "MACD_hist": macd_hist,
                "MACD_cruce": macd_cruce,
                "stoch_k": stoch_k,
                "stoch_d": stoch_d,
                "stoch_cruce": stoch_cruce,
                "stoch_diferencia": stoch_diff,
                "ATR": atr,
                "volatilidad": volatilidad,
                "momentum": momentum,
                "tendencia": tendencia,
                "fuerza_senal": fuerza_senal,
                "BB_width": bb_width,
                "EMA_tendencia": float(_val("EMA_tendencia", 0.0)),
                "EMA_diferencia": float(_val("EMA_diferencia", 0.0)),
                "TDI_rsi": float(_val("TDI_rsi", _val("tdi_rsi", rsi))),
                "TDI_direccion": float(_val("TDI_direccion", 0.0)),
                "TDI_fuerza": float(_val("TDI_fuerza", 0.0)),
                "direccion": float(_val("direccion", 0.0)),
            }

            feature_names = None
            if isinstance(scaler, dict):
                feature_names = scaler.get("features")
            if isinstance(feature_names, list) and feature_names:
                features = [float(feature_map.get(name, 0.0))
                            for name in feature_names]
            else:
                base_order = [
                    "RSI", "RSI_zona", "RSI_distancia_50",
                    "MACD", "MACD_hist", "MACD_cruce",
                    "stoch_k", "stoch_d", "stoch_cruce", "stoch_diferencia",
                    "ATR", "volatilidad", "momentum", "tendencia", "fuerza_senal",
                    "BB_width",
                    "EMA_tendencia", "EMA_diferencia",
                    "TDI_rsi", "TDI_direccion", "TDI_fuerza",
                    "direccion",
                ]
                features = [float(feature_map.get(name, 0.0))
                            for name in base_order]

            if len(features) < expected_n:
                features.extend([0.0] * (expected_n - len(features)))
            elif len(features) > expected_n:
                features = features[:expected_n]

            x = np.array(features, dtype=np.float32).reshape(1, -1)
            if scaler is not None:
                try:
                    if isinstance(
                            scaler, dict) and "mean" in scaler and "std" in scaler:
                        mean = np.array(
                            scaler["mean"], dtype=np.float32).reshape(
                            1, -1)
                        std = np.array(
                            scaler["std"], dtype=np.float32).reshape(
                            1, -1)
                        if mean.shape[1] == x.shape[1] and std.shape[1] == x.shape[1]:
                            x = (x - mean) / (std + 1e-8)
                    elif hasattr(scaler, "transform"):
                        x = scaler.transform(x)
                except Exception:
                    pass

            with torch.no_grad():
                modelo_nn.eval()
                entrada = torch.FloatTensor(x)
                salida = modelo_nn(entrada)
                return float(salida.item())
            return 0.5
        except Exception as e:
            try:
                logger.error(f"Error prediccion NN: {e}", exc_info=True)
            except Exception:
                logger.error(f"Error prediccion NN: {e}")
            return 0.5

    def _calibrar_probabilidad(self, prob: float) -> float:
        """Aplica calibracion de temperatura a la probabilidad"""
        try:
            # Temperature scaling para calibracion
            # Valores mas altos de temperatura -> probabilidades mas cercanas a 0.5
            # Valores mas bajos -> probabilidades mas extremas
            logit = math.log(prob / (1 - prob + 1e-10))
            logit_calibrado = logit / self.temperatura_calibracion
            prob_calibrada = 1 / (1 + math.exp(-logit_calibrado))
            return prob_calibrada
        except Exception as e:
            return prob

    def registrar_resultado(self, prediccion: dict, exitoso: bool):
        """Registra resultado de prediccion para ajustar calibracion"""
        self.predicciones_totales += 1
        if exitoso:
            self.predicciones_correctas += 1
        # Ajustar temperatura si precision baja
        if self.predicciones_totales >= 20:
            precision_actual = self.predicciones_correctas / self.predicciones_totales
            if precision_actual < 0.80:
                # Aumentar umbral de confianza
                self.umbral_confianza = min(0.90, self.umbral_confianza + 0.01)
            elif precision_actual > 0.88:
                # Reducir umbral (mas operaciones)
                self.umbral_confianza = max(
                    0.80, self.umbral_confianza - 0.005)
            logger.info(
                f"Precision actual: {
                    precision_actual:.1%}, Umbral: {
                    self.umbral_confianza:.1%}")

    def obtener_precision(self) -> float:
        """Retorna precision actual del predictor"""
        if self.predicciones_totales == 0:
            return 0.5
        return self.predicciones_correctas / self.predicciones_totales

# ========== ESTRATEGIA MARKET MAKER (CAPITULOS 1-10) ==========
# CAPITULO 14:
# ==================================================


class MarketMakerStrategy:
    """
    Implementacion completa del Metodo Market Maker para senales binarias de 5 minutos.
    Combina deteccion de ciclos, patrones de precio, indicadores tecnicos y
    alineacion de tendencia para lograr 85%+ de eficiencia.
    Basado en: https://www.tradingBinarysp.com/metodo-market-maker
    Capitulos 1-10: Ciclos, Stop Hunt, Patrones M/W, Indicadores, Sesiones.
    """

    def __init__(self):
        self.umbral_confianza_mm = 0.92
        self.historial_precios = {}
        self.ciclo_actual = {}
        self.sesion_actual = None
        self.ultimo_stop_hunt = {}
        self.patrones_detectados = []
        # Configuracion de EMAs para Market Maker
        self.ema_periodos = [5, 13, 50, 200]
        # ADR (Average Daily Range) por par
        self.adr_valores = {}
        # Pivots calculados
        self.pivots = {}
        # Estado del ciclo de 3 dias
        self.ciclo_3_dias = {
            'dia_actual': 1,
            'nivel_actual': 'I',
            'direccion_principal': None,
            'punto_reversal': None
        }
        logger.info("Estrategia Market Maker inicializada (Capitulos 1-10)")

    # ========== CAPITULO 1: IDENTIFICACION DEL MARKET MAKER ==========
    def detectar_manipulacion_mm(self, df: pd.DataFrame) -> dict:
        """
        Detecta senales de manipulacion del Market Maker:
        - Movimientos violentos contra la tendencia
        - Barridos de stops (stop hunts)
        - Acumulacion en rangos estrechos
        """
        try:
            if len(df) < 20:
                return {'manipulacion': False, 'tipo': None}
            # Calcular volatilidad normal vs actual
            atr = self._calcular_atr(df, 14)
            volatilidad_actual = abs(
                df['close'].iloc[-1] - df['close'].iloc[-2])
            volatilidad_promedio = atr.iloc[-1] if len(
                atr) > 0 else volatilidad_actual
            # Detectar movimiento anormal (>2x ATR = posible stop hunt)
            es_movimiento_anormal = volatilidad_actual > (
                volatilidad_promedio * 2)
            # Detectar reversal rapida (vela actual opuesta a anterior)
            reversal_rapida = False
            if len(df) >= 3:
                vela_anterior = df['close'].iloc[-2] - df['open'].iloc[-2]
                vela_actual = df['close'].iloc[-1] - df['open'].iloc[-1]
                reversal_rapida = (
                    vela_anterior * vela_actual) < 0 and abs(vela_actual) > abs(vela_anterior) * 0.5
            # Detectar acumulacion (rango estrecho)
            rango_ultimas = df['high'].iloc[-5:].max() - \
                df['low'].iloc[-5:].min()
            es_acumulacion = rango_ultimas < (volatilidad_promedio * 3)
            tipo_manipulacion = None
            if es_movimiento_anormal and reversal_rapida:
                tipo_manipulacion = 'STOP_HUNT'
            elif es_acumulacion:
                tipo_manipulacion = 'ACUMULACION'
            elif es_movimiento_anormal:
                tipo_manipulacion = 'MOVIMIENTO_INSTITUCIONAL'
            return {
                'manipulacion': tipo_manipulacion is not None,
                'tipo': tipo_manipulacion,
                'volatilidad_ratio': volatilidad_actual / volatilidad_promedio if volatilidad_promedio > 0 else 1,
                'reversal_rapida': reversal_rapida
            }
        except Exception as e:
            logger.error(f"Error detectando manipulacion MM: {e}")
            return {'manipulacion': False, 'tipo': None}

    # ========== CAPITULO 2: CICLO DE 3 DIAS ==========
    def analizar_ciclo_3_dias(
            self, df_diario: pd.DataFrame, simbolo: str) -> dict:
        """
        Analiza el ciclo de 3 dias del Market Maker:
        - Dia 1 (Nivel I): Movimiento inicial desde punto de reversal
        - Dia 2 (Nivel II): Continuacion con menor agresividad
        - Dia 3 (Nivel III): Movimiento final, saturacion y senal de reversal
        """
        try:
            if len(df_diario) < 5:
                return {'nivel': 'I', 'fase': 'indefinida', 'direccion': None}
            # Obtener ultimos 5 dias
            ultimos_dias = df_diario.tail(5)
            # Calcular movimientos diarios
            movimientos = []
            for i in range(1, len(ultimos_dias)):
                mov = ultimos_dias['close'].iloc[i] - \
                    ultimos_dias['close'].iloc[i - 1]
                movimientos.append(mov)
            if len(movimientos) < 3:
                return {'nivel': 'I', 'fase': 'indefinida', 'direccion': None}
            # Determinar direccion principal (ultimos 3 dias)
            suma_movimientos = sum(movimientos[-3:])
            direccion = 'ALCISTA' if suma_movimientos > 0 else 'BAJISTA'
            # Analizar patron de intensidad
            intensidades = [abs(m) for m in movimientos[-3:]]
            # Nivel I: Mayor movimiento al inicio
            # Nivel II: Movimiento moderado
            # Nivel III: Movimiento final (puede ser menor o explosion)
            if len(intensidades) >= 3:
                if intensidades[0] > intensidades[1] > intensidades[2]:
                    nivel = 'III'  # Desacelerando - fin del ciclo
                    fase = 'SATURACION'
                elif intensidades[1] > intensidades[0] and intensidades[1] > intensidades[2]:
                    nivel = 'II'  # Pico en el medio
                    fase = 'CONTINUACION'
                elif intensidades[2] > intensidades[1]:
                    nivel = 'I'  # Acelerando - inicio del ciclo
                    fase = 'INICIO'
                else:
                    nivel = 'II'
                    fase = 'TRANSICION'
            else:
                nivel = 'I'
                fase = 'INDEFINIDA'
            # Detectar posible reversal en Nivel III
            senal_reversal = False
            if nivel == 'III':
                # Buscar divergencia o agotamiento
                if len(movimientos) >= 2:
                    ultimo_mov = movimientos[-1]
                    penultimo_mov = movimientos[-2]
                    # Si el ultimo movimiento es opuesto o muy pequeno
                    if (ultimo_mov * penultimo_mov <
                            0) or (abs(ultimo_mov) < abs(penultimo_mov) * 0.3):
                        senal_reversal = True
            resultado = {
                'nivel': nivel,
                'fase': fase,
                'direccion': direccion,
                'intensidad_actual': intensidades[-1] if intensidades else 0,
                'senal_reversal': senal_reversal,
                'recomendacion': self._obtener_recomendacion_ciclo(nivel, direccion, senal_reversal)
            }
            self.ciclo_3_dias[simbolo] = resultado
            return resultado
        except Exception as e:
            logger.error(f"Error analizando ciclo 3 dias: {e}")
            return {'nivel': 'I', 'fase': 'indefinida', 'direccion': None}

    def _obtener_recomendacion_ciclo(
            self, nivel: str, direccion: str, senal_reversal: bool) -> str:
        """Genera recomendacion basada en el ciclo"""
        if senal_reversal:
            return 'PUT' if direccion == 'ALCISTA' else 'CALL'
        elif nivel == 'I':
            return 'CALL' if direccion == 'ALCISTA' else 'PUT'
        elif nivel == 'II':
            return 'CALL' if direccion == 'ALCISTA' else 'PUT'
        else:  # Nivel III
            return 'ESPERAR'  # Riesgo alto de reversal

    # ========== CAPITULO 2B: CICLO INTRADIA ==========
    def analizar_ciclo_intradia(self, df: pd.DataFrame, simbolo: str) -> dict:
        """
        Analiza el ciclo intradia:
        - Fase de Acumulacion (Asia): Movimiento lateral, rango estrecho
        - Stop Hunt (Londres): Movimiento agresivo hacia HOD/LOD
        - Tendencia Verdadera (NY): Movimiento real en direccion opuesta al Stop Hunt
        """
        try:
            hora_actual = datetime.now().hour
            # Determinar sesion actual (horas UTC)
            if 0 <= hora_actual < 8:
                sesion = 'ASIA'
                fase_esperada = 'ACUMULACION'
            elif 8 <= hora_actual < 13:
                sesion = 'LONDRES'
                fase_esperada = 'STOP_HUNT'
            elif 13 <= hora_actual < 21:
                sesion = 'NEW_YORK'
                fase_esperada = 'T_V'
            else:
                sesion = 'ASIA'
                fase_esperada = 'ACUMULACION'
            self.sesion_actual = sesion
            # Calcular HOD/LOD usando ultimas velas (no depende de DatetimeIndex)
            # Para velas de 5 min, usamos las ultimas 48 velas (~4 horas de
            # datos)
            velas_por_sesion = min(48, len(df))
            df_hoy = df.tail(velas_por_sesion)
            hod = df_hoy['high'].max()  # High of Day
            lod = df_hoy['low'].min()   # Low of Day
            precio_actual = df['close'].iloc[-1]
            # Detectar si estamos cerca de HOD/LOD (zona de stop hunt)
            rango_dia = hod - lod
            distancia_hod = abs(precio_actual - hod)
            distancia_lod = abs(precio_actual - lod)
            cerca_extremo = min(
                distancia_hod,
                distancia_lod) < (
                rango_dia *
                0.1)
            en_hod = distancia_hod < distancia_lod
            # Detectar stop hunt (movimiento agresivo hacia extremo seguido de
            # rechazo)
            stop_hunt_detectado = False
            direccion_stop_hunt = None
            if len(df) >= 10:
                # Buscar spike reciente hacia HOD/LOD con rechazo
                ultimas_10 = df.tail(10)
                max_reciente = ultimas_10['high'].max()
                min_reciente = ultimas_10['low'].min()
                # Si tocamos HOD en las ultimas velas pero cerramos lejos
                if max_reciente >= hod * \
                        0.999 and precio_actual < hod - (rango_dia * 0.05):
                    stop_hunt_detectado = True
                    direccion_stop_hunt = 'ARRIBA'
                # Si tocamos LOD pero cerramos arriba
                elif min_reciente <= lod * 1.001 and precio_actual > lod + (rango_dia * 0.05):
                    stop_hunt_detectado = True
                    direccion_stop_hunt = 'ABAJO'
            # Calcular fuerza de la tendencia actual
            ema_rapida = _ema_series(df['close'], 13)
            ema_lenta = _ema_series(df['close'], 50)
            tendencia = 'ALCISTA' if ema_rapida.iloc[-1] > ema_lenta.iloc[-1] else 'BAJISTA'
            resultado = {
                'sesion': sesion,
                'fase_esperada': fase_esperada,
                'hod': hod,
                'lod': lod,
                'cerca_extremo': cerca_extremo,
                'en_hod': en_hod,
                'stop_hunt_detectado': stop_hunt_detectado,
                'direccion_stop_hunt': direccion_stop_hunt,
                'tendencia_intradia': tendencia,
                'rango_dia_pips': rango_dia * 10000,  # Convertir a pips
                'recomendacion': self._obtener_recomendacion_intradia(
                    sesion, stop_hunt_detectado, direccion_stop_hunt, tendencia
                )
            }
            if stop_hunt_detectado:
                self.ultimo_stop_hunt[simbolo] = {
                    'timestamp': datetime.now(),
                    'direccion': direccion_stop_hunt,
                    'precio': precio_actual
                }
            return resultado
        except Exception as e:
            logger.error(f"Error analizando ciclo intradia: {e}")
            return {'sesion': 'UNKNOWN', 'fase_esperada': 'UNKNOWN'}

    def _obtener_recomendacion_intradia(self, sesion: str, stop_hunt: bool,
                                        dir_stop_hunt: str, tendencia: str) -> str:
        """Genera recomendacion basada en ciclo intradia"""
        if sesion == 'ASIA':
            return 'ESPERAR'  # No operar en acumulacion
        elif stop_hunt:
            # Operar en contra del stop hunt (tendencia verdadera)
            if dir_stop_hunt == 'ARRIBA':
                return 'PUT'
            else:
                return 'CALL'
        elif sesion == 'NEW_YORK':
            return 'CALL' if tendencia == 'ALCISTA' else 'PUT'
        else:
            return 'ESPERAR'

    # ========== CAPITULO 3-4: PATRONES M/W Y HALF BATMAN ==========
    def detectar_patron_mw(self, df: pd.DataFrame) -> dict:
        """
        Detecta patrones M (doble techo) y W (doble suelo).
        Estos patrones indican reversiones tras manipulacion del MM.
        """
        try:
            if len(df) < 20:
                return {'patron': None, 'confianza': 0}
            precios = df['close'].values
            highs = df['high'].values
            lows = df['low'].values
            # Buscar patron M (doble techo)
            patron_m = self._buscar_doble_techo(highs, precios)
            # Buscar patron W (doble suelo)
            patron_w = self._buscar_doble_suelo(lows, precios)
            # Determinar cual es mas fuerte
            if patron_m['detectado'] and patron_w['detectado']:
                if patron_m['confianza'] > patron_w['confianza']:
                    return {'patron': 'M', 'direccion': 'PUT', **patron_m}
                else:
                    return {'patron': 'W', 'direccion': 'CALL', **patron_w}
            elif patron_m['detectado']:
                return {'patron': 'M', 'direccion': 'PUT', **patron_m}
            elif patron_w['detectado']:
                return {'patron': 'W', 'direccion': 'CALL', **patron_w}
            else:
                return {'patron': None, 'confianza': 0}
        except Exception as e:
            logger.error(f"Error detectando patron M/W: {e}")
            return {'patron': None, 'confianza': 0}

    def _buscar_doble_techo(self, highs: np.ndarray,
                            closes: np.ndarray) -> dict:
        """Busca patron de doble techo (M) con validación mejorada"""
        try:
            n = len(highs)
            if n < 20:
                return {'detectado': False, 'confianza': 0}

            # Buscar picos en ventana reciente
            ventana = min(30, n)
            highs_ventana = highs[-ventana:]

            # Encontrar maximos locales (order=3 para filtrar ruido)
            from scipy.signal import argrelmax
            maximos = argrelmax(highs_ventana, order=3)[0]

            if len(maximos) >= 2:
                # Analizar los dos últimos picos significativos
                idx_p2 = maximos[-1]
                idx_p1 = maximos[-2]

                p2 = highs_ventana[idx_p2]
                p1 = highs_ventana[idx_p1]

                # 1. Similitud de altura (tolerancia 0.2%)
                diferencia_altura = abs(p2 - p1) / p1
                if diferencia_altura > 0.002:
                    return {'detectado': False, 'confianza': 0}

                # 2. Separación mínima (al menos 5 velas)
                separacion = idx_p2 - idx_p1
                if separacion < 5:
                    return {'detectado': False, 'confianza': 0}

                # 3. Valle intermedio (Neckline)
                valle_idx_rel = np.argmin(
                    highs_ventana[idx_p1:idx_p2]) + idx_p1
                neckline = highs_ventana[valle_idx_rel]

                # Profundidad del valle (debe haber retroceso)
                profundidad = (p1 - neckline) / p1
                if profundidad < 0.0005:  # Muy plano
                    return {'detectado': False, 'confianza': 0}

                # 4. Precio actual rompiendo neckline o cerca
                precio_actual = closes[-1]

                # Calcular confianza
                score = 0.0
                score += (1.0 - diferencia_altura * 100) * \
                    0.4  # Altura similar
                score += min(1.0, separacion / 20.0) * \
                    0.3     # Separación adecuada
                score += min(1.0, profundidad * 1000) * \
                    0.3    # Profundidad clara

                # Si precio actual está bajo el neckline, es ruptura confirmada
                if precio_actual < neckline:
                    score += 0.2

                return {
                    'detectado': True,
                    'confianza': min(0.98, max(0.6, score)),
                    'nivel_resistencia': max(p1, p2),
                    'neckline': neckline
                }

            return {'detectado': False, 'confianza': 0}
        except Exception as e:
            logger.error(f"Error en doble techo: {e}")
            return {'detectado': False, 'confianza': 0}

    def _buscar_doble_suelo(self, lows: np.ndarray,
                            closes: np.ndarray) -> dict:
        """Busca patron de doble suelo (W) con validación mejorada"""
        try:
            n = len(lows)
            if n < 20:
                return {'detectado': False, 'confianza': 0}

            ventana = min(30, n)
            lows_ventana = lows[-ventana:]

            from scipy.signal import argrelmin
            minimos = argrelmin(lows_ventana, order=3)[0]

            if len(minimos) >= 2:
                idx_v2 = minimos[-1]
                idx_v1 = minimos[-2]

                v2 = lows_ventana[idx_v2]
                v1 = lows_ventana[idx_v1]

                # 1. Similitud
                diferencia_altura = abs(v2 - v1) / abs(v1)
                if diferencia_altura > 0.002:
                    return {'detectado': False, 'confianza': 0}

                # 2. Separación
                separacion = idx_v2 - idx_v1
                if separacion < 5:
                    return {'detectado': False, 'confianza': 0}

                # 3. Pico intermedio (Neckline)
                pico_idx_rel = np.argmax(lows_ventana[idx_v1:idx_v2]) + idx_v1
                neckline = lows_ventana[pico_idx_rel]

                # Altura del pico
                altura = (neckline - v1) / abs(v1)
                if altura < 0.0005:
                    return {'detectado': False, 'confianza': 0}

                # 4. Confianza
                score = 0.0
                score += (1.0 - diferencia_altura * 100) * 0.4
                score += min(1.0, separacion / 20.0) * 0.3
                score += min(1.0, altura * 1000) * 0.3

                precio_actual = closes[-1]
                if precio_actual > neckline:
                    score += 0.2

                return {
                    'detectado': True,
                    'confianza': min(0.98, max(0.6, score)),
                    'nivel_soporte': min(v1, v2),
                    'neckline': neckline
                }

            return {'detectado': False, 'confianza': 0}
        except Exception as e:
            logger.error(f"Error en doble suelo: {e}")
            return {'detectado': False, 'confianza': 0}

    def detectar_half_batman(self, df: pd.DataFrame) -> dict:
        """
        Detecta patron Half Batman: version abreviada del M/W.
        Ocurre cuando ya hay suficientes traders atrapados.
        """
        try:
            if len(df) < 10:
                return {'patron': None, 'confianza': 0}
            ultimas = df.tail(10)
            # Half Batman alcista: caida rapida seguida de recuperacion parcial
            caida_inicial = ultimas['close'].iloc[0] - ultimas['low'].min()
            recuperacion = ultimas['close'].iloc[-1] - ultimas['low'].min()
            if caida_inicial > 0:
                ratio_recuperacion = recuperacion / caida_inicial
                # Half Batman si recuperamos 50-80% de la caida
                if 0.5 <= ratio_recuperacion <= 0.8:
                    return {
                        'patron': 'HALF_BATMAN_ALCISTA',
                        'direccion': 'CALL',
                        'confianza': 0.7 + (ratio_recuperacion - 0.5) * 0.3
                    }
            # Half Batman bajista: subida rapida seguida de retroceso parcial
            subida_inicial = ultimas['high'].max() - ultimas['close'].iloc[0]
            retroceso = ultimas['high'].max() - ultimas['close'].iloc[-1]
            if subida_inicial > 0:
                ratio_retroceso = retroceso / subida_inicial
                if 0.5 <= ratio_retroceso <= 0.8:
                    return {
                        'patron': 'HALF_BATMAN_BAJISTA',
                        'direccion': 'PUT',
                        'confianza': 0.7 + (ratio_retroceso - 0.5) * 0.3
                    }
            return {'patron': None, 'confianza': 0}
        except Exception as e:
            return {'patron': None, 'confianza': 0}

    def detectar_rrt(self, df: pd.DataFrame) -> dict:
        """
        Detecta patron RRT (Railroad Tracks):
        Dos velas consecutivas de cuerpo grande y direcciones opuestas.
        Indica reversal comprimida en tiempo.
        """
        try:
            if len(df) < 3:
                return {'patron': None, 'confianza': 0}
            ultimas = df.tail(3)
            # Calcular cuerpos de las ultimas 2 velas
            cuerpo_penultima = ultimas['close'].iloc[-2] - \
                ultimas['open'].iloc[-2]
            cuerpo_ultima = ultimas['close'].iloc[-1] - \
                ultimas['open'].iloc[-1]
            # Calcular tamaño promedio de cuerpos
            cuerpos_historicos = abs(df['close'] - df['open']).mean()
            # RRT: dos velas opuestas con cuerpos grandes (>1.5x promedio)
            es_grande_penultima = abs(
                cuerpo_penultima) > cuerpos_historicos * 1.5
            es_grande_ultima = abs(cuerpo_ultima) > cuerpos_historicos * 1.5
            son_opuestas = cuerpo_penultima * cuerpo_ultima < 0
            if es_grande_penultima and es_grande_ultima and son_opuestas:
                # La direccion del RRT es la de la ultima vela
                if cuerpo_ultima > 0:
                    return {
                        'patron': 'RRT',
                        'direccion': 'CALL',
                        'confianza': 0.75,
                        'fuerza': abs(cuerpo_ultima) / cuerpos_historicos
                    }
                else:
                    return {
                        'patron': 'RRT',
                        'direccion': 'PUT',
                        'confianza': 0.75,
                        'fuerza': abs(cuerpo_ultima) / cuerpos_historicos
                    }
            return {'patron': None, 'confianza': 0}
        except Exception as e:
            return {'patron': None, 'confianza': 0}

    # ========== CAPITULO 5: ADR Y PIVOTS ==========
    def calcular_adr(self, df_diario: pd.DataFrame,
                     periodos: int = 14) -> float:
        """
        Calcula el ADR (Average Daily Range).
        Util para anticipar rangos de movimiento y detectar saturacion.
        """
        try:
            if len(df_diario) < periodos:
                return 0
            rangos_diarios = df_diario['high'].tail(
                periodos) - df_diario['low'].tail(periodos)
            adr = rangos_diarios.mean()
            return adr
        except Exception as e:
            return 0

    def calcular_pivots(self, df: pd.DataFrame) -> dict:
        """
        Calcula niveles de pivot (PP, R1-R4, S1-S4).
        Zonas clave de reaccion institucional.
        """
        try:
            if len(df) < 2:
                return {}
            # Usar datos del dia anterior
            high = df['high'].iloc[-2]
            low = df['low'].iloc[-2]
            close = df['close'].iloc[-2]
            # Pivot Point clasico
            pp = (high + low + close) / 3
            # Resistencias
            r1 = (2 * pp) - low
            r2 = pp + (high - low)
            r3 = high + 2 * (pp - low)
            r4 = r3 + (high - low)
            # Soportes
            s1 = (2 * pp) - high
            s2 = pp - (high - low)
            s3 = low - 2 * (high - pp)
            s4 = s3 - (high - low)
            # Niveles M (Camarilla)
            m1 = (pp + s1) / 2
            m2 = (pp + r1) / 2
            m3 = (r1 + r2) / 2
            m4 = (s1 + s2) / 2
            return {
                'PP': pp,
                'R1': r1, 'R2': r2, 'R3': r3, 'R4': r4,
                'S1': s1, 'S2': s2, 'S3': s3, 'S4': s4,
                'M1': m1, 'M2': m2, 'M3': m3, 'M4': m4
            }
        except Exception as e:
            return {}

    def analizar_posicion_vs_pivots(self, precio: float, pivots: dict) -> dict:
        """Analiza posicion del precio respecto a pivots"""
        try:
            if not pivots:
                return {'zona': 'NEUTRAL', 'cercano_a': None}
            pp = pivots.get('PP', precio)
            # Determinar zona
            if precio > pivots.get('R2', precio):
                zona = 'SOBRECOMPRA_EXTREMA'
            elif precio > pivots.get('R1', precio):
                zona = 'SOBRECOMPRA'
            elif precio > pp:
                zona = 'ALCISTA'
            elif precio > pivots.get('S1', precio):
                zona = 'BAJISTA'
            elif precio > pivots.get('S2', precio):
                zona = 'SOBREVENTA'
            else:
                zona = 'SOBREVENTA_EXTREMA'
            # Encontrar nivel mas cercano
            niveles = [(k, v) for k, v in pivots.items()]
            cercano = min(niveles, key=lambda x: abs(x[1] - precio))
            return {
                'zona': zona,
                'cercano_a': cercano[0],
                'distancia_pips': abs(cercano[1] - precio) * 10000
            }
        except Exception as e:
            return {'zona': 'NEUTRAL', 'cercano_a': None}

    # ========== CAPITULO 6: INDICADORES COMPLEMENTARIOS ==========
    def calcular_emas_mm(self, df: pd.DataFrame) -> dict:
        """
        Calcula EMAs del sistema Market Maker: 5, 13, 50, 200
        """
        try:
            emas = {}
            for periodo in self.ema_periodos:
                if len(df) >= periodo:
                    emas[f'EMA_{periodo}'] = _ema_series(
                        df['close'], periodo).iloc[-1]
                else:
                    emas[f'EMA_{periodo}'] = df['close'].iloc[-1]
            # Analizar cruces
            cruces = {
                'cruce_5_13': emas.get('EMA_5', 0) > emas.get('EMA_13', 0),
                'cruce_13_50': emas.get('EMA_13', 0) > emas.get('EMA_50', 0),
                'cruce_50_200': emas.get('EMA_50', 0) > emas.get('EMA_200', 0)
            }
            # Tendencia general
            alcistas = sum(cruces.values())
            if alcistas >= 3:
                tendencia = 'F_A'
            elif alcistas == 2:
                tendencia = 'ALCISTA'
            elif alcistas == 1:
                tendencia = 'BAJISTA'
            else:
                tendencia = 'F_B'
            return {
                **emas,
                **cruces,
                'tendencia_emas': tendencia
            }
        except Exception as e:
            return {}

    def calcular_tdi(self, df: pd.DataFrame, periodo_rsi: int = 13) -> dict:
        """
        Calcula el TDI (Traders Dynamic Index).
        Combina RSI + media movil + bandas de volatilidad.
        El patron "Shark Fin" indica reversal.
        """
        try:
            if len(df) < periodo_rsi + 10:
                return {}
            # Calcular RSI
            delta = df['close'].diff()
            gain = (
                delta.where(
                    delta > 0,
                    0)).rolling(
                window=periodo_rsi).mean()
            loss = (-delta.where(delta < 0, 0)
                    ).rolling(window=periodo_rsi).mean()
            rs = gain / loss
            rsi = 100 - (100 / (1 + rs))
            # Linea de precio (media del RSI)
            linea_precio = rsi.rolling(window=2).mean()
            # Linea de senal (media mas lenta)
            linea_senal = rsi.rolling(window=7).mean()
            # Bandas de volatilidad
            banda_superior = rsi.rolling(window=34).mean(
            ) + rsi.rolling(window=34).std() * 1.618
            banda_inferior = rsi.rolling(window=34).mean(
            ) - rsi.rolling(window=34).std() * 1.618
            # Detectar Shark Fin (cruce de linea precio sobre senal en
            # extremos)
            shark_fin = False
            direccion_shark = None
            rsi_actual = rsi.iloc[-1]
            precio_actual = linea_precio.iloc[-1]
            senal_actual = linea_senal.iloc[-1]
            precio_anterior = linea_precio.iloc[-2] if len(
                linea_precio) > 1 else precio_actual
            senal_anterior = linea_senal.iloc[-2] if len(
                linea_senal) > 1 else senal_actual
            # Cruce alcista en sobreventa
            if precio_anterior < senal_anterior and precio_actual > senal_actual and rsi_actual < 32:
                shark_fin = True
                direccion_shark = 'CALL'
            # Cruce bajista en sobrecompra
            elif precio_anterior > senal_anterior and precio_actual < senal_actual and rsi_actual > 68:
                shark_fin = True
                direccion_shark = 'PUT'
            return {
                'rsi': rsi_actual,
                'linea_precio': precio_actual,
                'linea_senal': senal_actual,
                'banda_superior': banda_superior.iloc[-1],
                'banda_inferior': banda_inferior.iloc[-1],
                'shark_fin': shark_fin,
                'direccion_shark': direccion_shark
            }
        except Exception as e:
            return {}

    # ========== METODO PRINCIPAL: GENERAR SENAL MARKET MAKER ==========
    def generar_senal_mm(self, df: pd.DataFrame, df_diario: pd.DataFrame = None,
                         simbolo: str = 'EURUSD') -> dict:
        """
        Genera senal de trading combinando todos los elementos del Metodo Market Maker.
        Objetivo: 85%+ de precision en senales de 5 minutos.
        """
        try:
            if len(df) < 50:
                return {'senal': 'ESPERAR', 'confianza': 0,
                        'razon': 'Datos insuficientes'}
            # 1. Analisis de manipulacion MM
            manipulacion = self.detectar_manipulacion_mm(df)
            # 2. Ciclo intradia
            ciclo_intradia = self.analizar_ciclo_intradia(df, simbolo)
            # 3. Patrones de precio
            patron_mw = self.detectar_patron_mw(df)
            patron_hb = self.detectar_half_batman(df)
            patron_rrt = self.detectar_rrt(df)
            # 4. Indicadores EMAs
            emas = self.calcular_emas_mm(df)
            # 5. TDI
            tdi = self.calcular_tdi(df)
            # 6. Pivots
            pivots = self.calcular_pivots(df)
            precio_actual = df['close'].iloc[-1]
            pos_pivots = self.analizar_posicion_vs_pivots(
                precio_actual, pivots)
            # 7. Ciclo de 3 dias (si hay datos diarios)
            ciclo_3d = None
            if df_diario is not None and len(df_diario) >= 5:
                ciclo_3d = self.analizar_ciclo_3_dias(df_diario, simbolo)
            # ========== LOGICA DE DECISION ==========
            votos_call = 0
            votos_put = 0
            confianzas = []
            razones = []
            # Voto 1: Stop Hunt detectado (peso alto)
            if ciclo_intradia.get('stop_hunt_detectado'):
                if ciclo_intradia.get('direccion_stop_hunt') == 'ARRIBA':
                    votos_put += 2
                    razones.append('Stop Hunt Arriba -> PUT')
                else:
                    votos_call += 2
                    razones.append('Stop Hunt Abajo -> CALL')
                confianzas.append(0.92)
            # Voto 2: Patron M/W (peso alto)
            if patron_mw.get('patron'):
                if patron_mw['direccion'] == 'CALL':
                    votos_call += 2
                else:
                    votos_put += 2
                razones.append(
                    f"Patron {patron_mw['patron']} -> {patron_mw['direccion']}")
                confianzas.append(patron_mw.get('confianza', 0.7))
            # Voto 3: RRT (peso medio-alto)
            if patron_rrt.get('patron'):
                if patron_rrt['direccion'] == 'CALL':
                    votos_call += 1.5
                else:
                    votos_put += 1.5
                razones.append(f"RRT -> {patron_rrt['direccion']}")
                confianzas.append(patron_rrt.get('confianza', 0.75))
            # Voto 4: Half Batman (peso medio)
            if patron_hb.get('patron'):
                if patron_hb['direccion'] == 'CALL':
                    votos_call += 1
                else:
                    votos_put += 1
                razones.append(f"Half Batman -> {patron_hb['direccion']}")
                confianzas.append(patron_hb.get('confianza', 0.7))
            # Voto 5: TDI Shark Fin (peso alto)
            if tdi.get('shark_fin'):
                if tdi['direccion_shark'] == 'CALL':
                    votos_call += 2
                else:
                    votos_put += 2
                razones.append(f"TDI Shark Fin -> {tdi['direccion_shark']}")
                confianzas.append(0.80)
            # Voto 6: Tendencia EMAs (peso medio)
            tendencia_emas = emas.get('tendencia_emas', '')
            if 'ALCISTA' in tendencia_emas:
                votos_call += 1
                razones.append(f"EMAs {tendencia_emas}")
            elif 'BAJISTA' in tendencia_emas:
                votos_put += 1
                razones.append(f"EMAs {tendencia_emas}")
            # Voto 7: Sesion optima (filtro)
            sesion = ciclo_intradia.get('sesion', 'UNKNOWN')
            if sesion == 'ASIA':
                # Reducir confianza en Asia
                votos_call *= 0.5
                votos_put *= 0.5
                razones.append('Sesion Asia - Riesgo')
            # Voto 8: Ciclo 3 dias (si disponible)
            if ciclo_3d:
                rec_3d = ciclo_3d.get('recomendacion', 'ESPERAR')
                if rec_3d == 'CALL':
                    votos_call += 1
                    razones.append('Ciclo 3D -> CALL')
                elif rec_3d == 'PUT':
                    votos_put += 1
                    razones.append('Ciclo 3D -> PUT')
            # ========== CALCULAR SENAL FINAL ==========
            total_votos = votos_call + votos_put
            if total_votos == 0:
                return {
                    'senal': 'ESPERAR',
                    'confianza': 0,
                    'razon': 'Sin senales claras',
                    'detalles': {
                        'manipulacion': manipulacion,
                        'ciclo_intradia': ciclo_intradia,
                        'emas': emas
                    }
                }
            # Determinar direccion
            if votos_call > votos_put:
                senal = 'CALL'
                ratio = votos_call / total_votos
            else:
                senal = 'PUT'
                ratio = votos_put / total_votos
            # Calcular confianza final
            if confianzas:
                confianza_promedio = sum(confianzas) / len(confianzas)
                confianza_final = confianza_promedio * ratio
            else:
                confianza_final = ratio * 0.6
            # Ajustar por fuerza de alineacion
            if ratio > 0.8:  # Fuerte alineacion
                confianza_final = min(0.98, confianza_final * 1.1)
            elif ratio < 0.6:  # Alineacion debil
                confianza_final *= 0.8
            # Verificar umbral minimo
            operar = confianza_final >= self.umbral_confianza_mm
            return {
                'senal': senal if operar else 'ESPERAR',
                'direccion_sugerida': senal,
                'confianza': confianza_final,
                'operar': operar,
                'razones': razones,
                'votos': {'CALL': votos_call, 'PUT': votos_put},
                'detalles': {
                    'manipulacion': manipulacion,
                    'ciclo_intradia': ciclo_intradia,
                    'patron_mw': patron_mw,
                    'patron_rrt': patron_rrt,
                    'tdi': tdi,
                    'emas': emas,
                    'pivots': pos_pivots,
                    'sesion': sesion
                }
            }
        except Exception as e:
            logger.error(f"Error generando senal MM: {e}")
            return {'senal': 'ESPERAR', 'confianza': 0, 'razon': str(e)}

    # ========== UTILIDADES ==========
    def _calcular_atr(self, df: pd.DataFrame, periodo: int = 14) -> pd.Series:
        """Calcula el ATR (Average True Range) con suavizado de Wilder"""
        try:
            return _atr_series(df['high'], df['low'], df['close'], periodo)
        except Exception as e:
            logger.error(f"Error calculando ATR: {e}")
            return pd.Series([0.0] * len(df), index=df.index)

# ========== ESTRATEGIA MULTI-TIMEFRAME CON EMA 21/50 + TDI + IA ==========
# CAPITULO 15:
# ==================================================


class EstrategiaMultiTimeframe:
    """
    Estrategia avanzada que combina:
    - EMAs 21 y 50 para determinar tendencia a corto plazo
    - TDI (Traders Dynamic Index) para momentum y reversiones
    - Acción del precio y estructura de mercado
    - Ciclo de mercado (sesiones)
    - Figuras de velas y patrones
    - Predicciones de IA con historial
    - Análisis multi-timeframe: 1m + 5m (optimizado para precisión)
    Objetivo: 85%+ de precisión en operaciones binarias de 5 minutos
    Alineación: Solo opera cuando 1m y 5m están de acuerdo
    """

    def __init__(self, config, predictor_ia=None, repositorio_trades=None):
        self.config = config
        self.predictor_ia = predictor_ia
        self.repositorio = repositorio_trades
        # Timeframes para análisis (en minutos) - SOLO 1m+5m para mejor
        # precisión
        self.timeframes = [1, 5]
        # Pesos para cada componente de la estrategia (SIN MACD NI ESTOCASTICO)
        # BALANCEADO: 50% IA + 50% Análisis Técnico
        self.pesos = {
            'ema_tendencia': 0.25,      # EMAs 21/50 determinan tendencia
            'tdi_momentum': 0.15,        # TDI para momentum y reversiones
            # Estructura de precio (AUMENTADO - clave para IA)
            'accion_precio': 0.30,
            'ciclo_mercado': 0.10,       # Sesión y hora óptima
            'patrones_vela': 0.20,       # Patrones de velas japonesas
            'prediccion_ia': 0.50        # IA con historial (50% del total)
            # NOTA: MACD y Estocástico removidos - se usa acción del precio
        }
        # Configuración de EMAs
        self.ema_rapida = 21
        self.ema_lenta = 50
        # Umbral mínimo de confianza para operar
        self.umbral_confianza = 0.92
        # Patrones de velas reconocidos
        self.patrones_alcistas = [
            'hammer', 'inverted_hammer', 'bullish_engulfing',
            'morning_star', 'three_white_soldiers', 'piercing_line'
        ]
        self.patrones_bajistas = [
            'hanging_man', 'shooting_star', 'bearish_engulfing',
            'evening_star', 'three_black_crows', 'dark_cloud_cover'
        ]

    def analizar_timeframe(self, df: pd.DataFrame, timeframe: int) -> dict:
        """
        Analiza un timeframe específico y retorna señales individuales.
        Args:
            df: DataFrame con datos OHLCV
            timeframe: Timeframe en minutos (5, 15, 30)
        Returns:
            dict con análisis del timeframe
        """
        try:
            if len(df) < 60:
                return {'valido': False, 'razon': 'Datos insuficientes'}
            resultado = {
                'valido': True,
                'timeframe': timeframe,
                'señales': {},
                'votos_call': 0,
                'votos_put': 0,
                'confianza': 0
            }
            # 1. ANÁLISIS EMA 21/50 - Tendencia a corto plazo
            ema_analisis = self._analizar_emas(df)
            resultado['señales']['ema'] = ema_analisis
            if ema_analisis['tendencia'] == 'ALCISTA':
                resultado['votos_call'] += ema_analisis['fuerza']
            elif ema_analisis['tendencia'] == 'BAJISTA':
                resultado['votos_put'] += ema_analisis['fuerza']
            # 2. ANÁLISIS TDI - Momentum y reversiones
            tdi_analisis = self._analizar_tdi(df)
            resultado['señales']['tdi'] = tdi_analisis
            if tdi_analisis['señal'] == 'CALL':
                resultado['votos_call'] += tdi_analisis['fuerza']
            elif tdi_analisis['señal'] == 'PUT':
                resultado['votos_put'] += tdi_analisis['fuerza']
            # 3. ACCIÓN DEL PRECIO - Estructura de mercado
            precio_analisis = self._analizar_accion_precio(df)
            resultado['señales']['precio'] = precio_analisis
            if precio_analisis['direccion'] == 'CALL':
                resultado['votos_call'] += precio_analisis['fuerza']
            elif precio_analisis['direccion'] == 'PUT':
                resultado['votos_put'] += precio_analisis['fuerza']
            # 4. PATRONES DE VELAS
            patrones_analisis = self._detectar_patrones_velas(df)
            resultado['señales']['patrones'] = patrones_analisis
            if patrones_analisis['direccion'] == 'CALL':
                resultado['votos_call'] += patrones_analisis['fuerza']
            elif patrones_analisis['direccion'] == 'PUT':
                resultado['votos_put'] += patrones_analisis['fuerza']
            # 5. CICLO DE MERCADO
            ciclo_analisis = self._analizar_ciclo_mercado()
            resultado['señales']['ciclo'] = ciclo_analisis
            # El ciclo actúa como multiplicador
            if ciclo_analisis['sesion_optima']:
                resultado['votos_call'] *= 1.2
                resultado['votos_put'] *= 1.2
            else:
                resultado['votos_call'] *= 0.8
                resultado['votos_put'] *= 0.8
            return resultado
        except Exception as e:
            logger.error(f"Error analizando timeframe {timeframe}: {e}")
            return {'valido': False, 'razon': str(e)}

    def _analizar_emas(self, df: pd.DataFrame) -> dict:
        """
        Analiza EMAs 21 y 50 para determinar tendencia a corto plazo.
        Señales:
        - Cruce alcista: EMA21 cruza por encima de EMA50
        - Cruce bajista: EMA21 cruza por debajo de EMA50
        - Precio encima de ambas EMAs: Tendencia alcista fuerte
        - Precio debajo de ambas EMAs: Tendencia bajista fuerte
        """
        try:
            # Calcular EMAs
            df_calc = df.copy()
            df_calc['ema_21'] = _ema_series(df_calc['close'], 21)
            df_calc['ema_50'] = _ema_series(df_calc['close'], 50)
            df_calc['ema_200'] = _ema_series(df_calc['close'], 200)
            ultimo = df_calc.iloc[-1]
            anterior = df_calc.iloc[-2]
            ema21 = ultimo['ema_21']
            ema50 = ultimo['ema_50']
            ema200 = ultimo['ema_200']
            precio = ultimo['close']
            ema21_ant = anterior['ema_21']
            ema50_ant = anterior['ema_50']
            # Determinar tendencia
            if ema21 > ema50 and ema50 > ema200:
                tendencia = 'ALCISTA'
                if ema21_ant <= ema50_ant:  # Cruce reciente
                    fuerza = 2.5
                    cruce = 'C_A'
                elif precio > ema21:  # Precio encima de ambas
                    fuerza = 2.0
                    cruce = 'T_F'
                else:
                    fuerza = 1.5
                    cruce = 'T_N'
            elif ema21 < ema50 and ema50 < ema200:
                tendencia = 'BAJISTA'
                if ema21_ant >= ema50_ant:  # Cruce reciente
                    fuerza = 2.5
                    cruce = 'C_B'
                elif precio < ema21:  # Precio debajo de ambas
                    fuerza = 2.0
                    cruce = 'T_F'
                else:
                    fuerza = 1.5
                    cruce = 'T_N'
            else:
                tendencia = 'LATERAL'
                fuerza = 0.5
                cruce = 'SIN_CRUCE'
            # Calcular distancia del precio a las EMAs (normalizada por ATR)
            atr = self._calcular_atr(df_calc)
            if atr > 0:
                distancia_ema21 = (precio - ema21) / atr
                distancia_ema50 = (precio - ema50) / atr
                distancia_ema200 = (precio - ema200) / atr
            else:
                distancia_ema21 = 0
                distancia_ema50 = 0
                distancia_ema200 = 0
            return {
                'tendencia': tendencia,
                'cruce': cruce,
                'fuerza': fuerza,
                'ema_21': ema21,
                'ema_50': ema50,
                'ema_200': ema200,
                'precio': precio,
                'distancia_ema21': distancia_ema21,
                'distancia_ema50': distancia_ema50,
                'distancia_ema200': distancia_ema200,
                'alineacion': 'COMPLETA' if (precio > ema21 > ema50 > ema200 or precio < ema21 < ema50 < ema200) else 'PARCIAL'
            }
        except Exception as e:
            logger.error(f"Error en análisis EMA: {e}")
            return {'tendencia': 'LATERAL', 'fuerza': 0, 'cruce': 'ERROR'}

    def _analizar_tdi(self, df: pd.DataFrame, periodo_rsi: int = 13) -> dict:
        """
        Analiza el TDI (Traders Dynamic Index) para momentum y reversiones.
        Componentes:
        - RSI base (periodo 13)
        - Línea de precio (media del RSI)
        - Línea de señal (media más lenta)
        - Bandas de volatilidad
        - Shark Fin (patrón de reversión)
        """
        try:
            if len(df) < periodo_rsi + 15:
                return {'señal': 'NEUTRAL', 'fuerza': 0}
            # Calcular RSI
            delta = df['close'].diff()
            gain = (
                delta.where(
                    delta > 0,
                    0)).rolling(
                window=periodo_rsi).mean()
            loss = (-delta.where(delta < 0, 0)
                    ).rolling(window=periodo_rsi).mean()
            rs = gain / loss
            rsi = 100 - (100 / (1 + rs))
            # Líneas del TDI
            linea_precio = rsi.rolling(window=2).mean()
            linea_senal = rsi.rolling(window=7).mean()
            # Bandas de volatilidad
            banda_media = rsi.rolling(window=34).mean()
            banda_std = rsi.rolling(window=34).std()
            banda_superior = banda_media + banda_std * 1.618
            banda_inferior = banda_media - banda_std * 1.618
            # Valores actuales
            rsi_actual = rsi.iloc[-1]
            precio_actual = linea_precio.iloc[-1]
            senal_actual = linea_senal.iloc[-1]
            precio_anterior = linea_precio.iloc[-2]
            senal_anterior = linea_senal.iloc[-2]
            banda_sup = banda_superior.iloc[-1]
            banda_inf = banda_inferior.iloc[-1]
            # Detectar Shark Fin y señales
            señal = 'NEUTRAL'
            fuerza = 0
            shark_fin = False
            tipo_senal = 'NINGUNA'
            # Shark Fin Alcista: Cruce en sobreventa
            if precio_anterior < senal_anterior and precio_actual > senal_actual and rsi_actual < 35:
                señal = 'CALL'
                fuerza = 2.5
                shark_fin = True
                tipo_senal = 'SHARK_FIN_ALCISTA'
            # Shark Fin Bajista: Cruce en sobrecompra
            elif precio_anterior > senal_anterior and precio_actual < senal_actual and rsi_actual > 65:
                señal = 'PUT'
                fuerza = 2.5
                shark_fin = True
                tipo_senal = 'SHARK_FIN_BAJISTA'
            # Momentum alcista normal
            elif precio_actual > senal_actual and rsi_actual > 50:
                señal = 'CALL'
                fuerza = 1.5 if precio_actual > 60 else 1.0
                tipo_senal = 'MOMENTUM_ALCISTA'
            # Momentum bajista normal
            elif precio_actual < senal_actual and rsi_actual < 50:
                señal = 'PUT'
                fuerza = 1.5 if precio_actual < 40 else 1.0
                tipo_senal = 'MOMENTUM_BAJISTA'
            # Sobrecompra extrema (posible reversión)
            elif rsi_actual > banda_sup:
                señal = 'PUT'
                fuerza = 1.0
                tipo_senal = 'SOBRECOMPRA'
            # Sobreventa extrema (posible reversión)
            elif rsi_actual < banda_inf:
                señal = 'CALL'
                fuerza = 1.0
                tipo_senal = 'SOBREVENTA'
            return {
                'señal': señal,
                'fuerza': fuerza,
                'rsi': rsi_actual,
                'linea_precio': precio_actual,
                'linea_senal': senal_actual,
                'banda_superior': banda_sup,
                'banda_inferior': banda_inf,
                'shark_fin': shark_fin,
                'tipo_senal': tipo_senal
            }
        except Exception as e:
            logger.error(f"Error en análisis TDI: {e}")
            return {'señal': 'NEUTRAL', 'fuerza': 0, 'tipo_senal': 'ERROR'}

    def _detectar_patrones_market_maker(self, df: pd.DataFrame) -> dict:
        """
        Detecta patrones institucionales de Market Maker (W y M) con lógica Fibonacci.
        Implementa "Trampa del Segundo Pico" (Higher Low en W, Lower High en M).
        Zona Áurea: 61.8% - 78.6% Fibonacci.
        """
        try:
            if len(df) < 50:
                return {'patron': None, 'fuerza': 0, 'confianza': 0}

            # Usar zigzag o extremos locales para identificar picos y valles
            # Simplificación: Usar ventana deslizante para encontrar máximos/mínimos locales
            high = df['high'].values
            low = df['low'].values
            close = df['close'].values
            
            # Buscar últimos 3 pivotes significativos (P1, P2, P3)
            # Para patrón M (Venta): Subida -> P1 (Techo 1) -> Bajada -> P2 (Suelo/Cuello) -> Subida -> P3 (Techo 2)
            # Para patrón W (Compra): Bajada -> P1 (Suelo 1) -> Subida -> P2 (Techo/Cuello) -> Bajada -> P3 (Suelo 2)

            # Implementación simple buscando extremos en ventanas de 5-10 velas
            # Esto es una aproximación. Para producción idealmente usar librería ZigZag.
            
            patron = None
            fuerza = 0
            confianza = 0
            detalle = ""

            # --- DETECCIÓN DE PATRÓN M (DOBLE TECHO / TRAMPA BAJISTA) ---
            # Buscar P1 (Alto previo) en las últimas 20-40 velas
            p1_idx = np.argmax(high[-40:-10]) + (len(high) - 40)
            p1_val = high[p1_idx]
            
            # Buscar P2 (Cuello/Mínimo intermedio) entre P1 y actual
            if p1_idx < len(high) - 5:
                p2_window = low[p1_idx:]
                p2_rel_idx = np.argmin(p2_window)
                p2_idx = p1_idx + p2_rel_idx
                p2_val = low[p2_idx]
                
                # Buscar P3 (Segundo alto - Actual o muy reciente)
                # Debe estar formándose AHORA (últimas 3-5 velas)
                p3_window = high[p2_idx:]
                if len(p3_window) > 2:
                    p3_rel_idx = np.argmax(p3_window)
                    p3_idx = p2_idx + p3_rel_idx
                    p3_val = high[p3_idx]
                    
                    # Validar Estructura M
                    # 1. Lower High (Trampa): P3 debe ser menor o igual a P1 (o ligeramente superior para Stop Hunt, pero nos enfocamos en LH para seguridad)
                    # OJO: El usuario pide "Lower High" (P3 < P1)
                    if p3_idx > p2_idx and p2_idx > p1_idx:
                        # Calcular Retroceso de Fibonacci de la caída P1 -> P2 (No, Fibonacci se mide del impulso anterior o de la caída)
                        # Corrección Lógica User: "Verifica si el rebote hacia el segundo pico se detuvo en la zona del 61.8% - 78.6% de la caída previa."
                        # Caída previa??? En una M, P1 es alto. P2 es bajo. P3 es alto.
                        # El "impulso" es la bajada P1 -> P2? No, eso es la primera pata.
                        # Normalmente Fib se traza del impulso bajista anterior o del rango.
                        # Interpretación Usuario: "de la caída previa" -> P1 a P2.
                        # Entonces medimos el retroceso de P3 respecto al rango P1-P2.
                        # Rango = P1 - P2. Retracement = (P3 - P2) / (P1 - P2)
                        
                        rango_caida = p1_val - p2_val
                        if rango_caida > 0:
                            retroceso = (p3_val - p2_val) / rango_caida
                            
                            # Validar Zona Áurea (61.8% - 78.6%)
                            en_zona_aurea = 0.618 <= retroceso <= 0.786
                            
                            # Validar Lower High (P3 < P1)
                            lower_high = p3_val < p1_val
                            
                            if lower_high and en_zona_aurea:
                                # Confirmar con vela de rechazo en P3 (última vela)
                                ult_vela = df.iloc[-1]
                                mecha_sup = ult_vela['high'] - max(ult_vela['open'], ult_vela['close'])
                                cuerpo = abs(ult_vela['close'] - ult_vela['open'])
                                
                                # Vela de rechazo o envolvente bajista
                                rechazo = mecha_sup > cuerpo * 1.5
                                # O envolvente (comparar con anterior)
                                ant_vela = df.iloc[-2]
                                envolvente = (ult_vela['close'] < ant_vela['low']) and (ult_vela['open'] > ant_vela['high'])
                                
                                if rechazo or envolvente:
                                    patron = 'M_PATTERN_FIB'
                                    fuerza = 3.0 # Alta probabilidad
                                    confianza = 90
                                    detalle = f"M Pattern (Lower High) en Zona Fib {retroceso:.1%}"

            # --- DETECCIÓN DE PATRÓN W (DOBLE SUELO / TRAMPA ALCISTA) ---
            if not patron:
                # Buscar P1 (Bajo previo)
                p1_idx_w = np.argmin(low[-40:-10]) + (len(low) - 40)
                p1_val_w = low[p1_idx_w]
                
                if p1_idx_w < len(low) - 5:
                    p2_window_w = high[p1_idx_w:]
                    p2_rel_idx_w = np.argmax(p2_window_w)
                    p2_idx_w = p1_idx_w + p2_rel_idx_w
                    p2_val_w = high[p2_idx_w]
                    
                    p3_window_w = low[p2_idx_w:]
                    if len(p3_window_w) > 2:
                        p3_rel_idx_w = np.argmin(p3_window_w)
                        p3_idx_w = p2_idx_w + p3_rel_idx_w
                        p3_val_w = low[p3_idx_w]
                        
                        if p3_idx_w > p2_idx_w and p2_idx_w > p1_idx_w:
                            # Higher Low (Trampa): P3 > P1
                            rango_subida = p2_val_w - p1_val_w
                            if rango_subida > 0:
                                # Retroceso: Cuánto bajó P3 respecto a la subida P1->P2
                                # Retracement = (P2 - P3) / (P2 - P1)
                                retroceso_w = (p2_val_w - p3_val_w) / rango_subida
                                
                                en_zona_aurea_w = 0.618 <= retroceso_w <= 0.786
                                higher_low = p3_val_w > p1_val_w
                                
                                if higher_low and en_zona_aurea_w:
                                    # Confirmar vela rechazo (mecha inferior)
                                    ult_vela = df.iloc[-1]
                                    mecha_inf = min(ult_vela['open'], ult_vela['close']) - ult_vela['low']
                                    cuerpo = abs(ult_vela['close'] - ult_vela['open'])
                                    
                                    rechazo_w = mecha_inf > cuerpo * 1.5
                                    ant_vela = df.iloc[-2]
                                    envolvente_w = (ult_vela['close'] > ant_vela['high']) and (ult_vela['open'] < ant_vela['low'])
                                    
                                    if rechazo_w or envolvente_w:
                                        patron = 'W_PATTERN_FIB'
                                        fuerza = 3.0
                                        confianza = 90
                                        detalle = f"W Pattern (Higher Low) en Zona Fib {retroceso_w:.1%}"

            return {
                'patron': patron,
                'fuerza': fuerza,
                'confianza': confianza,
                'detalle': detalle
            }

        except Exception as e:
            logger.error(f"Error detectando patrones Market Maker: {e}")
            return {'patron': None, 'fuerza': 0, 'confianza': 0}

    def _analizar_accion_precio(self, df: pd.DataFrame) -> dict:
        """
        Analiza la acción del precio de forma AVANZADA para IA.
        MEJORADO: Sin MACD ni Estocástico - Enfoque en estructura pura de precio.
        Analiza:
        - Higher Highs / Lower Lows (estructura de tendencia)
        - Impulsos y retrocesos (ondas de Elliott simplificadas)
        - Breakouts de rangos
        - Momentum y velocidad del movimiento
        - Volatilidad y rango de las velas
        - Zonas de soporte/resistencia dinámicas
        """
        try:
            if len(df) < 30:
                return {'direccion': 'NEUTRAL', 'fuerza': 0}
            # Obtener datos
            ultimas = df.tail(30)
            close = ultimas['close'].values
            high = ultimas['high'].values
            low = ultimas['low'].values
            open_price = ultimas['open'].values
            # 1. ESTRUCTURA DE TENDENCIA (Higher Highs/Lows)
            max_local_1 = max(high[-5:])
            max_local_2 = max(high[-10:-5]) if len(high) >= 10 else max_local_1
            max_local_3 = max(
                high[-15:-10]) if len(high) >= 15 else max_local_2
            min_local_1 = min(low[-5:])
            min_local_2 = min(low[-10:-5]) if len(low) >= 10 else min_local_1
            min_local_3 = min(low[-15:-10]) if len(low) >= 15 else min_local_2
            higher_high = max_local_1 > max_local_2
            higher_high_confirmado = max_local_1 > max_local_2 and max_local_2 > max_local_3
            higher_low = min_local_1 > min_local_2
            higher_low_confirmado = min_local_1 > min_local_2 and min_local_2 > min_local_3
            lower_high = max_local_1 < max_local_2
            lower_low = min_local_1 < min_local_2
            # 2. MOMENTUM MULTI-PERIODO
            momentum_3 = (close[-1] - close[-3]) / \
                close[-3] * 100 if close[-3] > 0 else 0
            momentum_5 = (close[-1] - close[-5]) / \
                close[-5] * 100 if close[-5] > 0 else 0
            momentum_10 = (close[-1] - close[-10]) / \
                close[-10] * 100 if close[-10] > 0 else 0
            # Aceleración del momentum
            aceleracion = momentum_3 - momentum_5
            # 3. VOLATILIDAD Y RANGO
            rango_promedio = np.mean(high[-10:] - low[-10:])
            rango_actual = high[-1] - low[-1]
            expansion_volatilidad = rango_actual > rango_promedio * 1.5
            contraccion_volatilidad = rango_actual < rango_promedio * 0.5
            # 4. VELAS DE IMPULSO
            cuerpo_actual = abs(close[-1] - open_price[-1])
            mecha_superior = high[-1] - max(close[-1], open_price[-1])
            mecha_inferior = min(close[-1], open_price[-1]) - low[-1]
            es_vela_impulso = cuerpo_actual > rango_promedio * 0.7
            es_vela_rechazo = (
                mecha_superior > cuerpo_actual *
                2) or (
                mecha_inferior > cuerpo_actual *
                2)
            # 5. BREAKOUT DETECTION
            resistencia = max(high[-20:-1])
            soporte = min(low[-20:-1])
            breakout_alcista = close[-1] > resistencia
            breakout_bajista = close[-1] < soporte
            # 6. SCORING COMPUESTO
            score_alcista = 0
            score_bajista = 0

            # ----------------------------------------------------
            # INTEGRACIÓN ESTRATEGIA MARKET MAKER FIBONACCI (W/M)
            # ----------------------------------------------------
            mm_patterns = self._detectar_patrones_market_maker(df)
            patron_mm = mm_patterns.get('patron')
            fuerza_mm = mm_patterns.get('fuerza', 0)
            detalle_mm = mm_patterns.get('detalle', "")

            if patron_mm == 'W_PATTERN_FIB':
                score_alcista += 15.0  # Bonus masivo por patrón institucional
                logger.info(f"🦁 [MARKET MAKER] Detectado {detalle_mm} - Bonus +15.0 pts")
            elif patron_mm == 'M_PATTERN_FIB':
                score_bajista += 15.0  # Bonus masivo por patrón institucional
                logger.info(f"🦁 [MARKET MAKER] Detectado {detalle_mm} - Bonus +15.0 pts")

            # Estructura de tendencia
            if higher_high_confirmado and higher_low_confirmado:
                score_alcista += 3.0
            elif higher_high and higher_low:
                score_alcista += 2.0
            elif higher_high or higher_low:
                score_alcista += 1.0
            if lower_high and lower_low:
                score_bajista += 2.0
            elif lower_high or lower_low:
                score_bajista += 1.0
            # Momentum
            if momentum_3 > 0.1 and momentum_5 > 0:
                score_alcista += 1.5
            elif momentum_3 < -0.1 and momentum_5 < 0:
                score_bajista += 1.5
            if aceleracion > 0.05:
                score_alcista += 1.0
            elif aceleracion < -0.05:
                score_bajista += 1.0
            # Velas de impulso
            if es_vela_impulso and close[-1] > open_price[-1]:
                score_alcista += 1.5
            elif es_vela_impulso and close[-1] < open_price[-1]:
                score_bajista += 1.5
            # Breakouts
            if breakout_alcista:
                score_alcista += 2.5
            if breakout_bajista:
                score_bajista += 2.5
            # Rechazo (velas de reversión)
            if es_vela_rechazo:
                if mecha_inferior > mecha_superior:  # Rechazo a la baja = alcista
                    score_alcista += 1.0
                else:  # Rechazo a la alza = bajista
                    score_bajista += 1.0
            # DETERMINAR DIRECCIÓN FINAL
            diferencia = score_alcista - score_bajista
            if diferencia > 2.0:
                direccion = 'CALL'
                fuerza = min(3.0, diferencia)
                estructura = 'ALCISTA_FUERTE' if diferencia > 4 else 'ALCISTA'
            elif diferencia > 0.5:
                direccion = 'CALL'
                fuerza = diferencia
                estructura = 'ALCISTA_DEBIL'
            elif diferencia < -2.0:
                direccion = 'PUT'
                fuerza = min(3.0, abs(diferencia))
                estructura = 'BAJISTA_FUERTE' if diferencia < -4 else 'BAJISTA'
            elif diferencia < -0.5:
                direccion = 'PUT'
                fuerza = abs(diferencia)
                estructura = 'BAJISTA_DEBIL'
            else:
                direccion = 'NEUTRAL'
                fuerza = 0.5
                estructura = 'LATERAL'
            return {
                'direccion': direccion,
                'fuerza': fuerza,
                'estructura': estructura,
                'higher_high': higher_high,
                'higher_low': higher_low,
                'lower_high': lower_high,
                'lower_low': lower_low,
                'momentum_rapido': momentum_3,
                'momentum_medio': momentum_5,
                'momentum_lento': momentum_10,
                'aceleracion': aceleracion,
                'breakout_alcista': breakout_alcista,
                'breakout_bajista': breakout_bajista,
                'vela_impulso': es_vela_impulso,
                'vela_rechazo': es_vela_rechazo,
                'expansion_volatilidad': expansion_volatilidad,
                'score_alcista': score_alcista,
                'score_bajista': score_bajista
            }
        except Exception as e:
            logger.error(f"Error en análisis de acción del precio: {e}")
            return {'direccion': 'NEUTRAL', 'fuerza': 0, 'estructura': 'ERROR'}

    def _detectar_patrones_velas(self, df: pd.DataFrame) -> dict:
        """
        Detecta patrones de velas japonesas para confirmar señales.
        Incluye: Martillo, Martillo Invertido, Envolvente, Morning Star, Evening Star,
        Estrella Fugaz, Hombre Colgado, Suelo/Techo en Pinzas, Tres Estrellas
        """
        try:
            if len(df) < 5:
                return {'direccion': 'NEUTRAL', 'fuerza': 0,
                        'patrones': [], 'confirmacion': False}
            ultimas = df.tail(5)
            # Última vela
            o1, h1, l1, c1 = ultimas.iloc[-1][['open', 'high', 'low', 'close']]
            cuerpo1 = abs(c1 - o1)
            mecha_sup1 = h1 - max(o1, c1)
            mecha_inf1 = min(o1, c1) - l1
            rango1 = h1 - l1
            es_alcista1 = c1 > o1
            # Penúltima vela
            o2, h2, l2, c2 = ultimas.iloc[-2][['open', 'high', 'low', 'close']]
            cuerpo2 = abs(c2 - o2)
            mecha_sup2 = h2 - max(o2, c2)
            mecha_inf2 = min(o2, c2) - l2
            rango2 = h2 - l2
            es_alcista2 = c2 > o2
            # Antepenúltima vela
            o3, h3, l3, c3 = ultimas.iloc[-3][['open', 'high', 'low', 'close']]
            cuerpo3 = abs(c3 - o3)
            es_alcista3 = c3 > o3
            # Cuarta vela (para patrones de 3+)
            o4, h4, l4, c4 = ultimas.iloc[-4][['open', 'high', 'low', 'close']]
            # ========== PATRONES ALCISTAS (CALL) ==========
            # 1. Hammer (Martillo) - Cuerpo pequeño arriba, mecha inferior
            # larga
            if rango1 > 0 and mecha_inf1 > cuerpo1 * 2 and mecha_sup1 < cuerpo1 * 0.5:
                patrones_detectados.append('hammer')
                direccion = 'CALL'
                fuerza += 2.0
                logger.info(f"[PATRON] Martillo detectado - CALL")
            # 2. Martillo Invertido - En tendencia bajista, cuerpo pequeño
            # abajo, mecha superior larga
            if rango1 > 0 and mecha_sup1 > cuerpo1 * 2 and mecha_inf1 < cuerpo1 * 0.5:
                # Verificar tendencia bajista previa (últimas 3 velas bajistas)
                if not es_alcista2 and not es_alcista3:
                    patrones_detectados.append('inverted_hammer')
                    direccion = 'CALL'
                    fuerza += 1.5
                    logger.info(
                        f"[PATRON] Martillo Invertido detectado - CALL")
            # 3. Bullish Engulfing (Envolvente Alcista)
            if not es_alcista2 and es_alcista1:  # Vela anterior bajista, actual alcista
                if c1 > o2 and o1 < c2 and cuerpo1 > cuerpo2 * 1.5:  # Envuelve completamente
                    patrones_detectados.append('bullish_engulfing')
                    direccion = 'CALL'
                    fuerza += 2.5
                    logger.info(
                        f"[PATRON] Envolvente Alcista detectado - CALL")
            # 4. Morning Star (Estrella de la Mañana) - 3 velas
            if not es_alcista3 and cuerpo2 < cuerpo3 * 0.3 and es_alcista1:
                if c1 > (o3 + c3) / 2 and cuerpo1 > cuerpo2:
                    patrones_detectados.append('morning_star')
                    direccion = 'CALL'
                    fuerza += 3.0
                    logger.info(f"[PATRON] Morning Star detectado - CALL")
            # 5. Piercing Line (Línea de Perforación)
            if not es_alcista2 and es_alcista1:
                if o1 < c2 and c1 > (o2 + c2) / 2 and c1 < o2:
                    patrones_detectados.append('piercing_line')
                    direccion = 'CALL'
                    fuerza += 2.0
                    logger.info(f"[PATRON] Piercing Line detectado - CALL")
            # 6. Suelo en Pinzas (Tweezer Bottom) - Dos mínimos iguales
            if abs(l1 - l2) < rango1 * \
                    0.05 and not es_alcista2 and es_alcista1:
                patrones_detectados.append('tweezer_bottom')
                direccion = 'CALL'
                fuerza += 2.0
                logger.info(f"[PATRON] Suelo en Pinzas detectado - CALL")
            # 7. Tres Estrellas Alcistas (Three White Soldiers)
            if es_alcista1 and es_alcista2 and es_alcista3:
                if c1 > c2 > c3 and o1 > o2 > o3:  # Cierre cada vez más alto
                    if cuerpo1 > rango1 * 0.6 and cuerpo2 > rango2 * 0.6:  # Cuerpos largos
                        patrones_detectados.append('three_white_soldiers')
                        direccion = 'CALL'
                        fuerza += 3.0
                        logger.info(
                            f"[PATRON] Tres Estrellas Alcistas detectado - CALL")
            # ========== PATRONES BAJISTAS (PUT) ==========
            # 8. Shooting Star (Estrella Fugaz) - Cuerpo pequeño abajo, mecha
            # superior larga
            if rango1 > 0 and mecha_sup1 > cuerpo1 * 2 and mecha_inf1 < cuerpo1 * 0.5:
                # Verificar tendencia alcista previa
                if es_alcista2 and es_alcista3:
                    patrones_detectados.append('shooting_star')
                    direccion = 'PUT'
                    fuerza += 2.0
                    logger.info(f"[PATRON] Estrella Fugaz detectado - PUT")
            # 9. Hombre Colgado (Hanging Man) - Como martillo pero en tendencia
            # alcista
            if rango1 > 0 and mecha_inf1 > cuerpo1 * 2 and mecha_sup1 < cuerpo1 * 0.5:
                if es_alcista2 and es_alcista3:  # Después de tendencia alcista
                    patrones_detectados.append('hanging_man')
                    direccion = 'PUT'
                    fuerza += 2.0
                    logger.info(f"[PATRON] Hombre Colgado detectado - PUT")
            # 10. Bearish Engulfing (Envolvente Bajista)
            if es_alcista2 and not es_alcista1:  # Vela anterior alcista, actual bajista
                if c1 < o2 and o1 > c2 and cuerpo1 > cuerpo2 * 1.5:  # Envuelve completamente
                    patrones_detectados.append('bearish_engulfing')
                    direccion = 'PUT'
                    fuerza += 2.5
                    logger.info(f"[PATRON] Envolvente Bajista detectado - PUT")
            # 11. Evening Star (Estrella de la Tarde) - 3 velas
            if es_alcista3 and cuerpo2 < cuerpo3 * 0.3 and not es_alcista1:
                if c1 < (o3 + c3) / 2 and cuerpo1 > cuerpo2:
                    patrones_detectados.append('evening_star')
                    direccion = 'PUT'
                    fuerza += 3.0
                    logger.info(f"[PATRON] Evening Star detectado - PUT")
            # 12. Dark Cloud Cover (Nube Oscura)
            if es_alcista2 and not es_alcista1:
                if o1 > c2 and c1 < (o2 + c2) / 2 and c1 > o2:
                    patrones_detectados.append('dark_cloud_cover')
                    direccion = 'PUT'
                    fuerza += 2.0
                    logger.info(f"[PATRON] Dark Cloud Cover detectado - PUT")
            # 13. Techo en Pinzas (Tweezer Top) - Dos máximos iguales
            if abs(h1 - h2) < rango1 * \
                    0.05 and es_alcista2 and not es_alcista1:
                patrones_detectados.append('tweezer_top')
                direccion = 'PUT'
                fuerza += 2.0
                logger.info(f"[PATRON] Techo en Pinzas detectado - PUT")
            # 14. Tres Estrellas Bajistas (Three Black Crows)
            if not es_alcista1 and not es_alcista2 and not es_alcista3:
                if c1 < c2 < c3 and o1 < o2 < o3:  # Cierre cada vez más bajo
                    if cuerpo1 > rango1 * 0.6 and cuerpo2 > rango2 * 0.6:  # Cuerpos largos
                        patrones_detectados.append('three_black_crows')
                        direccion = 'PUT'
                        fuerza += 3.0
                        logger.info(
                            f"[PATRON] Tres Estrellas Bajistas detectado - PUT")
            # ========== PATRONES DE INDECISIÓN ==========
            # 15. Doji - Cuerpo muy pequeño
            if rango1 > 0 and cuerpo1 / rango1 < 0.1:
                patrones_detectados.append('doji')
                # No cambia dirección pero reduce confianza
                fuerza *= 0.7
                logger.info(f"[PATRON] Doji detectado - Indecisión")
            # Determinar dirección final
            if len(patrones_detectados) > 0:
                return {
                    'direccion': direccion,
                    'fuerza': min(fuerza, 4.0),
                    'patrones': patrones_detectados,
                    'confirmacion': fuerza >= 2.0
                }
            else:
                return {
                    'direccion': 'NEUTRAL',
                    'fuerza': 0,
                    'patrones': [],
                    'confirmacion': False
                }
        except Exception as e:
            logger.error(f"Error detectando patrones de velas: {e}")
            return {'direccion': 'NEUTRAL', 'fuerza': 0,
                    'patrones': [], 'confirmacion': False}

    def _analizar_ciclo_mercado(self) -> dict:
        """
        Analiza el ciclo de mercado basado en la sesión actual.
        Las mejores horas para trading de forex:
        - Londres: 08:00-16:00 GMT (mejor volatilidad)
        - Nueva York: 13:00-21:00 GMT (solapamiento con Londres)
        - Tokio: 00:00-08:00 GMT (menor volatilidad)
        """
        try:
            ahora = datetime.now()
            hora_utc = ahora.hour  # Ajustar a UTC si es necesario
            # Determinar sesión
            if 0 <= hora_utc < 8:
                sesion = 'ASIA'
                sesion_optima = False
                multiplicador = 0.7
            elif 8 <= hora_utc < 13:
                sesion = 'LONDRES'
                sesion_optima = True
                multiplicador = 1.2
            elif 13 <= hora_utc < 17:
                sesion = 'LONDRES_NY'  # Solapamiento
                sesion_optima = True
                multiplicador = 1.3  # Mejor momento
            elif 17 <= hora_utc < 21:
                sesion = 'NY'
                sesion_optima = True
                multiplicador = 1.1
            else:
                sesion = 'CIERRE'
                sesion_optima = False
                multiplicador = 0.6
            # Día de la semana (evitar viernes tarde)
            dia = ahora.weekday()
            if dia == 4 and hora_utc >= 18:  # Viernes tarde
                sesion_optima = False
                multiplicador *= 0.5
            elif dia in [5, 6]:  # Fin de semana
                sesion_optima = False
                multiplicador = 0
            return {
                'sesion': sesion,
                'sesion_optima': sesion_optima,
                'multiplicador': multiplicador,
                'hora_utc': hora_utc,
                'dia_semana': dia
            }
        except Exception as e:
            logger.error(f"Error analizando ciclo de mercado: {e}")
            return {'sesion': 'UNKNOWN',
                    'sesion_optima': False, 'multiplicador': 0.5}

    def _calcular_atr(self, df: pd.DataFrame, periodo: int = 14) -> float:
        """Calcula el ATR actual"""
        try:
            high = df['high']
            low = df['low']
            close = df['close']
            tr1 = high - low
            tr2 = abs(high - close.shift())
            tr3 = abs(low - close.shift())
            tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
            atr = tr.rolling(window=periodo).mean().iloc[-1]
            return atr if not pd.isna(atr) else 0
        except BaseException:
            return 0

    def generar_senal_multitimeframe(self, datos_5m: pd.DataFrame,
                                     datos_15m: pd.DataFrame = None,
                                     datos_1m: pd.DataFrame = None,
                                     simbolo: str = 'EURUSD') -> dict:
        """
        Genera señal combinando análisis de múltiples timeframes (1m, 5m, 15m).
        El timeframe de 5m es obligatorio (donde se ejecuta la operación binaria).
        Los timeframes de 1m y 15m proporcionan confirmación de tendencia.
        Reglas:
        1. La tendencia de 15m marca la dirección general
        2. El timeframe de 5m es la entrada principal
        3. El timeframe de 1m proporciona confirmación de corto plazo
        4. Solo operar cuando los 3 timeframes están alineados
        """
        try:
            logger.info(f"Generando señal multi-timeframe para {simbolo}")
            resultado = {
                'simbolo': simbolo,
                'timestamp': datetime.now().isoformat(),
                'senal': 'ESPERAR',
                'confianza': 0,
                'operar': False,
                'analisis': {},
                'razones': [],
                'alineacion_tf': {},
                'precio_actual': 0.0,
                'ia_confianza': 0.0,
                'tecnico_confianza': 0.0,
                'fortaleza': 'N/A',
                'tipo_datos': 'REAL',
                'indicadores': {}
            }
            # Analizar timeframe de 5 minutos (obligatorio - entrada principal)
            analisis_5m = self.analizar_timeframe(datos_5m, 5)
            resultado['analisis']['5m'] = analisis_5m
            if not analisis_5m.get('valido'):
                resultado['razones'].append('Datos 5m insuficientes')
                return resultado
            # Analizar timeframe de 1 minuto (opcional - confirmación rápida)
            analisis_1m = {}
            if datos_1m is not None:
                analisis_1m = self.analizar_timeframe(datos_1m, 1)
                resultado['analisis']['1m'] = analisis_1m
                if not analisis_1m.get('valido'):
                    resultado['razones'].append('Datos 1m insuficientes')
                    return resultado
            # Analizar timeframe de 15 minutos (opcional - análisis adicional)
            analisis_15m = {}
            if datos_15m is not None:
                analisis_15m = self.analizar_timeframe(datos_15m, 15)
                resultado['analisis']['15m'] = analisis_15m
                if not analisis_15m.get('valido'):
                    resultado['razones'].append('Datos 15m insuficientes')
                    return resultado
            # ✅ Verificar alineación de timeframes
            alineacion_tf = self._verificar_alineacion_multi_timeframe(
                simbolo, analisis_1m, analisis_5m, analisis_15m)
            resultado['alineacion_tf'] = alineacion_tf
            if not alineacion_tf['alineado']:
                resultado['razones'].append(
                    f"Timeframes NO alineados: {
                        alineacion_tf['razon']}")
                return resultado
            resultado['razones'].append("Timeframes alineados")
            # ✅ Predicción IA
            ia_disponible = False
            confianza_ia = 0.0
            prob_call = 0.5
            prob_put = 0.5
            if self.modelo_neuronal and self.escalador:
                try:
                    # Preparar datos para la predicción
                    datos_con_indicadores = self._calcular_indicadores_completos(
                        datos_5m.copy())
                    datos_con_indicadores.dropna(inplace=True)
                    if not datos_con_indicadores.empty:
                        ultimo_registro = datos_con_indicadores.iloc[-1].values.reshape(
                            1, -1)
                        try:
                            datos_escalados = self.escalador.transform(
                                ultimo_registro)
                        except Exception as e:
                            logger.warning(f"Error escalando datos: {e}")
                            return 50.0
                        if TORCH_AVAILABLE and hasattr(
                                self.modelo_neuronal, 'forward'):
                            with torch.no_grad():
                                self.modelo_neuronal.eval()
                                prediccion = self.modelo_neuronal(
                                    torch.FloatTensor(datos_escalados))
                                # Salida binaria con Sigmoid: 0-1 donde >0.5 =
                                # CALL, <0.5 = PUT
                                prob_call = prediccion.item()  # Valor 0-1
                                prob_put = 1 - prob_call
                                # Convertir a puntuación: 0=PUT fuerte,
                                # 50=neutral, 100=CALL fuerte
                                confianza_ia = prob_call * 100
                                ia_disponible = True
                except Exception as e:
                    logger.warning(
                        f"⚠️ Error en predicción IA OTC turbo: {e}",
                        exc_info=True)
            if not ia_disponible:
                # ✅ FALLBACK: Usar análisis técnico avanzado como pseudo-IA
                logger.warning(
                    f"⚠️ Modelo IA no disponible, usando análisis técnico avanzado como fallback")
                # Calcular pseudo-IA basada en múltiples indicadores técnicos
                # Acceder correctamente a los valores anidados en 'señales'
                señales_1m = analisis_1m.get('señales', {})
                señales_5m = analisis_5m.get('señales', {})
                rsi_1m = señales_1m.get('rsi', {}).get('valor', 50)
                rsi_5m = señales_5m.get('rsi', {}).get('valor', 50)
                tendencia_1m = señales_1m.get(
                    'ema', {}).get(
                    'tendencia', 'NEUTRAL')
                tendencia_5m = señales_5m.get(
                    'ema', {}).get(
                    'tendencia', 'NEUTRAL')
                # Score pseudo-IA basado en RSI y tendencia
                pseudo_score = 50.0
                if tendencia_1m == 'ALCISTA' and tendencia_5m == 'ALCISTA':
                    pseudo_score += 20
                if rsi_1m < 70 and rsi_5m < 70:  # No sobrecomprado
                    pseudo_score += 15
                elif tendencia_1m == 'BAJISTA' and tendencia_5m == 'BAJISTA':
                    pseudo_score -= 20
                if rsi_1m > 30 and rsi_5m > 30:  # No sobrevendido
                    pseudo_score -= 15
                # Limitar entre 0-100
                pseudo_score = max(0, min(100, pseudo_score))
                prob_call = pseudo_score / 100.0
                prob_put = 1 - prob_call
                confianza_ia = pseudo_score
                ia_disponible = True
            if ia_disponible:
                resultado['analisis']['ia'] = {
                    'probabilidad_call': prob_call,
                    'confianza': confianza_ia,
                    'direccion': 'CALL' if prob_call >= 0.5 else 'PUT',
                    'tipo': 'IA' if self.modelo_neuronal else 'PSEUDO_IA'
                }
                logger.info(
                    f"🧠 IA/PSEUDO-IA: {'CALL' if prob_call >= 0.5 else 'PUT'} con {confianza_ia:.1f}%")
            # ===== COMPONENTE 1: ANÁLISIS TÉCNICO (30%) =====
            score_tecnico_call = 0
            score_tecnico_put = 0
            peso_tecnico = self.config.PESO_TECNICO  # 0.30
            votos_1m_call = analisis_1m.get('votos_call', 0)
            votos_1m_put = analisis_1m.get('votos_put', 0)
            votos_5m_call = analisis_5m.get('votos_call', 0)
            votos_5m_put = analisis_5m.get('votos_put', 0)
            votos_15m_call = analisis_15m.get('votos_call', 0)
            votos_15m_put = analisis_15m.get('votos_put', 0)
            score_tecnico_call = (
                votos_1m_call * 1.2 + votos_5m_call * 0.8 + votos_15m_call * 0.5) / 2.5
            score_tecnico_put = (
                votos_1m_put * 1.2 + votos_5m_put * 0.8 + votos_15m_put * 0.5) / 2.5
            max_tecnico = max(score_tecnico_call, score_tecnico_put, 1)
            score_tecnico_call_norm = (score_tecnico_call / max_tecnico) * 100
            score_tecnico_put_norm = (score_tecnico_put / max_tecnico) * 100
            # ===== COMPONENTE 2: IA (70%) =====
            peso_ia = self.config.PESO_NEURONAL  # 0.70
            # Calcular confianza total
            confianza_total_call = (
                score_tecnico_call_norm * peso_tecnico) + (confianza_ia * peso_ia)
            confianza_total_put = (
                score_tecnico_put_norm * peso_tecnico) + (confianza_ia * peso_ia)
            # Determinar dirección y confianza
            if confianza_total_call > confianza_total_put:
                señal = 'CALL'
                confianza = confianza_total_call
            else:
                señal = 'PUT'
                confianza = confianza_total_put
            # ===== FUSIÓN (70% IA + 30% TÉCNICO) =====
            resultado['razones'].append(
                f"Fusión: {peso_tecnico:.0%} Técnico + {peso_ia:.0%} IA")
            if ia_disponible:
                resultado['razones'].append(
                    f"IA: {
                        'CALL' if prob_call >= 0.5 else 'PUT'} ({
                        confianza_ia:.1f}%)")
            # ✅ AÑADIR CAMPOS PARA LA TABLA DE ANÁLISIS
            precio_actual = datos_5m['close'].iloc[-1] if not datos_5m.empty else 0.0
            tipo_datos = datos_5m.iloc[-1].get('tipo_datos',
                                               'REAL') if not datos_5m.empty else 'DESCONOCIDO'
            # Calcular confianza técnica normalizada
            tecnico_pct = max(score_tecnico_call_norm, score_tecnico_put_norm)
            # Determinar fortaleza
            if confianza >= self.config.UMBRAL_SEÑAL_CONFIRMADA:
                fortaleza = 'CONFIRMADA'
            elif confianza >= self.config.UMBRAL_SEÑAL_DESTACADA:
                fortaleza = 'DESTACADA'
            else:
                fortaleza = 'DÉBIL'
            resultado['precio_actual'] = round(precio_actual, 5)
            resultado['ia_confianza'] = round(confianza_ia, 2)
            resultado['tecnico_confianza'] = round(tecnico_pct, 2)
            resultado['fortaleza'] = fortaleza
            resultado['tipo_datos'] = tipo_datos
            resultado['indicadores'] = {
                'ai_confianza': round(confianza_ia, 2),
                'tecnico_confianza': round(tecnico_pct, 2),
                'votos_call': votos_1m_call + votos_5m_call + votos_15m_call,
                'votos_put': votos_1m_put + votos_5m_put + votos_15m_put
            }
            logger.info(
                f"✅ Señal OTC turbo: {
                    resultado['senal']} con confianza {
                    resultado['confianza']:.2f}% | IA: {
                    confianza_ia:.1f}% | Técnico: {
                    tecnico_pct:.1f}%")
            return resultado
        except Exception as e:
            logger.critical(
                f"💥 Error CRÍTICO generando señal OTC turbo para {simbolo}: {e}",
                exc_info=True)
            return {
                'senal': 'ESPERAR',
                'confianza': 0.0,
                'operar': False,
                'error': str(e),
                'timestamp': datetime.now().isoformat()
            }

    # ========================================================================
    # AUXILIARES NECESARIOS (añadidos para completar la clase)
    # ========================================================================
    def analizar_timeframe(self, df: pd.DataFrame, timeframe: int) -> dict:
        """Analiza un timeframe específico (1, 5, 15 min)."""
        try:
            if df.empty or len(df) < 30:
                return {'valido': False, 'razon': 'Datos insuficientes'}
            # Calcular indicadores
            close = df['close']
            ema_21 = _ema_series(close, 21).iloc[-1]
            ema_50 = _ema_series(close, 50).iloc[-1]
            ema_200 = _ema_series(close, 200).iloc[-1]
            rsi = self.indicadores.calcular_rsi(close, 14).iloc[-1]
            tdi_data = self._calcular_tdi(df)
            patrones = self._detectar_patrones(df)
            precio = close.iloc[-1]
            tendencia = 'ALCISTA' if precio > ema_21 > ema_50 > ema_200 else \
                'BAJISTA' if precio < ema_21 < ema_50 < ema_200 else 'NEUTRAL'
            # Votos
            votos_call = 0
            votos_put = 0
            if tendencia == 'ALCISTA':
                votos_call += 3
            elif tendencia == 'BAJISTA':
                votos_put += 3
            if rsi < 30:
                votos_call += 2
            elif rsi > 70:
                votos_put += 2
            if tdi_data.get('senal') == 'CALL':
                votos_call += 3
            elif tdi_data.get('senal') == 'PUT':
                votos_put += 3
            if 'hammer' in patrones:
                votos_call += 2
            elif 'shooting_star' in patrones:
                votos_put += 2
            return {
                'valido': True,
                'timeframe': timeframe,
                'votos_call': votos_call,
                'votos_put': votos_put,
                'señales': {
                    'ema': {'tendencia': tendencia},
                    'rsi': {'valor': rsi},
                    'tdi': tdi_data,
                    'patrones': patrones
                }
            }
        except Exception as e:
            logger.error(f"Error analizando timeframe {timeframe}: {e}")
            return {'valido': False, 'razon': str(e)}

    def _normalizar_dataframe_velas(self, datos) -> pd.DataFrame:
        """Convierte lista de velas crudas de IQ Option a DataFrame con índice datetime 'time'"""
        if not datos or len(datos) == 0:
            return pd.DataFrame()
        try:
            df = pd.DataFrame(datos)
            if 'from' in df.columns:
                df['time'] = pd.to_datetime(df['from'], unit='s')
                df.set_index('time', inplace=True)
            elif 'timestamp' in df.columns:
                df['time'] = pd.to_datetime(df['timestamp'], unit='s')
                df.set_index('time', inplace=True)
            elif 'time' in df.columns:
                df['time'] = pd.to_datetime(
                    df['time'], unit='s', errors='coerce')
                df.set_index('time', inplace=True)
            else:
                df['time'] = pd.date_range(
                    end=pd.Timestamp.now(), periods=len(df), freq='1min')
                df.set_index('time', inplace=True)
            return df
        except Exception as e:
            logger.error(f"Error normalizando velas: {e}")
            return pd.DataFrame()

    def _obtener_direccion_tf(self, analisis) -> str:
        if not analisis or not analisis.get('valido'):
            return 'NEUTRAL'
        if analisis.get('votos_call', 0) > analisis.get('votos_put', 0):
            return 'CALL'
        elif analisis.get('votos_put', 0) > analisis.get('votos_call', 0):
            return 'PUT'
        return 'NEUTRAL'

    def _calcular_tdi(self, df: pd.DataFrame) -> dict:
        """Calcula TDI manual (índice de volatilidad direccional)"""
        try:
            if len(df) < 14:
                return {'senal': 'NEUTRAL', 'fuerza': 0}
            close = df['close']
            rsi = self.indicadores.calcular_rsi(close, 13)
            rsi_ema = _ema_series(rsi, 2)
            rsi_senal = rsi.rolling(7).mean()
            rsi_banda_sup = rsi_senal + (2 * rsi.rolling(34).std())
            rsi_banda_inf = rsi_senal - (2 * rsi.rolling(34).std())
            actual_rsi = rsi.iloc[-1]
            actual_ema = rsi_ema.iloc[-1]
            actual_senal = rsi_senal.iloc[-1]
            actual_banda_sup = rsi_banda_sup.iloc[-1]
            actual_banda_inf = rsi_banda_inf.iloc[-1]
            if actual_rsi > actual_senal and actual_rsi > actual_banda_sup:
                senal = 'CALL'
            elif actual_rsi < actual_senal and actual_rsi < actual_banda_inf:
                senal = 'PUT'
            else:
                senal = 'NEUTRAL'
            fuerza = abs(actual_rsi - actual_senal) / \
                actual_senal if actual_senal != 0 else 0
            return {
                'senal': senal,
                'fuerza': fuerza,
                'rsi': actual_rsi,
                'linea_precio': actual_rsi,
                'linea_senal': actual_senal,
                'banda_superior': actual_banda_sup,
                'banda_inferior': actual_banda_inf
            }
        except BaseException:
            return {'senal': 'NEUTRAL', 'fuerza': 0}

    def _detectar_patrones(self, df: pd.DataFrame) -> list:
        """Detecta patrones básicos de velas japonesas"""
        patrones = []
        if len(df) >= 2:
            prev = df.iloc[-2]
            curr = df.iloc[-1]
            # Hammer
            if curr['close'] > curr['open'] and (
                    curr['open'] - curr['low']) > 2 * (curr['high'] - curr['close']):
                patrones.append('hammer')
            # Shooting Star
            if curr['open'] > curr['close'] and (
                    curr['high'] - curr['open']) > 2 * (curr['close'] - curr['low']):
                patrones.append('shooting_star')
        return patrones

    def _preparar_datos_para_ia(
            self, df: pd.DataFrame) -> Optional[np.ndarray]:
        """Prepara datos para predicción neuronal"""
        try:
            # Calcular indicadores
            datos_con_indicadores = self._calcular_indicadores_completos(df)
            if datos_con_indicadores.empty:
                return None
            # Seleccionar características
            cols = [
                c for c in datos_con_indicadores.columns if pd.api.types.is_numeric_dtype(
                    datos_con_indicadores[c])]
            X = datos_con_indicadores[cols].iloc[-1:].values
            # Escalar
            if self.escalador:
                X = self.escalador.transform(X)
            return X
        except Exception as e:
            logger.warning(f"Error preparando datos para IA: {e}")
            return None

    def _verificar_alineacion_multi_timeframe(
            self, simbolo: str, analisis_1m: dict, analisis_5m: dict, analisis_15m: dict) -> dict:
        """
        Verifica que los timeframes 1m, 5m y 15m estén alineados en la misma dirección.
        Returns:
            dict con: alineado (bool), direccion (str), confianza (float), razon (str)
        """
        try:
            resultado = {
                'alineado': False,
                'direccion': 'NEUTRAL',
                'confianza': 0.0,
                'razon': 'Sin análisis',
                'alineacion_completa': False
            }
            # Obtener direcciones de cada timeframe
            dir_1m = self._obtener_direccion_tf(
                analisis_1m) if analisis_1m and analisis_1m.get('valido') else 'NEUTRAL'
            dir_5m = self._obtener_direccion_tf(
                analisis_5m) if analisis_5m and analisis_5m.get('valido') else 'NEUTRAL'
            dir_15m = self._obtener_direccion_tf(
                analisis_15m) if analisis_15m and analisis_15m.get('valido') else 'NEUTRAL'
            if 'NEUTRAL' in (dir_1m, dir_5m, dir_15m):
                resultado['razon'] = f'No alineado: 1m={dir_1m}, 5m={dir_5m}, 15m={dir_15m}'
                return resultado

            if dir_1m == dir_5m == dir_15m:
                resultado['alineado'] = True
                resultado['direccion'] = dir_5m
                confianzas = []
                for a in (analisis_1m, analisis_5m, analisis_15m):
                    if a and a.get('valido'):
                        confianzas.append(
                            a.get(
                                'votos_call',
                                0) +
                            a.get(
                                'votos_put',
                                0))
                if confianzas:
                    resultado['confianza'] = sum(
                        confianzas) / len(confianzas) / 10.0
                resultado['alineacion_completa'] = True
                resultado['razon'] = f'Alineación completa 1m/5m/15m en {dir_5m}'
            else:
                resultado['razon'] = f'Conflicto: 1m={dir_1m}, 5m={dir_5m}, 15m={dir_15m}'
            return resultado
        except Exception as e:
            logger.error(f"Error verificando alineación multi-TF: {e}")
            return {'alineado': False, 'direccion': 'NEUTRAL',
                    'confianza': 0.0, 'razon': str(e)}


# ========== EMULADOR DE ACCIONES HUMANAS ==========
# CAPITULO 16:
# ==================================================


logger = logging.getLogger(__name__)


# ==================================================
# CLASE HumanMouseExecutor COMPLETA
# ==================================================

class HumanMouseExecutor:
    """
    Executor de órdenes con emulación humana.
    Diseñado para:
    - Trading REAL en IQ Option
    - Paper trading
    - Evitar patrones de bot (delays no deterministas)
    """

    def __init__(self, config=None, randomizar: bool = True,
                 delay_min: float = None, delay_max: float = None):
        """
        Inicializa el executor humano.

        Args:
            config: Configuración del sistema (opcional)
            randomizar: Si True, genera delays aleatorios
            delay_min: Delay mínimo personalizado
            delay_max: Delay máximo personalizado
        """
        self.config = config
        self.logger = logging.getLogger(__name__)

        # Delays base
        if randomizar:
            self.delay_min = delay_min if delay_min is not None else random.uniform(
                0.25, 0.45)
            self.delay_max = delay_max if delay_max is not None else random.uniform(
                1.1, 1.8)
        else:
            self.delay_min = delay_min if delay_min is not None else 0.3
            self.delay_max = delay_max if delay_max is not None else 1.5

        self.velocidad_mouse = random.uniform(0.4, 0.8)
        self.errores_humanos = True
        self.modo_cansancio = random.random() < 0.15

        self.logger.info(
            f"[HUMAN EXECUTOR] Inicializado | "
            f"delay_min={self.delay_min:.2f}s | "
            f"delay_max={self.delay_max:.2f}s | "
            f"cansancio={self.modo_cansancio}"
        )

    # ==================================================
    # EJECUCIÓN PRINCIPAL (ACTUALIZADA)
    # ==================================================
    def ejecutar_orden_humana(
        self,
        api,
        simbolo: str,
        direccion: str,
        monto: float,
        duracion: int = 5
    ) -> Optional[int]:
        """
        Ejecuta una orden simulando comportamiento humano real.
        Compatible con ambas APIs de IQ Option.

        Args:
            api: Instancia de IQ Option API (stable o async)
            simbolo: Par a operar (ej: "EURUSD")
            direccion: "CALL" o "PUT"
            monto: Monto de la operación
            duracion: Duración en minutos

        Returns:
            ID de la operación o None si falla.
        """
        try:
            self.logger.info(
                f"[EMULACIÓN HUMANA] Iniciando: {simbolo} {direccion} "
                f"${monto:.2f} ({duracion}min)"
            )

            # Verificar modo PAPER TRADING
            if self.config and getattr(
                    self.config, 'MODO_PAPER_TRADING', False):
                order_id = random.randint(10000, 99999)
                self.logger.info(
                    f"[EMULACIÓN] Orden simulada (PAPER) | ID={order_id}")
                return order_id

            duracion_min = int(duracion or 5)
            if duracion_min <= 0:
                duracion_min = 5

            # Calcular tiempo restante del ciclo
            ts = self._get_server_time(api)
            ciclo = max(60, duracion_min * 60)
            restante = float(ciclo - (ts % ciclo))

            if restante <= 8.0:
                time.sleep(max(0.0, restante) + random.uniform(0.6, 1.4))

            restante = float(ciclo - (self._get_server_time(api) % ciclo))
            apuro = restante <= 25.0

            # Delays humanos antes de ejecutar
            self._delay_humano(0.18, 0.55, permitir_extra=not apuro)
            self._delay_humano(0.10, 0.28, permitir_extra=not apuro)
            self._delay_humano(0.10, 0.32, permitir_extra=not apuro)
            self._delay_humano(0.14, 0.55, permitir_extra=not apuro)

            if (not apuro) and random.random() < 0.25:
                self._delay_humano(0.05, 0.16, permitir_extra=True)

            # API STABLE (IQ_Option_Stable)
            if IQOPTION_STABLE_AVAILABLE and hasattr(api, "buy"):
                dir_up = str(direccion or "").upper()
                if dir_up not in ("CALL", "PUT"):
                    self.logger.error(
                        f"[EMULACIÓN] Dirección inválida: {direccion}")
                    return None

                action = "call" if dir_up == "CALL" else "put"
                order_id = self._buy_with_retry_stable(
                    api, monto, simbolo, action, duracion_min, max_intentos=2)

                if order_id is not None:
                    self.logger.info(
                        f"[EMULACIÓN] Orden ejecutada (stable) | ID={order_id}")
                    self._delay_humano(0.12, 0.40, permitir_extra=False)
                    return int(order_id)
                return None

            # API ASYNC (IQOptionClient)
            elif IQOPTION_ASYNC_AVAILABLE and hasattr(api, "place_binary_option"):
                dir_up = str(direccion or "").upper()
                if dir_up not in ("CALL", "PUT"):
                    self.logger.error(
                        f"[EMULACIÓN] Dirección inválida: {direccion}")
                    return None

                action = "call" if dir_up == "CALL" else "put"
                order_id = self._buy_with_retry_async(
                    api, monto, simbolo, action, duracion_min, max_intentos=2)

                if order_id is not None:
                    self.logger.info(
                        f"[EMULACIÓN] Orden ejecutada (async) | ID={order_id}")
                    self._delay_humano(0.12, 0.40, permitir_extra=False)
                    return int(order_id)
                return None

            # FALLBACK SIMULADO (para pruebas)
            order_id = random.randint(10000, 99999)
            self.logger.info(
                f"[EMULACIÓN] Orden simulada (fallback) | ID={order_id}")
            return order_id

        except Exception as e:
            self.logger.error(f"[EMULACIÓN] Error crítico: {e}", exc_info=True)
            return None

    # ==================================================
    # DELAY HUMANO NO DETERMINISTA (ACTUALIZADO)
    # ==================================================
    def _delay_humano(self, min_delay: float = None,
                      max_delay: float = None, permitir_extra: bool = True):
        """
        Delay humano con variaciones aleatorias.

        Args:
            min_delay: Delay mínimo (usa self.delay_min si es None)
            max_delay: Delay máximo (usa self.delay_max si es None)
            permitir_extra: Si True, agrega variaciones extra
        """
        min_d = min_delay if min_delay is not None else self.delay_min
        max_d = max_delay if max_delay is not None else self.delay_max

        # Distribución no lineal para mayor realismo
        delay = min_d + (max_d - min_d) * (random.random() ** 1.5)

        # Errores humanos ocasionales (tecleo lento, distracción)
        if permitir_extra and self.errores_humanos:
            if random.random() < 0.1:  # 10% de probabilidad de error
                delay += random.uniform(0.5, 2.0)
                self.logger.debug(
                    f"[DELAY] Error humano añadido: +{delay - (min_d + (max_d - min_d) * (random.random() ** 1.5)):.2f}s")

            # Modo cansancio (final de sesión)
            if self.modo_cansancio:
                delay *= random.uniform(1.2, 1.6)
                self.logger.debug(
                    f"[DELAY] Modo cansancio: x{delay / (min_d + (max_d - min_d) * (random.random() ** 1.5)):.2f}")

        time.sleep(delay)

    def _get_server_time(self, api) -> float:
        """
        Obtiene timestamp del servidor o usa tiempo local como fallback.
        """
        try:
            if api is not None:
                # API stable
                if hasattr(api, "get_server_timestamp"):
                    ts = api.get_server_timestamp()
                    if isinstance(ts, (int, float)) and ts:
                        return float(ts)

                # API async
                if hasattr(api, "get_server_time"):
                    try:
                        ts = api.get_server_time()
                        if isinstance(ts, (int, float)):
                            return float(ts)
                    except Exception:
                        pass
        except Exception:
            pass

        # Fallback a tiempo local
        return float(time.time())

    # ==================================================
    # MÉTODOS DE COMPRA PARA DIFERENTES APIs
    # ==================================================

    def _buy_with_retry_stable(self, api, monto: float, simbolo: str, action: str,
                               duracion_min: int, max_intentos: int = 2) -> Optional[int]:
        """
        Compra con API stable con reintentos.
        """
        for intento in range(max_intentos):
            try:
                res = api.buy(monto, simbolo, action, int(duracion_min))
            except Exception as e:
                self.logger.warning(f"[EMULACIÓN] Fallo API stable: {e}")
                return None

            # Procesar respuesta
            check = False
            order_id = None
            raw_msg = None

            if isinstance(res, tuple) and len(res) >= 2:
                check = bool(res[0])
                order_id = res[1]
                raw_msg = res[1]
            elif isinstance(res, dict):
                check = bool(res.get("check", res.get("success", False)))
                order_id = res.get("id", res.get("order_id"))
                raw_msg = res
            else:
                raw_msg = res

            if check and order_id:
                return int(order_id)

            msg = str(raw_msg) if raw_msg is not None else ""
            self.logger.warning(f"[EMULACIÓN] Fallo API stable: {raw_msg}")

            # Reintentar si es "late"
            if ("late" in msg.lower()) and intento < (max_intentos - 1):
                ts = self._get_server_time(api)
                ciclo = max(60, int(duracion_min) * 60)
                restante = float(ciclo - (ts % ciclo))
                time.sleep(max(0.0, restante) + random.uniform(0.6, 1.4))
                continue

            return None

        return None

    def _buy_with_retry_async(self, api, monto: float, simbolo: str, action: str,
                              duracion_min: int, max_intentos: int = 2) -> Optional[int]:
        """
        Compra con API async con reintentos.
        """
        for intento in range(max_intentos):
            try:
                # Ejecutar de forma asíncrona
                async def comprar_async():
                    return await api.place_binary_option(
                        symbol=simbolo,
                        amount=monto,
                        direction=action,
                        duration=duracion_min * 60  # Convertir a segundos
                    )

                res = _run_async_safe(comprar_async())

            except Exception as e:
                self.logger.warning(f"[EMULACIÓN] Fallo API async: {e}")
                return None

            # Procesar respuesta
            if isinstance(res, dict):
                order_id = res.get('order_id', res.get('id'))
                if order_id:
                    return int(order_id)
                else:
                    self.logger.warning(
                        f"[EMULACIÓN] Respuesta API async sin order_id: {res}")
            elif isinstance(res, (int, str)):
                return int(res)
            else:
                self.logger.warning(
                    f"[EMULACIóN] Respuesta inesperada API async: {res}")

            # Reintentar
            if intento < (max_intentos - 1):
                ts = self._get_server_time(api)
                ciclo = max(60, int(duracion_min) * 60)
                restante = float(ciclo - (ts % ciclo))
                time.sleep(max(0.0, restante) + random.uniform(0.6, 1.4))

        return None

    # ==================================================
    # MOVIMIENTO DE MOUSE (BEZIER IMPERFECTO) - GUI ONLY
    # ==================================================
    def mover_mouse_bezier(
        self,
        x_inicio: int,
        y_inicio: int,
        x_fin: int,
        y_fin: int
    ) -> List[Tuple[int, int]]:
        """
        Simula movimiento de mouse humano con curva de Bezier.
        Solo para GUI con PyQt5/pyautogui.
        """
        try:
            # Verificar si tenemos GUI disponible
            if not GUI_AVAILABLE or HEADLESS_MODE:
                return [(x_fin, y_fin)]

            puntos: List[Tuple[int, int]] = []

            # Punto de control aleatorio para curva natural
            ctrl_x = (x_inicio + x_fin) / 2 + random.uniform(-50, 50)
            ctrl_y = (y_inicio + y_fin) / 2 + random.uniform(-30, 30)

            # Número de pasos variable
            pasos = random.randint(20, 40)

            for i in range(pasos + 1):
                t = i / pasos

                # Fórmula curva de Bezier cuadrática
                x = (
                    (1 - t) ** 2 * x_inicio
                    + 2 * (1 - t) * t * ctrl_x
                    + t ** 2 * x_fin
                )
                y = (
                    (1 - t) ** 2 * y_inicio
                    + 2 * (1 - t) * t * ctrl_y
                    + t ** 2 * y_fin
                )

                # Micro-variaciones naturales
                x += random.uniform(-2, 2)
                y += random.uniform(-1, 1)

                puntos.append((int(x), int(y)))

            # Corrección humana ocasional (retroceso)
            if random.random() < 0.25 and len(puntos) > 5:
                mitad = len(puntos) // 2
                puntos.insert(mitad, puntos[mitad])  # Pausa en el medio

            return puntos

        except Exception as e:
            self.logger.error(f"Error en movimiento Bezier: {e}")
            return [(x_fin, y_fin)]

    def ejecutar_movimiento_mouse(self, x_fin: int, y_fin: int) -> bool:
        """
        Ejecuta movimiento de mouse real usando pyautogui.
        Requiere GUI y pyautogui instalado.
        """
        try:
            if not GUI_AVAILABLE or HEADLESS_MODE:
                return False

            import pyautogui

            # Obtener posición actual
            x_ini, y_ini = pyautogui.position()

            # Generar trayectoria Bezier
            puntos = self.mover_mouse_bezier(x_ini, y_ini, x_fin, y_fin)

            # Mover a través de todos los puntos
            for x, y in puntos:
                pyautogui.moveTo(x, y, duration=self.velocidad_mouse / 1000.0)
                time.sleep(random.uniform(0.001, 0.005))

            return True

        except ImportError:
            self.logger.warning(
                "pyautogui no disponible para movimiento de mouse")
            return False
        except Exception as e:
            self.logger.error(f"Error moviendo mouse: {e}")
            return False

    # ==================================================
    # CLICK HUMANO IMPRECISO - GUI ONLY
    # ==================================================
    def simular_click(self, x: int, y: int,
                      doble_click: bool = False) -> Tuple[int, int]:
        """
        Simula click humano con imprecisiones naturales.

        Args:
            x, y: Coordenadas objetivo
            doble_click: Si True, simula doble click

        Returns:
            Coordenadas reales donde se hizo click
        """
        try:
            # Variación natural en el objetivo
            x_real = x + random.randint(-3, 3)
            y_real = y + random.randint(-2, 2)

            # Delay antes del click
            self._delay_humano(0.05, 0.15)

            # Ejecutar click real si tenemos pyautogui
            if GUI_AVAILABLE and not HEADLESS_MODE:
                try:
                    import pyautogui

                    # Mover a posición
                    self.ejecutar_movimiento_mouse(x_real, y_real)

                    # Click simple o doble
                    if doble_click:
                        pyautogui.doubleClick()
                        self._delay_humano(0.08, 0.15)  # Delay entre clicks
                    else:
                        pyautogui.click()

                except ImportError:
                    pass

            return x_real, y_real

        except Exception as e:
            self.logger.error(f"Error en simulación de click: {e}")
            return x, y

    # ==================================================
    # NUEVOS MÉTODOS PARA INTEGRACIÓN CON SISTEMA
    # ==================================================

    def ejecutar_orden_con_emulacion(self, api, simbolo: str, direccion: str,
                                     monto: float, duracion: int = 5) -> Optional[int]:
        """
        Versión mejorada con emulación completa (mouse + teclado).
        Para uso en GUI con auto-trading habilitado.
        """
        try:
            # 1. Simular movimiento hacia botón de operación
            if GUI_AVAILABLE and not HEADLESS_MODE:
                self.logger.debug("[EMULACIÓN] Simulando preparación...")

                # Mover a área general de trading
                screen_width, screen_height = 1920, 1080  # Asumir Full HD
                x_trading = random.randint(
                    screen_width // 2 - 100, screen_width // 2 + 100)
                y_trading = random.randint(200, 300)

                self.ejecutar_movimiento_mouse(x_trading, y_trading)
                self._delay_humano(0.2, 0.5)

            # 2. Seleccionar par (simulado)
            self._delay_humano(0.1, 0.3)

            # 3. Establecer monto (simulado)
            self._delay_humano(0.15, 0.4)

            # 4. Seleccionar duración (simulado)
            self._delay_humano(0.1, 0.25)

            # 5. Ejecutar orden principal
            return self.ejecutar_orden_humana(
                api, simbolo, direccion, monto, duracion)

        except Exception as e:
            self.logger.error(f"Error en emulación completa: {e}")
            # Fallback a método simple
            return self.ejecutar_orden_humana(
                api, simbolo, direccion, monto, duracion)

    def configurar_delays(self, min_delay: float = None, max_delay: float = None,
                          velocidad_mouse: float = None, errores_humanos: bool = None):
        """
        Permite configurar parámetros de emulación en tiempo real.
        """
        if min_delay is not None:
            self.delay_min = max(0.1, min_delay)  # Mínimo 0.1s
        if max_delay is not None:
            self.delay_max = max(self.delay_min + 0.1, max_delay)
        if velocidad_mouse is not None:
            self.velocidad_mouse = max(0.1, min(2.0, velocidad_mouse))
        if errores_humanos is not None:
            self.errores_humanos = errores_humanos

        self.logger.info(
            f"[EMULACIÓN] Configurado: min={self.delay_min:.2f}s, "
            f"max={self.delay_max:.2f}s, vel_mouse={self.velocidad_mouse:.2f}"
        )

    def obtener_estadisticas(self) -> dict:
        """
        Retorna estadísticas de uso del executor.
        """
        return {
            "delay_min": self.delay_min,
            "delay_max": self.delay_max,
            "velocidad_mouse": self.velocidad_mouse,
            "errores_humanos": self.errores_humanos,
            "modo_cansancio": self.modo_cansancio
        }


