class EstadoSenal:
    """Estados posibles de una señal"""
    DETECTADA = "DETECTADA"           # Señal inicial detectada
    EN_SEGUIMIENTO = "EN_SEGUIMIENTO"  # Monitoreo activo
    CONFIRMADA = "CONFIRMADA"         # Lista para ejecutar
    EJECUTADA = "EJECUTADA"           # Trade ejecutado
    WIN = "WIN"                       # Resultado ganador
    LOSS = "LOSS"                     # Resultado perdedor
    CANCELADA = "CANCELADA"           # Señal cancelada

# CAPITULO 18:


class PaperTradingEngine:
    """
    Simula una operación binaria REALISTA.
    Respeta expiración y devuelve WIN / LOSS.
    """

    def __init__(self, iq_bridge, ai_engine):
        self.iq_bridge = iq_bridge
        self.ai_engine = ai_engine

    def ejecutar(self, par, direccion, precio_entrada, expiracion_segundos):
        """
        Simula una operación binaria completa.
        """
        inicio = datetime.now()

        # Esperar expiración real
        time.sleep(expiracion_segundos)

        # Obtener precio final REAL
        df = self.iq_bridge.obtener_datos_tiempo_real(
            par, cantidad=2, timeframe="1"
        )

        if df is None or df.empty:
            return None

        precio_final = df['close'].iloc[-1]

        # Determinar resultado
        if direccion == 'CALL':
            win = precio_final > precio_entrada
        else:
            win = precio_final < precio_entrada

        beneficio = 1.0 if win else -1.0

        # 🔥 ENTRENAR IA
        if self.ai_engine:
            self.ai_engine.learn_from_result(win, direccion)

        return {
            'win': win,
            'beneficio': beneficio,
            'precio_final': precio_final,
            'duracion': (datetime.now() - inicio).total_seconds()
        }

# ==================================================


class SeguimientoSenales:
    """
    Sistema unificado de seguimiento de señales con dos modos:

    1. Modo Continuo: Monitorea múltiples pares simultáneamente
    2. Modo Binario: Una operación a la vez con seguimiento de estados

    Flujo Binario: DETECTADA → EN_SEGUIMIENTO → CONFIRMADA → EJECUTADA → WIN/LOSS/CANCELADA
    """

    def __init__(self, config, iq_bridge, motor_trading,
                 ai_engine=None, modo_binario=True):
        """
        Inicializa el sistema de seguimiento.

        Args:
            config: Configuración del sistema
            iq_bridge: Conexión con IQ Option
            motor_trading: Motor de trading para análisis
            ai_engine: Motor de IA (opcional)
            modo_binario: True para modo binario (una operación), False para modo continuo
        """
        self.config = config
        self.iq_bridge = iq_bridge
        self.motor_trading = motor_trading
        self.ai_engine = ai_engine
        self.modo_binario = modo_binario

        self.logger = logging.getLogger(__name__)
        self.trading_manager = getattr(self.iq_bridge, "trading_manager", None)
        self.notificaciones = getattr(self.iq_bridge, "notificaciones", None)
        if self.notificaciones is None:
            try:
                self.notificaciones = SistemaNotificaciones(
                    self.config, self.iq_bridge)
                try:
                    setattr(self.iq_bridge, "notificaciones", self.notificaciones)
                except Exception:
                    pass
            except Exception:
                self.notificaciones = None

        # Modo Continuo
        self.pares_activos = []
        self.senales_actuales = {}
        self.ultima_actualizacion = None
        self.en_ejecucion = False
        self.cache_velas = {}
        self.cache_timeout = 30

        # Modo Binario
        self.human_executor = HumanMouseExecutor()
        self.senales_activas_binario = {}
        self.historial_senales = []
        self.lock = threading.RLock()

        # Configuración común
        self.confirmaciones_requeridas = int(
            getattr(self.config, "AUTO_EJECUTAR_CONFIRMACIONES", 1) or 1)
        self.intervalo_verificacion = int(
            getattr(
                self.config,
                "AUTO_EJECUTAR_INTERVALO_VERIFICACION",
                5) or 5)

        # Cooldown y límites
        self._trades_timestamps = deque()
        self._dia_actual = datetime.now().date()
        self._ultimo_trade_por_par = {}
        self._trades_dia = 0
        self._ultimo_loss_ts = 0.0

        # Monitoreo binario
        self.monitoreo_binario_activo = False
        self.thread_monitoreo_binario = None

        # Estadísticas unificadas
        self.estadisticas = {
            "total_pares": 0,
            "pares_con_señal": 0,
            "señales_call": 0,
            "señales_put": 0,
            "ultima_operacion": None,
            "total_operaciones": 0,
            "ganadas": 0,
            "perdidas": 0,
            "beneficio_total": 0.0,
            "modo_actual": "BINARIO" if modo_binario else "CONTINUO"
        }

        self.logger.info(
            f"✅ Sistema de seguimiento inicializado - Modo: {
                'BINARIO' if modo_binario else 'CONTINUO'}")

    # ==================================================
    # MÉTODOS DEL MODO CONTINUO
    # ==================================================

    def iniciar_seguimiento(self):
        """Inicia el sistema de seguimiento según el modo configurado"""
        self.en_ejecucion = True

        if self.modo_binario:
            self.logger.info("🚀 Iniciando sistema de seguimiento BINARIO")
            # Modo binario: solo monitorea señales destacadas
            self._iniciar_monitoreo_binario()
        else:
            self.logger.info("🚀 Iniciando sistema de seguimiento CONTINUO")
            # Modo continuo: ciclo principal de múltiples pares
            self.actualizar_pares_activos()
            self._ciclo_principal_continuo()

    def detener_seguimiento(self):
        """Detiene el sistema de seguimiento"""
        self.en_ejecucion = False

        if self.modo_binario:
            self.monitoreo_binario_activo = False
            if self.thread_monitoreo_binario:
                self.thread_monitoreo_binario.join(timeout=5)
        self.logger.info("⏹️ Sistema de seguimiento detenido")

    def actualizar_pares_activos(self):
        """Actualiza la lista de pares activos desde el broker"""
        try:
            if self.iq_bridge and self.iq_bridge.api:
                if self.config.actualizar_pares_activos(self.iq_bridge.api):
                    self.pares_activos = self.config.PARES_TRADING
                    self.estadisticas["total_pares"] = len(self.pares_activos)
                    self.logger.info(
                        f"✅ Pares activos actualizados: {len(self.pares_activos)}")
                else:
                    self.pares_activos = self.config.PARES_14_DEFAULT[:10]
                    self.logger.warning(
                        f"Usando pares por defecto: {len(self.pares_activos)}")
        except Exception as e:
            self.logger.error(f"Error actualizando pares activos: {e}")
            self.pares_activos = self.config.PARES_14_DEFAULT[:10]

    def _ciclo_principal_continuo(self):
        """Ciclo principal para modo continuo"""
        while self.en_ejecucion and not self.modo_binario:
            try:
                inicio_ciclo = time.time()

                # Actualizar pares cada 5 minutos
                if not self.ultima_actualizacion or (
                        time.time() - self.ultima_actualizacion > 300):
                    self.actualizar_pares_activos()
                    self.ultima_actualizacion = time.time()

                # Procesar cada par activo
                senales_nuevas = {}
                contadores = {"call": 0, "put": 0, "wait": 0}

                for par in self.pares_activos[:20]:
                    if not self.en_ejecucion:
                        break

                    senal = self._obtener_senal_par(par)

                    if senal and senal.get("accion") in ["CALL", "PUT"]:
                        senales_nuevas[par] = senal

                        if senal["accion"] == "CALL":
                            contadores["call"] += 1
                        else:
                            contadores["put"] += 1
                    else:
                        contadores["wait"] += 1

                    time.sleep(0.1)

                # Actualizar señales
                self.senales_actuales = senales_nuevas
                self.estadisticas.update({
                    "pares_con_señal": len(senales_nuevas),
                    "señales_call": contadores["call"],
                    "señales_put": contadores["put"],
                    "ultima_actualizacion": datetime.now().isoformat()
                })

                # Actualizar GUI si está disponible
                if GUI_AVAILABLE and not HEADLESS_MODE:
                    self._actualizar_gui_senales()

                # Ejecutar operaciones automáticas
                if self.config.AUTO_TRADING_HABILITADO and not self.config.MODO_PAPER_TRADING:
                    self._evaluar_operaciones_automaticas()

                # Calcular tiempo del ciclo
                duracion_ciclo = time.time() - inicio_ciclo
                tiempo_espera = max(
                    5, self.config.INTERVALO_ESCANEO - duracion_ciclo)

                if tiempo_espera > 0:
                    time.sleep(tiempo_espera)

            except KeyboardInterrupt:
                self.detener_seguimiento()
                break
            except Exception as e:
                self.logger.error(
                    f"Error en ciclo principal: {e}",
                    exc_info=True)
                time.sleep(10)

    def _obtener_senal_par(self, par):
        """Obtiene señal para un par específico con multi-timeframe"""
        try:
            # Obtener datos para los 3 timeframes
            datos_tf = {"1m": None, "5m": None, "15m": None}
            tf_map = {"1m": 60, "5m": 300, "15m": 900}

            for tf_name, tf_seconds in tf_map.items():
                clave_cache = f"{par}_{tf_name}"

                # Verificar cache
                if clave_cache in self.cache_velas:
                    cache_entry = self.cache_velas[clave_cache]
                    if time.time() - \
                            cache_entry["timestamp"] < self.cache_timeout:
                        datos_tf[tf_name] = cache_entry["datos"]
                        continue

                # Obtener datos del broker
                if self.iq_bridge and self.iq_bridge.api:
                    velas = obtener_velas_seguras(
                        self.iq_bridge.api,
                        par,
                        tf_seconds,
                        self.config.MIN_CANDLES_REQUERIDAS,
                        None
                    )

                    if velas and len(velas) >= 10:
                        df = pd.DataFrame(velas)
                        if 'close' in df.columns and 'open' in df.columns and \
                           'high' in df.columns and 'low' in df.columns:
                            datos_tf[tf_name] = df
                            self.cache_velas[clave_cache] = {
                                "timestamp": time.time(),
                                "datos": df
                            }

            # Verificar datos
            datos_validos = [d for d in datos_tf.values() if d is not None]
            if len(datos_validos) < 2:
                return None

            # Usar timeframe principal (5m) para análisis
            df_principal = datos_tf.get("5m") or datos_tf.get(
                "1m") or datos_tf.get("15m")

            if df_principal is None or len(df_principal) < 20:
                return None

            # Calcular señal
            expiracion = self.config.TIEMPO_EXPIRACION * 60
            senal = self.motor_trading.calcular_senal_final(
                df_principal,
                expiracion_segundos=expiracion
            )

            if senal:
                senal["par"] = par
                senal["timestamp"] = datetime.now().isoformat()

                # Verificar confluencia multi-timeframe
                if datos_tf["1m"] is not None and datos_tf["5m"] is not None and datos_tf["15m"] is not None:
                    senal_1m = self.motor_trading.calcular_senal_final(
                        datos_tf["1m"], expiracion)
                    senal_5m = self.motor_trading.calcular_senal_final(
                        datos_tf["5m"], expiracion)
                    senal_15m = self.motor_trading.calcular_senal_final(
                        datos_tf["15m"], expiracion)

                    coincidencias = 0
                    if senal_1m.get("accion") == senal.get("accion"):
                        coincidencias += 1
                    if senal_5m.get("accion") == senal.get("accion"):
                        coincidencias += 1
                    if senal_15m.get("accion") == senal.get("accion"):
                        coincidencias += 1

                    senal["confluencia_tf"] = coincidencias
                    senal["alineacion_completa"] = coincidencias == 3

                    if coincidencias == 3 and senal.get("confianza", 0) < 95:
                        senal["confianza"] = min(99, senal["confianza"] + 10)
                        senal["motivo"] = f"{
                            senal.get(
                                'motivo',
                                '')} | CONFLUENCIA_1M_5M_15M"

            return senal

        except Exception as e:
            self.logger.error(f"Error obteniendo señal para {par}: {e}")
            return None

    def _evaluar_operaciones_automaticas(self):
        """Evalúa y ejecuta operaciones automáticas para modo continuo"""
        try:
            # Filtrar señales válidas para operar
            señales_operables = []

            for par, senal in self.senales_actuales.items():
                if senal.get("accion") not in ["CALL", "PUT"]:
                    continue

                if senal.get("confianza",
                             0) < self.config.AUTO_EJECUTAR_MIN_CONFIANZA:
                    continue

                if not senal.get("alineacion_completa", False):
                    continue

                señales_operables.append((par, senal))

            # Ordenar por confianza
            señales_operables.sort(
                key=lambda x: x[1].get(
                    "confianza", 0), reverse=True)

            # Tomar la mejor señal
            if señales_operables:
                mejor_par, mejor_senal = señales_operables[0]

                resultado = self.motor_trading.ejecutar_trade(
                    mejor_par,
                    mejor_senal,
                    self.config.TIEMPO_EXPIRACION * 60
                )

                if resultado:
                    self.logger.info(
                        f"✅ Operación automática ejecutada: {mejor_par} {
                            mejor_senal['accion']}")
                    self.estadisticas["ultima_operacion"] = {
                        "par": mejor_par,
                        "direccion": mejor_senal["accion"],
                        "confianza": mejor_senal["confianza"],
                        "timestamp": datetime.now().isoformat()
                    }

        except Exception as e:
            self.logger.error(f"Error en operaciones automáticas: {e}")

    # ==================================================
    # MÉTODOS DEL MODO BINARIO
    # ==================================================

    def registrar_senal_destacada(
            self, par, direccion, confianza, indicadores, precio_entrada):
        """Registra una señal destacada para modo binario"""
        with self.lock:
            # Modo binario solo permite una operación a la vez
            if self.senales_activas_binario or (self.iq_bridge.operacion_activa if hasattr(
                    self.iq_bridge, 'operacion_activa') else False):
                self.logger.info("⛔ Señal ignorada: operación binaria activa")
                return None

            senal_id = f"{par}_{datetime.now().strftime('%H%M%S')}"

            self.senales_activas_binario[par] = {
                'id': senal_id,
                'par': par,
                'direccion': direccion,
                'confianza_inicial': confianza,
                'confianza_actual': confianza,
                'precio_entrada': precio_entrada,
                'indicadores': indicadores,
                'estado': 'CONFIRMADA' if self.confirmaciones_requeridas <= 1 else 'EN_SEGUIMIENTO',
                'confirmaciones': self.confirmaciones_requeridas if self.confirmaciones_requeridas <= 1 else 1,
                'timestamp_inicio': datetime.now(),
                'order_id': None,
                'notificada_destacada': False,
                'notificada_confirmada': False
            }

        self.logger.info(
            f"[SEÑAL {senal_id}] {par} {direccion} EN SEGUIMIENTO ({
                confianza:.1f}%)")

        # Notificación
        try:
            if self.notificaciones:
                self.senales_activas_binario[par]['notificada_destacada'] = True
                self.notificaciones.notificar_senal_destacada(
                    par, direccion, float(confianza or 0))

                time.sleep(1)

                if self.confirmaciones_requeridas <= 1:
                    self.senales_activas_binario[par]['notificada_confirmada'] = True
                    self.notificaciones.notificar_senal_confirmada(
                        par, direccion, float(confianza or 0))

        except Exception as e:
            self.logger.warning(f"Error notificando señal a Telegram: {e}")

        self._iniciar_monitoreo_binario()
        return senal_id

    def _iniciar_monitoreo_binario(self):
        """Inicia el monitoreo para modo binario"""
        if self.monitoreo_binario_activo:
            return

        self.monitoreo_binario_activo = True
        self.thread_monitoreo_binario = threading.Thread(
            target=self._loop_monitoreo_binario, daemon=True
        )
        self.thread_monitoreo_binario.start()

    def _loop_monitoreo_binario(self):
        """Loop de monitoreo para modo binario"""
        while self.monitoreo_binario_activo:
            try:
                with self.lock:
                    pares = list(self.senales_activas_binario.keys())

                for par in pares:
                    self._procesar_senal_binaria(par)

                with self.lock:
                    if not self.senales_activas_binario:
                        self.monitoreo_binario_activo = False
                        break

                time.sleep(self.intervalo_verificacion)

            except Exception as e:
                self.logger.error(
                    f"Error monitoreo señales binarias: {e}",
                    exc_info=True)
                time.sleep(5)

    def _procesar_senal_binaria(self, par):
        """Procesa una señal en modo binario"""
        senal = self.senales_activas_binario.get(par)
        if not senal:
            return

        if senal['estado'] == 'EN_SEGUIMIENTO':
            self._verificar_confirmacion_binaria(par)
        elif senal['estado'] == 'CONFIRMADA':
            self._ejecutar_trade_binario(par)
        elif senal['estado'] == 'EJECUTADA':
            self._verificar_resultado_binario(par)

    def _verificar_confirmacion_binaria(self, par):
        """Verifica confirmación para modo binario"""
        if hasattr(self.iq_bridge,
                   'operacion_activa') and self.iq_bridge.operacion_activa:
            return

        df = self.iq_bridge.obtener_datos_tiempo_real(
            par, cantidad=60, timeframe="5"
        )
        if df is None or df.empty:
            return

        resultado = self.motor_trading.calcular_senal_final(
            df=df,
            expiracion_segundos=self.config.TIEMPO_EXPIRACION * 60
        )

        senal = self.senales_activas_binario.get(par)
        if not senal:
            return

        if resultado['accion'] == senal['direccion']:
            senal['confirmaciones'] += 1
            senal['confianza_actual'] = resultado['confianza']

            if senal['confirmaciones'] >= self.confirmaciones_requeridas:
                senal['estado'] = 'CONFIRMADA'
                self.logger.info(f"[SEÑAL {senal['id']}] CONFIRMADA")

                try:
                    if not bool(senal.get('notificada_confirmada')):
                        if self.notificaciones:
                            if not bool(senal.get('notificada_destacada')):
                                self.notificaciones.notificar_senal_destacada(
                                    par, senal.get('direccion', ''),
                                    float(senal.get('confianza_actual', 0) or 0))
                                senal['notificada_destacada'] = True
                                time.sleep(1)

                            senal['notificada_confirmada'] = True
                            self.notificaciones.notificar_senal_confirmada(
                                par, senal.get('direccion', ''),
                                float(senal.get('confianza_actual', 0) or 0))
                except Exception as e:
                    self.logger.warning(
                        f"Error notificando confirmación a Telegram: {e}")

    def _ejecutar_trade_binario(self, par):
        """Ejecuta trade en modo binario"""
        with self.lock:
            senal = self.senales_activas_binario.get(par)
            if not senal:
                return

        # Verificar condiciones
        if getattr(self.config, "KILL_SWITCH", False):
            return
        if getattr(self.config, "PAUSADO_POR_OBJETIVO", False):
            return
        if not getattr(self.config, "AUTO_TRADING_HABILITADO", False):
            return

        # Modo Paper Trading
        if self.config.MODO_PAPER_TRADING:
            self.logger.info(f"🧪 PAPER TRADING → {par} {senal['direccion']}")

            precio_entrada = self.iq_bridge.obtener_precio_actual(par)
            if precio_entrada is None:
                self.logger.warning(
                    "No se pudo obtener precio de entrada real")
                return

            paper_engine = PaperTradingEngine(
                iq_bridge=self.iq_bridge,
                ai_engine=self.motor_trading.ai_engine if hasattr(
                    self.motor_trading, 'ai_engine') else None
            )

            resultado = paper_engine.ejecutar(
                par=par,
                direccion=senal['direccion'],
                precio_entrada=precio_entrada,
                expiracion_segundos=self.config.TIEMPO_EXPIRACION * 60
            )

            if resultado is None:
                self.logger.warning("Resultado PAPER inválido")
                return

            estado_final = 'WIN' if resultado['win'] else 'LOSS'

            with self.lock:
                self._actualizar_estadisticas_binario(
                    estado_final, resultado['beneficio'])
                del self.senales_activas_binario[par]

            return

        # Modo Producción
        if not getattr(self.config, "MODO_PRODUCCION", False):
            return
        if getattr(self.config, "DRY_RUN", False):
            return
        if not getattr(self.config, "AUTO_EJECUTAR_BROKER", False):
            return

        # Verificar límites y cooldown
        ahora = datetime.now()
        hoy = ahora.date()
        if hoy != self._dia_actual:
            self._dia_actual = hoy
            self._trades_timestamps.clear()
            self._ultimo_trade_por_par.clear()
            self._trades_dia = 0
        # Cooldown post pérdida global (anti-congelamiento y sobreoperación)
        cd_loss = int(getattr(self.config, "COOLDOWN_POST_LOSS_SEC", 0) or 0)
        if cd_loss > 0 and float(self._ultimo_loss_ts or 0) > 0:
            if (datetime.now().timestamp() - float(self._ultimo_loss_ts)) < cd_loss:
                return

        max_hora = int(getattr(self.config, "MAX_TRADES_POR_HORA", 0) or 0)
        max_dia = int(getattr(self.config, "MAX_TRADES_POR_DIA", 0) or 0)
        while self._trades_timestamps and (
                ahora - self._trades_timestamps[0]).total_seconds() > 3600:
            self._trades_timestamps.popleft()
        if max_hora > 0 and len(self._trades_timestamps) >= max_hora:
            return
        if max_dia > 0 and int(self._trades_dia) >= max_dia:
            return

        cooldown_par = int(
            getattr(
                self.config,
                "AUTO_EJECUTAR_COOLDOWN_PAR_SEG",
                0) or 0)
        ultimo = self._ultimo_trade_por_par.get(par)
        if ultimo and cooldown_par > 0 and (
                ahora - ultimo).total_seconds() < cooldown_par:
            return

        # Verificar conexión
        if not (getattr(self.iq_bridge, "connected", False)
                and getattr(self.iq_bridge, "api", None)):
            return
        if not self.iq_bridge.verificar_activo_operable(par):
            return

        # Calcular monto
        monto = float(
            getattr(
                self.config,
                "LOTE_SIZE_ACTUAL",
                getattr(
                    self.config,
                    "MONTO_OPERACION",
                    1.0)) or 1.0)
        if getattr(self.config, "INTERES_COMPUESTO_ACTIVO", False):
            try:
                porcentaje = float(
                    getattr(
                        self.config,
                        "PORCENTAJE_INVERSION",
                        0.1) or 0.1)
                monto_calc = int(
                    float(
                        getattr(
                            self.iq_bridge,
                            "balance_actual",
                            0.0) or 0.0) *
                    porcentaje)
                monto = float(max(1, monto_calc))
            except Exception:
                pass

        # Ejecutar orden
        duracion = int(getattr(self.config, "TIEMPO_EXPIRACION", 5) or 5)
        order_id = self.human_executor.ejecutar_orden_humana(
            self.iq_bridge.api,
            par,
            senal['direccion'],
            monto,
            duracion
        )

        if not order_id:
            with self.lock:
                senal['estado'] = 'CANCELADA'
                if par in self.senales_activas_binario:
                    del self.senales_activas_binario[par]
            return

        # Registrar operación
        if hasattr(self.iq_bridge, 'abrir_operacion'):
            self.iq_bridge.abrir_operacion(
                order_id, par, senal['direccion'], monto, duracion)

        with self.lock:
            if par in self.senales_activas_binario:
                self.senales_activas_binario[par]['order_id'] = order_id
                self.senales_activas_binario[par]['monto'] = monto
                self.senales_activas_binario[par]['estado'] = 'EJECUTADA'

        self._trades_timestamps.append(ahora)
        self._ultimo_trade_por_par[par] = ahora
        self._trades_dia += 1

    def _verificar_resultado_binario(self, par):
        """Verifica resultado de operación en modo binario"""
        senal = self.senales_activas_binario.get(par)
        if not senal:
            return

        # Verificar resultado del broker
        beneficio = None
        if hasattr(self.iq_bridge, 'verificar_resultado_operacion'):
            beneficio = self.iq_bridge.verificar_resultado_operacion(
                senal['order_id'])

        if beneficio is None:
            return

        # Determinar estado final
        is_win = beneficio > 0
        estado_final = 'WIN' if is_win else 'LOSS'
        if not is_win:
            self._ultimo_loss_ts = datetime.now().timestamp()

        # Actualizar estadísticas
        with self.lock:
            self._actualizar_estadisticas_binario(estado_final, beneficio)

        # Notificación
        if getattr(self.config, "TELEGRAM_HABILITADO", False):
            try:
                sesion = {}
                if self.iq_bridge and hasattr(
                        self.iq_bridge, '_actualizar_win_loss_sesion'):
                    sesion = self.iq_bridge._actualizar_win_loss_sesion(is_win) or {
                    }
                telegram = TelegramNotifier(self.config, self.iq_bridge)
                telegram.enviar_resultado(
                    par,
                    senal.get('direccion', ''),
                    is_win,
                    float(beneficio),
                    sesion.get("wins"),
                    sesion.get("losses"),
                )
            except Exception as e:
                self.logger.warning(
                    f"Error enviando resultado a Telegram: {e}")

        self.logger.info(
            f"[SEÑAL {
                senal['id']}] RESULTADO → {estado_final} | Beneficio={
                round(
                    beneficio,
                    2)}")

        try:
            tm = getattr(self, "trading_manager", None)
            if tm is not None:
                inicio = senal.get('timestamp_inicio')
                expiracion = inicio + timedelta(
                    minutes=self.config.TIEMPO_EXPIRACION) if inicio else None
                operacion_cerrada = {
                    'order_id': senal.get('order_id'),
                    'simbolo': par,
                    'tipo': senal.get('direccion', '').upper(),
                    'monto': float(senal.get('monto', 0) or 0),
                    'confianza': float(senal.get('confianza_actual', 0) or 0),
                    'beneficio': float(beneficio),
                    'fecha_apertura': inicio,
                    'expiracion': expiracion,
                    'fecha_cierre': datetime.now(),
                    'motivo_cierre': estado_final
                }
                with tm.lock:
                    tm.operaciones_cerradas.append(operacion_cerrada)
                tm._guardar_operaciones_cerradas()
        except Exception:
            pass

        # Feedback a la IA
        try:
            if self.ai_engine:
                if cumple_filtro_aprendizaje(self.config, senal.get("direccion"),
                                             senal.get("indicadores", {}) or {}):
                    self.ai_engine.learn_from_result(
                        is_win, senal.get("direccion"))
        except Exception as e:
            self.logger.error(
                f"❌ Error enviando feedback a IA: {e}",
                exc_info=True)

        # Cerrar operación y limpiar
        try:
            if hasattr(self.iq_bridge, 'cerrar_operacion'):
                self.iq_bridge.cerrar_operacion()
            if hasattr(self.iq_bridge, 'operacion_activa'):
                self.iq_bridge.operacion_activa = False
        except Exception:
            pass

        with self.lock:
            if par in self.senales_activas_binario:
                del self.senales_activas_binario[par]

    def _actualizar_estadisticas_binario(self, estado, beneficio):
        """Actualiza estadísticas para modo binario"""
        self.estadisticas['total_operaciones'] += 1
        self.estadisticas['beneficio_total'] += beneficio

        if estado == 'WIN':
            self.estadisticas['ganadas'] += 1
        else:
            self.estadisticas['perdidas'] += 1

    # ==================================================
    # MÉTODOS COMUNES
    # ==================================================

    def _actualizar_gui_pares(self):
        """Actualiza lista de pares en GUI"""
        if not GUI_AVAILABLE or HEADLESS_MODE:
            return

        try:
            app = QApplication.instance()
            if app:
                for widget in app.topLevelWidgets():
                    if hasattr(widget, 'actualizar_lista_pares'):
                        widget.actualizar_lista_pares(self.pares_activos)
                        break
        except BaseException:
            pass

    def _actualizar_gui_senales(self):
        """Actualiza tabla de señales en GUI"""
        if not GUI_AVAILABLE or HEADLESS_MODE:
            return

        try:
            app = QApplication.instance()
            if app:
                for widget in app.topLevelWidgets():
                    if hasattr(widget, 'actualizar_tabla_senales'):
                        datos_tabla = []
                        for par, senal in self.senales_actuales.items():
                            datos_tabla.append({
                                "par": par,
                                "senal": senal.get("accion", "WAIT"),
                                "confianza": f"{senal.get('confianza', 0):.1f}%",
                                "tipo": senal.get("tipo_senal", "DEBIL"),
                                "confluencia": senal.get("confluencia_tf", 0),
                                "hora": datetime.now().strftime("%H:%M:%S")
                            })

                        widget.actualizar_tabla_senales(datos_tabla)
                        break
        except BaseException:
            pass

    def obtener_resumen(self):
        """Retorna resumen actual del sistema"""
        resumen = {
            "estado": "ACTIVO" if self.en_ejecucion else "DETENIDO",
            "modo": "BINARIO" if self.modo_binario else "CONTINUO",
            "ultima_actualizacion": self.ultima_actualizacion,
            "estadisticas": self.estadisticas.copy()
        }

        if self.modo_binario:
            resumen.update({
                "senales_binario_activas": len(self.senales_activas_binario),
                "monitoreo_binario": "ACTIVO" if self.monitoreo_binario_activo else "INACTIVO"
            })
        else:
            resumen.update({
                "pares_monitoreados": len(self.pares_activos),
                "senales_activas": len(self.senales_actuales)
            })

        return resumen

    def cambiar_modo(self, nuevo_modo):
        """Cambia entre modo binario y continuo"""
        if nuevo_modo not in ["BINARIO", "CONTINUO"]:
            raise ValueError("Modo debe ser 'BINARIO' o 'CONTINUO'")

        # Detener modo actual
        self.detener_seguimiento()

        # Cambiar modo
        self.modo_binario = (nuevo_modo == "BINARIO")
        self.estadisticas["modo_actual"] = nuevo_modo

        # Limpiar estructuras del modo anterior
        if nuevo_modo == "BINARIO":
            self.senales_actuales.clear()
            self.pares_activos.clear()
        else:
            self.senales_activas_binario.clear()
            self.historial_senales.clear()

        self.logger.info(f"🔄 Modo cambiado a: {nuevo_modo}")

        # Reiniciar en nuevo modo
        self.iniciar_seguimiento()
# ========== AUTO-TRAINER (REENTRENAMIENTO AUTOMATICO) ==========
# CAPITULO 19:
# ==================================================


class AutoTrainer:
    """
    Sistema de autoaprendizaje que reentrena el modelo según el perfil activo:
    - REGULAR: Entrenamiento con 90 días de datos (Lunes-Viernes)
    - OTC: Entrenamiento con 24 horas de datos (Fines de semana)
    """

    def __init__(self, operations_repo: OperationsRepository,
                 config: 'ConfiguracionTrading'):
        self.operations_repo = operations_repo
        self.config = config
        self.ultimo_entrenamiento = None
        # Mínimo de trades para reentrenar se camnio el 50 por 5
        self.min_trades_para_entrenar = 5
        self.modelo_actual = None
        self.precision_objetivo = 0.92
        self.precision_actual = 0.5
        self.perfil_actual = None
        self.escalador = None
        self.n_features = None
        # Rutas dinámicas según perfil
        self._actualizar_rutas_segun_perfil()
        # Cargar modelo existente si hay
        self._cargar_modelo()

    def _actualizar_rutas_segun_perfil(self):
        """Actualiza las rutas de modelo según el perfil activo"""
        modo_actual = market_resolver.obtener_modo_actual()
        self.perfil_actual = modo_actual
        if modo_actual == "OTC":
            perfil = getattr(self.config, "PERFIL_OTC", None)
            if not perfil:
                perfil = {
                    "modelo_path": datos_rel("modelo_OTC.pth"),
                    "escalador_path": datos_rel("escalador_OTC.pkl"),
                    "intervalo_reentrenamiento_horas": 6,
                    "min_datos": 15,
                }
        else:
            perfil = getattr(self.config, "PERFIL_REGULAR", None)
            if not perfil:
                perfil = {
                    "modelo_path": datos_rel("modelo_REGULAR.pth"),
                    "escalador_path": datos_rel("escalador_REGULAR.pkl"),
                    "intervalo_reentrenamiento_horas": 24,
                    "min_datos": 15,
                }
        self.MODELO_PATH = perfil["modelo_path"]
        self.ESCALADOR_PATH = perfil["escalador_path"]
        self.intervalo_horas = perfil["intervalo_reentrenamiento_horas"]
        self.min_datos = perfil["min_datos"]
        logger.info(
            f"AutoTrainer configurado para perfil {modo_actual}: modelo={
                self.MODELO_PATH}")

    def verificar_y_entrenar(self) -> bool:
        """
        Verifica si es necesario reentrenar y lo hace si corresponde.
        Retorna True si se realizó entrenamiento.
        """
        try:
            ahora = datetime.now()
            # Verificar si es tiempo de reentrenar
            if self.ultimo_entrenamiento is not None:
                horas_desde_ultimo = (
                    ahora - self.ultimo_entrenamiento).total_seconds() / 3600
                if horas_desde_ultimo < self.intervalo_horas:
                    return False

            # Verificar si hay suficientes trades
            stats = self.operations_repo.obtener_estadisticas()
            if stats.get('total_trades', 0) < self.min_trades_para_entrenar:
                logger.info(
                    f"Insuficientes trades para reentrenar ({
                        stats.get(
                            'total_trades', 0)}/{
                        self.min_trades_para_entrenar})")
                return False

            logger.info("Iniciando reentrenamiento automático...")
            # Preparar datos de entrenamiento
            dataset = self._preparar_dataset()
            if dataset is None or len(dataset) < self.min_trades_para_entrenar:
                logger.warning("Dataset insuficiente para entrenamiento")
                return False

            # Entrenar modelo
            exito = self._entrenar_modelo(dataset)
            if exito:
                self.ultimo_entrenamiento = ahora
                logger.info("Reentrenamiento completado exitosamente")
                return True
            return False
        except Exception as e:
            logger.error(f"Error en verificar_y_entrenar: {e}")
            return False

    def _preparar_dataset(self) -> Optional[pd.DataFrame]:
        """Prepara dataset de entrenamiento desde trades históricos con características extendidas"""
        try:
            trades = self.operations_repo.trades
            if not trades:
                return None

            # Convertir trades a DataFrame con características extendidas
            registros = []
            for trade in trades:
                indicadores = trade.get('indicadores', {})
                # Características principales
                rsi = indicadores.get('RSI', 50)
                macd = indicadores.get('MACD', 0)
                macd_hist = indicadores.get('MACD_hist', 0)
                stoch_k = indicadores.get('stoch_k', 50)
                stoch_d = indicadores.get('stoch_d', 50)
                atr = indicadores.get('ATR', 0)
                momentum = indicadores.get('momentum', 0)
                tendencia = indicadores.get('tendencia', 0)
                fuerza_senal = indicadores.get('fuerza_senal', 0)
                # EMAs y TDI
                ema_21 = indicadores.get(
                    'ema_21', indicadores.get(
                        'EMA_21', 0))
                ema_50 = indicadores.get(
                    'ema_50', indicadores.get(
                        'EMA_50', 0))
                tdi_rsi = indicadores.get(
                    'tdi_rsi', indicadores.get(
                        'TDI_rsi', 50))
                tdi_precio = indicadores.get(
                    'tdi_precio_linea', indicadores.get(
                        'TDI_precio', 50))
                tdi_senal = indicadores.get(
                    'tdi_senal_linea', indicadores.get(
                        'TDI_senal', 50))

                # Características derivadas para mejorar la predicción
                # Sobrecompra/venta
                rsi_zona = 1 if rsi > 70 else (-1 if rsi < 30 else 0)
                macd_cruce = 1 if macd > 0 and macd_hist > 0 else (
                    -1 if macd < 0 and macd_hist < 0 else 0)
                stoch_cruce = 1 if stoch_k > stoch_d else -1
                ema_tendencia = 1 if ema_21 > ema_50 else (
                    -1 if ema_21 < ema_50 else 0)
                tdi_direccion = 1 if tdi_precio > tdi_senal else -1
                # Volatilidad normalizada
                volatilidad = min(atr * 100, 5)  # Limitar para evitar outliers

                registros.append({
                    'RSI': rsi,
                    'RSI_zona': rsi_zona,
                    'RSI_distancia_50': abs(rsi - 50),
                    'MACD': macd,
                    'MACD_hist': macd_hist,
                    'MACD_cruce': macd_cruce,
                    'stoch_k': stoch_k,
                    'stoch_d': stoch_d,
                    'stoch_cruce': stoch_cruce,
                    'stoch_diferencia': stoch_k - stoch_d,
                    'ATR': atr,
                    'volatilidad': volatilidad,
                    'momentum': momentum,
                    'tendencia': tendencia,
                    'fuerza_senal': fuerza_senal,
                    'EMA_tendencia': ema_tendencia,
                    'EMA_diferencia': ema_21 - ema_50 if ema_21 and ema_50 else 0,
                    'TDI_rsi': tdi_rsi,
                    'TDI_direccion': tdi_direccion,
                    'TDI_fuerza': abs(tdi_precio - tdi_senal),
                    'direccion': 1 if str(trade.get('direccion', '')).upper() == 'CALL' else (0 if str(trade.get('direccion', '')).upper() == 'PUT' else 0.5),
                    'exitoso': 1 if trade.get('exitoso', False) else 0
                })

            df = pd.DataFrame(registros)
            # Balancear dataset con SMOTE-like approach
            exitosos = df[df['exitoso'] == 1]
            fallidos = df[df['exitoso'] == 0]
            logger.info(
                f"Trades exitosos: {
                    len(exitosos)}, Trades fallidos: {
                    len(fallidos)}")

            if len(exitosos) == 0 and len(fallidos) == 0:
                logger.warning("No hay trades para entrenar")
                return None
            if len(exitosos) == 0 or len(fallidos) == 0:
                logger.info(
                    "Dataset con una sola clase (solo wins o solo losses). Esperando más trades reales para entrenar.")
                return None

            # Sobremuestrear la clase minoritaria con variación
            ratio_min = 0.4  # Al menos 40% de cada clase
            total_objetivo = max(len(exitosos), len(fallidos)) * 2
            if len(exitosos) > len(fallidos) and len(fallidos) > 0:
                n_necesarios = max(
                    int(total_objetivo * ratio_min), len(fallidos))
                fallidos_aug = fallidos.sample(
                    n=n_necesarios, replace=True, random_state=42)
                # Añadir pequeño ruido a las muestras duplicadas
                for col in fallidos_aug.select_dtypes(
                        include=[np.number]).columns:
                    if col != 'exitoso':
                        fallidos_aug[col] = fallidos_aug[col] + np.random.normal(
                            0, 0.05, len(fallidos_aug)) * fallidos_aug[col].std()
                fallidos = fallidos_aug
            elif len(fallidos) > len(exitosos) and len(exitosos) > 0:
                n_necesarios = max(
                    int(total_objetivo * ratio_min), len(exitosos))
                exitosos_aug = exitosos.sample(
                    n=n_necesarios, replace=True, random_state=42)
                for col in exitosos_aug.select_dtypes(
                        include=[np.number]).columns:
                    if col != 'exitoso':
                        exitosos_aug[col] = exitosos_aug[col] + np.random.normal(
                            0, 0.05, len(exitosos_aug)) * exitosos_aug[col].std()
                exitosos = exitosos_aug

            df_balanceado = pd.concat([exitosos, fallidos]).sample(
                frac=1, random_state=42).reset_index(drop=True)
            logger.info(
                f"Dataset preparado: {
                    len(df_balanceado)} muestras balanceadas")
            logger.info(
                f"Distribución final - Exitosos: {len(df_balanceado[df_balanceado['exitoso'] == 1])}, Fallidos: {len(df_balanceado[df_balanceado['exitoso'] == 0])}")
            return df_balanceado
        except Exception as e:
            logger.error(f"Error preparando dataset: {e}")
            logger.error(traceback.format_exc())
            return None

    def _entrenar_modelo(self, dataset: pd.DataFrame) -> bool:
        """Entrena el modelo OPTIMIZADO para bajo consumo de recursos (CPU-only, poca RAM)"""
        try:
            if not TORCH_AVAILABLE:
                logger.warning("PyTorch no disponible, entrenamiento omitido")
                return False

            import torch
            import torch.nn as nn
            import torch.optim as optim
            import torch.nn.functional as F
            from torch.utils.data import DataLoader, TensorDataset
            import pickle
            import gc

            # ========== OPTIMIZACIÓN PARA BAJO CONSUMO ==========
            MAX_MUESTRAS = 2000  # Limitar dataset para poca RAM
            EPOCHS_RAPIDO = 50  # Epochs reducidos
            BATCH_SIZE_LIGERO = 16  # Batch pequeño
            PACIENCIA_RAPIDA = 5  # Early stopping agresivo

            logger.info(
                f"[ENTRENAMIENTO LIGERO] Max muestras: {MAX_MUESTRAS}, Epochs: {EPOCHS_RAPIDO}, Batch: {BATCH_SIZE_LIGERO}")

            # Limitar tamaño del dataset
            if len(dataset) > MAX_MUESTRAS:
                logger.info(
                    f"Reduciendo dataset de {
                        len(dataset)} a {MAX_MUESTRAS} muestras")
                dataset = dataset.sample(
                    n=MAX_MUESTRAS,
                    random_state=42).reset_index(
                    drop=True)
                gc.collect()  # Liberar memoria

            # Características principales
            features = [
                'RSI', 'RSI_zona',
                'MACD', 'MACD_hist',
                'stoch_k', 'stoch_d',
                'ATR', 'volatilidad',
                'momentum', 'tendencia',
                'TDI_rsi', 'EMA_tendencia'
            ]
            # Filtrar solo las columnas que existen
            features_disponibles = [
                f for f in features if f in dataset.columns]
            logger.info(
                f"Características disponibles: {len(features_disponibles)}/{len(features)}")

            X = dataset[features_disponibles].values.astype(np.float32)
            y = dataset['exitoso'].values.astype(
                np.float32)  # ✅ FLOAT32 (para BCE)

            # Normalización robusta con guardado del escalador
            X_mean = X.mean(axis=0)
            X_std = X.std(axis=0) + 1e-8
            X_normalized = (X - X_mean) / X_std

            self.escalador = {
                'mean': X_mean,
                'std': X_std,
                'features': features_disponibles,
                'n_features': len(features_disponibles),
                'perfil': self.perfil_actual,
                'fecha_entrenamiento': datetime.now().isoformat()
            }
            try:
                ruta_escalador = getattr(
                    self, 'ESCALADOR_PATH', datos_rel('escalador_Binary.pkl'))
                with open(ruta_escalador, 'wb') as f:
                    pickle.dump(self.escalador, f)
                logger.info(
                    f"Escalador guardado en {ruta_escalador} (perfil: {
                        self.perfil_actual})")
            except Exception as e:
                logger.warning(f"No se pudo guardar escalador: {e}")

            # Dividir en train/val con estratificación
            indices = np.random.permutation(len(X_normalized))
            split_idx = int(len(X_normalized) * 0.8)
            train_idx, val_idx = indices[:split_idx], indices[split_idx:]
            X_train, X_val = X_normalized[train_idx], X_normalized[val_idx]
            y_train, y_val = y[train_idx], y[val_idx]
            logger.info(f"Train: {len(X_train)}, Val: {len(X_val)}")

            # Crear DataLoaders con batch pequeño para bajo consumo de RAM
            train_dataset = TensorDataset(
                torch.FloatTensor(X_train),
                torch.FloatTensor(y_train))
            train_loader = DataLoader(
                train_dataset,
                batch_size=BATCH_SIZE_LIGERO,
                shuffle=True,
                drop_last=True)
            n_features = len(features_disponibles)

            # Calcular peso de clase para balanceo
            n_positivos = y_train.sum()
            n_negativos = len(y_train) - n_positivos
            peso_positivo = n_negativos / (n_positivos + 1e-8)
            # Limitar entre 0.5 y 2.0
            peso_positivo = min(max(peso_positivo, 0.5), 2.0)
            logger.info(
                f"Balanceo de clases: {
                    n_positivos:.0f} positivos, {
                    n_negativos:.0f} negativos, peso={
                    peso_positivo:.2f}")

            # Arquitectura LIGERA para bajo consumo de recursos
            class RedNeuronalBinary(nn.Module):
                def __init__(self, input_dim, capas_ocultas):
                    super().__init__()
                    layers = []
                    prev_size = input_dim
                    for i, size in enumerate(capas_ocultas):
                        layers.extend([
                            nn.Linear(prev_size, size),
                            nn.BatchNorm1d(size),
                            nn.LeakyReLU(0.1),
                            nn.Dropout(0.25 if i > 0 else 0.125)
                        ])
                        prev_size = size
                    # Capa de salida: 1 neurona con Sigmoid para probabilidad
                    # de CALL
                    layers.append(nn.Linear(prev_size, 1))
                    layers.append(nn.Sigmoid())
                    self.red = nn.Sequential(*layers)

                def forward(self, x):
                    return self.red(x)

            capas_ocultas = [32, 16, 8]  # Arquitectura simplificada
            modelo = RedNeuronalBinary(n_features, capas_ocultas)

            pos_weight = float(peso_positivo)

            # Optimizador simple para entrenamiento rápido
            optimizer = optim.Adam(modelo.parameters(), lr=0.001)

            # Scheduler más agresivo para converger rápido
            scheduler = optim.lr_scheduler.ReduceLROnPlateau(
                optimizer, mode='max', factor=0.5, patience=3, verbose=False, min_lr=1e-5
            )

            # Entrenar con epochs reducidos y early stopping agresivo
            epochs = EPOCHS_RAPIDO
            mejor_loss = float('inf')
            mejor_modelo_state = None
            mejor_precision = 0.0
            sin_mejora = 0
            paciencia = PACIENCIA_RAPIDA

            logger.info(
                f"Iniciando entrenamiento: {epochs} epochs, paciencia={paciencia}")
            for epoch in range(epochs):
                modelo.train()
                train_loss = 0
                for batch_X, batch_y in train_loader:
                    optimizer.zero_grad()
                    outputs = modelo(batch_X)
                    weights = torch.ones_like(batch_y)
                    if pos_weight != 1.0:
                        weights = torch.where(
                            batch_y >= 0.5, torch.full_like(
                                batch_y, pos_weight), weights)
                    loss = F.binary_cross_entropy(
                        outputs.squeeze(-1), batch_y, weight=weights)
                    loss.backward()
                    # Gradient clipping para estabilidad
                    torch.nn.utils.clip_grad_norm_(
                        modelo.parameters(), max_norm=1.0)
                    optimizer.step()
                    train_loss += loss.item()

                # Validar cada 5 epochs
                if (epoch + 1) % 5 == 0:
                    modelo.eval()
                    with torch.no_grad():
                        val_outputs = modelo(
                            torch.FloatTensor(X_val)).squeeze(-1)
                        val_preds = (val_outputs >= 0.5).long()
                        val_true = (torch.FloatTensor(y_val) >= 0.5).long()
                        precision = (
                            val_preds == val_true).float().mean().item()

                        # Calcular métricas detalladas
                        tp = ((val_preds == 1) & (val_true == 1)).sum().item()
                        tn = ((val_preds == 0) & (val_true == 0)).sum().item()
                        fp = ((val_preds == 1) & (val_true == 0)).sum().item()
                        fn = ((val_preds == 0) & (val_true == 1)).sum().item()
                        precision_pos = tp / (tp + fp + 1e-8)
                        recall = tp / (tp + fn + 1e-8)
                        f1 = 2 * precision_pos * recall / \
                            (precision_pos + recall + 1e-8)

                        # Usar F1 como métrica principal para el scheduler
                        scheduler.step(f1)

                        # Guardar si mejora precisión
                        if precision > mejor_precision:
                            mejor_precision = precision
                            mejor_modelo_state = modelo.state_dict().copy()
                            self.modelo_actual = modelo
                            sin_mejora = 0
                        else:
                            sin_mejora += 1

                        avg_loss = train_loss / len(train_loader)
                        logger.info(f"Epoch {epoch + 1}/{epochs} | Loss: {avg_loss:.4f} | "
                                    f"Precision: {precision:.1%} | F1: {f1:.3f}")

                        # Early stopping agresivo para entrenamiento rápido
                        if sin_mejora >= paciencia:
                            logger.info(
                                f"Early stopping en epoch {
                                    epoch +
                                    1} con precisión {
                                    mejor_precision:.1%}")
                            break

                # Liberar memoria periódicamente
                if (epoch + 1) % 10 == 0:
                    gc.collect()

            # Restaurar mejor modelo
            if mejor_modelo_state is not None:
                modelo.load_state_dict(mejor_modelo_state)
                self.modelo_actual = modelo
                logger.info(
                    f"Mejor precisión alcanzada: {
                        mejor_precision:.1%}")

            # 🎯 BONUS: GUARDAR MODELO CON n_features Y METADATA COMPLETA
            if mejor_precision > self.precision_actual:
                self.precision_actual = mejor_precision
                self.n_features = n_features

                # Rutas dinámicas según perfil
                self._actualizar_rutas_segun_perfil()
                ruta_modelo = getattr(
                    self, 'MODELO_PATH', datos_rel('modelo_Binary.pth'))

                # Hash ligero de configuración para detectar cambios
                import hashlib
                config_hash = hashlib.md5(
                    str(self.config.__dict__).encode()).hexdigest()[:8]

                # ✅ CHECKPOINT COMPLETO CON VALIDACIÓN ROBUSTA
                checkpoint = {
                    'model_state_dict': modelo.state_dict(),
                    'precision': mejor_precision,
                    'ultimo_entrenamiento': datetime.now().isoformat(),
                    'n_features': n_features,
                    'features': features_disponibles,
                    'perfil': self.perfil_actual,
                    'arquitectura': 'ligera_v1',
                    'version': '2.1',
                    'config_hash': config_hash,
                    'epocas_entrenadas': epoch + 1,
                    'balance_positivos': n_positivos,
                    'balance_negativos': n_negativos,
                }
                try:
                    torch.save(checkpoint, ruta_modelo)
                    logger.info(
                        f"✅ Modelo guardado en {ruta_modelo} con {n_features} features ({
                            self.perfil_actual})")
                    logger.info(f"   Features: {features_disponibles}")
                    logger.info(f"   Precisión: {mejor_precision:.2%}")
                    return True
                except Exception as e:
                    logger.error(f"❌ Error guardando modelo: {e}")
                    return False
            return mejor_precision >= self.precision_objetivo * 0.9  # 90% del objetivo
        except Exception as e:
            logger.error(f"Error entrenando modelo: {e}")
            logger.error(traceback.format_exc())
            return False

    def obtener_modelo(self):
        """Retorna el modelo entrenado actual"""
        if self.modelo_actual is None:
            return None
        return {
            "model": self.modelo_actual,
            "scaler": getattr(self, "escalador", None),
            "n_features": getattr(self, "n_features", None),
            "perfil": getattr(self, "perfil_actual", None),
        }

    def _guardar_modelo(self):
        """Guarda el modelo entrenado a disco con arquitectura y escalador según perfil"""
        try:
            if TORCH_AVAILABLE and self.modelo_actual is not None:
                import torch
                import pickle
                # Actualizar rutas según perfil actual
                self._actualizar_rutas_segun_perfil()
                # Guardar modelo con información de arquitectura y perfil
                n_features = int(getattr(self, 'n_features', 0) or 0)
                features = None
                if isinstance(getattr(self, "escalador", None), dict):
                    features = self.escalador.get("features")
                    if not n_features:
                        try:
                            n_features = int(
                                self.escalador.get("n_features") or 0)
                        except Exception:
                            n_features = 0
                checkpoint = {
                    'model_state_dict': self.modelo_actual.state_dict(),
                    'precision': float(getattr(self, "precision_actual", 0.0) or 0.0),
                    'ultimo_entrenamiento': (self.ultimo_entrenamiento.isoformat() if self.ultimo_entrenamiento else datetime.now().isoformat()),
                    'n_features': n_features,
                    'features': features,
                    'perfil': getattr(self, "perfil_actual", "UNKNOWN"),
                    'arquitectura': 'ligera_v1',
                    'version': '2.1',
                }
                torch.save(checkpoint, self.MODELO_PATH)
                logger.info(
                    f"Modelo guardado en {
                        self.MODELO_PATH} (perfil: {
                        self.perfil_actual}) con precisión {
                        self.precision_actual:.1%}")
                # Guardar escalador si existe
                if hasattr(self, 'escalador'):
                    try:
                        escalador_path = getattr(
                            self, 'ESCALADOR_PATH', datos_rel('escalador_Binary.pkl'))
                        with open(escalador_path, 'wb') as f:
                            pickle.dump(self.escalador, f)
                        logger.info(f"Escalador guardado en {escalador_path}")
                    except Exception as e:
                        logger.warning(f"No se pudo guardar escalador: {e}")
            else:
                logger.warning(
                    "No se puede guardar modelo: PyTorch no disponible o modelo no entrenado")
        except Exception as e:
            logger.error(f"Error guardando modelo: {e}")

    def _cargar_modelo(self):
        """Carga el modelo desde disco según perfil activo con soporte para nueva arquitectura"""
        try:
            # Actualizar rutas según perfil actual
            self._actualizar_rutas_segun_perfil()
            if TORCH_AVAILABLE and os.path.exists(self.MODELO_PATH):
                import torch
                import torch.nn as nn
                import pickle
                # Cargar solo pesos para seguridad
                checkpoint = torch.load(self.MODELO_PATH, weights_only=True)
                arquitectura = checkpoint.get('arquitectura', 'legacy')
                n_features = checkpoint.get('n_features', 8)
                perfil_guardado = checkpoint.get('perfil', 'REGULAR')

                # Detectar arquitectura automáticamente por las claves del
                # state_dict
                state_dict = checkpoint['model_state_dict']
                tiene_prefijo_red = any(k.startswith('red.')
                                        for k in state_dict.keys())
                if tiene_prefijo_red:
                    arquitectura = 'mejorada_v2'
                    logger.info(
                        f"Arquitectura detectada automáticamente: mejorada_v2")

                if arquitectura == 'mejorada_v2':
                    # Detectar capas desde el checkpoint
                    capas_detectadas = checkpoint.get(
                        'capas_ocultas', [32, 16, 8])
                    logger.info(
                        f"Capas detectadas del checkpoint: {capas_detectadas}")
                    # Nueva arquitectura optimizada - usar 'red' para coincidir
                    # con entrenamiento

                    class RedNeuronalBinary(nn.Module):
                        def __init__(self, input_dim, capas_ocultas):
                            super().__init__()
                            # Construir arquitectura dinámica según checkpoint
                            layers = []
                            prev_size = input_dim
                            for i, size in enumerate(capas_ocultas):
                                layers.extend([
                                    nn.Linear(prev_size, size),
                                    nn.BatchNorm1d(size),
                                    nn.LeakyReLU(0.1),
                                    nn.Dropout(0.25 if i > 0 else 0.125)
                                ])
                                prev_size = size
                            # Capa de salida
                            layers.append(nn.Linear(prev_size, 1))
                            layers.append(nn.Sigmoid())
                            self.red = nn.Sequential(*layers)

                        def forward(self, x):
                            return self.red(x)
                    modelo = RedNeuronalBinary(n_features, capas_detectadas)
                else:
                    # Arquitectura legacy
                    modelo = nn.Sequential(
                        nn.Linear(n_features, 64),
                        nn.ReLU(),
                        nn.Dropout(0.3),
                        nn.Linear(64, 32),
                        nn.ReLU(),
                        nn.Dropout(0.2),
                        nn.Linear(32, 1),
                        nn.Sigmoid()
                    )

                modelo.load_state_dict(checkpoint['model_state_dict'])
                modelo.eval()
                self.modelo_actual = modelo
                self.precision_actual = checkpoint.get('precision', 0.5)
                self.n_features = n_features
                ultimo = checkpoint.get('ultimo_entrenamiento')
                if ultimo:
                    self.ultimo_entrenamiento = datetime.fromisoformat(ultimo)

                # Cargar escalador según perfil
                escalador_path = getattr(
                    self, 'ESCALADOR_PATH', datos_rel('escalador_Binary.pkl'))
                if os.path.exists(escalador_path):
                    try:
                        with open(escalador_path, 'rb') as f:
                            self.escalador = pickle.load(f)
                        logger.info(
                            f"Escalador cargado desde {escalador_path}")
                    except Exception as e:
                        logger.warning(f"No se pudo cargar escalador: {e}")

                logger.info(
                    f"Modelo cargado desde {
                        self.MODELO_PATH} (perfil: {perfil_guardado}) con precisión {
                        self.precision_actual:.1%} ({arquitectura})")
            else:
                logger.info(
                    f"No existe modelo para perfil {
                        self.perfil_actual} en {
                        self.MODELO_PATH}")
        except Exception as e:
            logger.warning(f"No se pudo cargar modelo: {e}")
            self.modelo_actual = None

    def cambiar_perfil(self, nuevo_perfil: str):
        """Cambia el perfil y recarga el modelo correspondiente"""
        if nuevo_perfil in ["REGULAR", "OTC"]:
            self.perfil_actual = nuevo_perfil
            self._actualizar_rutas_segun_perfil()
            self._cargar_modelo()
            logger.info(f"AutoTrainer cambiado a perfil {nuevo_perfil}")

