class IndicadoresTecnicos:
    @staticmethod
    def calcular_ema(datos: pd.Series, periodo: int) -> pd.Series:
        """Calcula la Media Móvil Exponencial"""
        return _ema_series(datos, periodo)

    @staticmethod
    def calcular_rsi(datos: pd.Series, periodo: int = 14) -> pd.Series:
        """Calcula el Índice de Fuerza Relativa"""
        return _rsi_series(datos, periodo)

    @staticmethod
    def calcular_macd(datos: pd.Series, periodo_rapido: int = 12,
                      periodo_lento: int = 26, periodo_senal: int = 9) -> Dict[str, pd.Series]:
        """Calcula MACD y línea de señal"""
        if TALIB_AVAILABLE:
            macd, macdsignal, macdhist = talib.MACD(datos.values,
                                                    fastperiod=periodo_rapido,
                                                    slowperiod=periodo_lento,
                                                    signalperiod=periodo_senal)
            return {
                'macd': pd.Series(macd),
                'senal': pd.Series(macdsignal),
                'histograma': pd.Series(macdhist)
            }
        else:
            ema_rapida = IndicadoresTecnicos.calcular_ema(
                datos, periodo_rapido)
            ema_lenta = IndicadoresTecnicos.calcular_ema(datos, periodo_lento)
            macd = ema_rapida - ema_lenta
            senal = IndicadoresTecnicos.calcular_ema(macd, periodo_senal)
            histograma = macd - senal
            return {
                'macd': macd,
                'senal': senal,
                'histograma': histograma
            }

    @staticmethod
    def calcular_tdi(datos: pd.DataFrame, rsi_periodo: int = 13,
                     precio_periodo: int = 2, senal_periodo: int = 7,
                     volatilidad_periodo: int = 34) -> Dict[str, pd.Series]:
        """Calcula el Traders Dynamic Index (TDI)"""
        try:
            # RSI base
            rsi = IndicadoresTecnicos.calcular_rsi(datos['close'], rsi_periodo)
            # Líneas del TDI
            precio_linea = IndicadoresTecnicos.calcular_ema(
                rsi, precio_periodo)
            senal_linea = IndicadoresTecnicos.calcular_ema(rsi, senal_periodo)
            # Bandas de volatilidad
            rsi_std = rsi.rolling(window=volatilidad_periodo).std()
            rsi_mean = rsi.rolling(window=volatilidad_periodo).mean()
            banda_superior = rsi_mean + (1.6185 * rsi_std)
            banda_inferior = rsi_mean - (1.6185 * rsi_std)
            banda_media = rsi_mean
            return {
                'rsi': rsi,
                'precio_linea': precio_linea,
                'senal_linea': senal_linea,
                'banda_superior': banda_superior,
                'banda_inferior': banda_inferior,
                'banda_media': banda_media
            }
        except Exception as e:
            logger.error(f"Error calculando TDI: {e}")
            return {}

    @staticmethod
    def calcular_bollinger_bands(datos: pd.Series, periodo: int = 20,
                                 desviaciones: float = 2.0) -> Dict[str, pd.Series]:
        """Calcula las Bandas de Bollinger"""
        if TALIB_AVAILABLE:
            upper, middle, lower = talib.BBANDS(
                datos.values, timeperiod=periodo, nbdevup=desviaciones, nbdevdn=desviaciones)
            return {
                'media': pd.Series(middle),
                'banda_superior': pd.Series(upper),
                'banda_inferior': pd.Series(lower)
            }
        else:
            media = datos.rolling(window=periodo).mean()
            std = datos.rolling(window=periodo).std()
            banda_superior = media + (desviaciones * std)
            banda_inferior = media - (desviaciones * std)
            return {
                'media': media,
                'banda_superior': banda_superior,
                'banda_inferior': banda_inferior
            }

    @staticmethod
    def calcular_estocastico(datos: pd.DataFrame, periodo_k: int = 14,
                             periodo_d: int = 3) -> Dict[str, pd.Series]:
        """Calcula el Oscilador Estocástico"""
        try:
            if TALIB_AVAILABLE:
                k, d = talib.STOCH(datos['high'].values, datos['low'].values, datos['close'].values,
                                   fastk_period=periodo_k, slowk_period=3, slowd_period=periodo_d)
                return {
                    'k': pd.Series(k),
                    'd': pd.Series(d)
                }
            else:
                # Implementación manual
                lowest_low = datos['low'].rolling(window=periodo_k).min()
                highest_high = datos['high'].rolling(window=periodo_k).max()
                k_percent = 100 * \
                    ((datos['close'] - lowest_low) /
                     (highest_high - lowest_low))
                d_percent = k_percent.rolling(window=periodo_d).mean()
                return {
                    'k': k_percent,
                    'd': d_percent
                }
        except Exception as e:
            logger.error(f"Error calculando estocástico: {e}")
            return {}


# ========== RED NEURONAL BINARIA REAL (PyTorch) ==========
# CAPITULO 23:
# ==================================================
# ========== RED NEURONAL BINARIA REAL (PyTorch) ==========
if TORCH_AVAILABLE:
    class RedNeuronalBinary(nn.Module):
        """
        Arquitectura de red neuronal PROFESIONAL para clasificación binaria CALL/PUT.
        Entrada: 27 características técnicas reales (RSI, EMAs, MACD, Volumen, ATR, etc.)
        Salida: Probabilidad de CALL (0-1) mediante Sigmoid en capa final.
        Diseñada para operar en tiempo real con datos reales de IQ Option.
        """

        def __init__(self, tamano_entrada: int = 27, capas_ocultas: List[int] = [256, 128, 64, 32],
                     dropout: float = 0.25, usar_batchnorm: bool = True):
            super(RedNeuronalBinary, self).__init__()

            # VALIDACIÓN CRÍTICA: Dropout debe estar entre 0 y 1
            if dropout < 0 or dropout > 1:
                logger.warning(
                    f"⚠️ Valor inválido de dropout={dropout}. Corrigiendo a 0.25")
                dropout = 0.25
            self.dropout = dropout
            self.tamano_entrada = tamano_entrada
            self.capas_ocultas = capas_ocultas
            self.usar_batchnorm = usar_batchnorm

            # Construcción de capas dinámicas
            capas = []
            tamano_anterior = tamano_entrada

            for i, tamano_capa in enumerate(capas_ocultas):
                # Capa lineal
                capas.append(nn.Linear(tamano_anterior, tamano_capa))

                # BatchNorm opcional
                if usar_batchnorm:
                    capas.append(nn.BatchNorm1d(tamano_capa))

                # Activación LeakyReLU (mejor que ReLU en trading)
                capas.append(nn.LeakyReLU(0.1))

                # Dropout: aplicado solo en capas ocultas (no en la última)
                # Usar dropout reducido en la primera capa para evitar pérdida
                # de información
                capa_dropout = dropout if i > 0 else dropout * 0.5
                capas.append(nn.Dropout(capa_dropout))

                tamano_anterior = tamano_capa

            # Capa de salida: 1 neurona con Sigmoid para probabilidad de CALL
            capas.append(nn.Linear(tamano_anterior, 1))
            capas.append(nn.Sigmoid())  # Salida entre 0 y 1: P(CALL)

            self.red = nn.Sequential(*capas)

            # Inicialización de pesos Xavier para mejor convergencia
            self._inicializar_pesos()

            logger.info(
                f"Red neuronal inicializada: {tamano_entrada} entradas → {capas_ocultas} → 1 salida (Sigmoid) | Dropout: {
                    self.dropout}")

        def _inicializar_pesos(self):
            """Inicialización Xavier uniforme para todas las capas lineales"""
            for m in self.modules():
                if isinstance(m, nn.Linear):
                    nn.init.xavier_uniform_(m.weight)
                    if m.bias is not None:
                        nn.init.zeros_(m.bias)

        def forward(self, x: torch.Tensor) -> torch.Tensor:
            """
            Propagación hacia adelante.
            Args:
                x: Tensor de forma (batch_size, tamano_entrada)
            Returns:
                Tensor de forma (batch_size, 1) con probabilidad de CALL (0-1)
            """
            if x.dim() != 2:
                raise ValueError(
                    f"Entrada debe ser 2D (batch_size, features), recibido: {
                        x.shape}")
            if x.size(1) != self.tamano_entrada:
                raise ValueError(
                    f"Se esperan {
                        self.tamano_entrada} características, recibidas: {
                        x.size(1)}")

            return self.red(x)

        def predecir_probabilidad(self, datos: np.ndarray) -> float:
            """
            Predice la probabilidad de un solo ejemplo (CALL).
            Usa el modelo entrenado y devuelve un valor entre 0 y 1.
            Args:
                datos: array de numpy con 27 características técnicas reales
            Returns:
                float: Probabilidad de que sea una señal CALL (0.0 - 1.0)
            """
            self.eval()  # Modo evaluación (desactiva dropout, batchnorm en inferencia)
            with torch.no_grad():  # Desactiva cálculo de gradientes (más rápido y seguro)
                tensor = torch.FloatTensor(datos).unsqueeze(
                    0)  # Añade dimensión batch
                probabilidad = self(tensor).item()  # Convierte tensor a float
                return probabilidad

        def predecir_clase(self, datos: np.ndarray,
                           umbral: float = 0.5) -> str:
            """
            Predice la clase (CALL o PUT) basada en un umbral.
            Args:
                datos: array de numpy con 27 características técnicas reales
                umbral: Umbral para clasificar (default 0.5)
            Returns:
                str: 'CALL' o 'PUT'
            """
            probabilidad = self.predecir_probabilidad(datos)
            return 'CALL' if probabilidad >= umbral else 'PUT'

        def guardar_modelo(self, ruta: str):
            """
            Guarda el modelo completo con metadatos para carga futura.
            """
            checkpoint = {
                'model_state_dict': self.state_dict(),
                'tamano_entrada': self.tamano_entrada,
                'capas_ocultas': self.capas_ocultas,
                'dropout': self.dropout,
                'usar_batchnorm': self.usar_batchnorm,
                'version': '2.1',
                'fecha_entrenamiento': datetime.now().isoformat()
            }
            torch.save(checkpoint, ruta)
            logger.info(f"Modelo guardado en: {ruta}")

        @classmethod
        def cargar_modelo(cls, ruta: str) -> 'RedNeuronalBinary':
            """
            Carga un modelo guardado previamente.
            """
            checkpoint = torch.load(ruta, weights_only=False)

            modelo = cls(
                tamano_entrada=checkpoint['tamano_entrada'],
                capas_ocultas=checkpoint['capas_ocultas'],
                dropout=checkpoint['dropout'],
                usar_batchnorm=checkpoint['usar_batchnorm']
            )
            modelo.load_state_dict(checkpoint['model_state_dict'])
            modelo.eval()  # Modo evaluación por defecto
            logger.info(
                f"Modelo cargado desde {ruta} (v{
                    checkpoint.get(
                        'version', '1.0')})")
            return modelo

        def entrenar(self, X_train: np.ndarray, y_train: np.ndarray,
                     X_val: np.ndarray, y_val: np.ndarray,
                     epochs: int = 200, batch_size: int = 32,
                     learning_rate: float = 0.001, patience: int = 30,
                     verbose: bool = True) -> dict:
            """
            Entrena el modelo con datos reales (X_train, y_train).
            Usa Early Stopping y validación para evitar overfitting.
            Args:
                X_train, y_train: Datos de entrenamiento
                X_val, y_val: Datos de validación
                epochs: Número máximo de épocas
                batch_size: Tamaño del lote
                learning_rate: Tasa de aprendizaje
                patience: Paciencia para Early Stopping
                verbose: Mostrar progreso
            Returns:
                dict con historial de entrenamiento
            """
            # Convertir a tensores
            X_train_tensor = torch.FloatTensor(X_train)
            y_train_tensor = torch.FloatTensor(
                y_train).unsqueeze(1)  # Asegurar dimensión (n, 1)
            X_val_tensor = torch.FloatTensor(X_val)
            y_val_tensor = torch.FloatTensor(y_val).unsqueeze(1)

            # Crear DataLoaders
            train_dataset = TensorDataset(X_train_tensor, y_train_tensor)
            val_dataset = TensorDataset(X_val_tensor, y_val_tensor)
            train_loader = DataLoader(
                train_dataset, batch_size=batch_size, shuffle=True)
            val_loader = DataLoader(val_dataset, batch_size=batch_size)

            # Definir pérdida y optimizador
            criterion = nn.BCELoss()  # Binary Cross Entropy para probabilidad
            optimizer = torch.optim.Adam(self.parameters(), lr=learning_rate)
            scheduler = torch.optim.lr_scheduler.ReduceLROnPlateau(
                optimizer, mode='min', factor=0.5, patience=10, verbose=False
            )

            # Historial
            historial = {'train_loss': [], 'val_loss': [], 'val_accuracy': []}
            mejor_loss = float('inf')
            sin_mejora = 0

            # Entrenamiento
            for epoch in range(epochs):
                # Entrenamiento
                self.train()
                train_loss = 0.0
                for batch_X, batch_y in train_loader:
                    optimizer.zero_grad()
                    outputs = self(batch_X)
                    loss = criterion(outputs, batch_y)
                    loss.backward()
                    torch.nn.utils.clip_grad_norm_(
                        self.parameters(), max_norm=1.0)
                    optimizer.step()
                    train_loss += loss.item()

                train_loss /= len(train_loader)
                historial['train_loss'].append(train_loss)

                # Validación
                self.eval()
                val_loss = 0.0
                correct = 0
                total = 0
                with torch.no_grad():
                    for batch_X, batch_y in val_loader:
                        outputs = self(batch_X)
                        loss = criterion(outputs, batch_y)
                        val_loss += loss.item()
                        predicted = (outputs > 0.5).float()
                        total += batch_y.size(0)
                        correct += (predicted == batch_y).sum().item()

                val_loss /= len(val_loader)
                val_accuracy = correct / total
                historial['val_loss'].append(val_loss)
                historial['val_accuracy'].append(val_accuracy)

                # Early Stopping
                if val_loss < mejor_loss:
                    mejor_loss = val_loss
                    sin_mejora = 0
                    torch.save(
                        self.state_dict(),
                        datos_rel("mejor_modelo.pth"))
                else:
                    sin_mejora += 1

                # Scheduler
                scheduler.step(val_loss)

                # Verbose
                if verbose and (epoch + 1) % 20 == 0:
                    logger.info(f"Epoch {epoch + 1}/{epochs} | "
                                f"Train Loss: {train_loss:.6f} | "
                                f"Val Loss: {val_loss:.6f} | "
                                f"Val Acc: {val_accuracy:.4f}")

                # Early stopping
                if sin_mejora >= patience:
                    logger.info(f"Early stopping en epoch {epoch + 1}")
                    break

            # Cargar mejor modelo
            self.load_state_dict(torch.load(datos_rel("mejor_modelo.pth")))
            os.remove(datos_rel("mejor_modelo.pth"))

            logger.info(
                f"Entrenamiento completado. Mejor loss de validación: {
                    mejor_loss:.6f}")
            return historial
else:
    # Si no hay PyTorch, esta clase no se usará (el sistema usará
    # SGDClassifier o LGBM)
    class RedNeuronalBinary:
        def __init__(self, *args, **kwargs):
            raise ImportError(
                "PyTorch no está instalado. No se puede usar RedNeuronalBinary.")

