    def _obtener_datos_para_grafico(
            self, simbolo: str, timeframe: str, cantidad: int = 100) -> Optional[pd.DataFrame]:
        """Obtiene datos para generar el gráfico de velas"""
        try:
            # Usar IQOptionBridge para obtener datos reales
            datos = self._get_iq_data(simbolo, timeframe, cantidad)
            if datos is not None and not datos.empty:
                return datos
            else:
                logger.warning(
                    f"No se pudieron obtener datos reales para {simbolo}")
                return None
        except Exception as e:
            logger.error(f"Error obteniendo datos para gráfico: {e}")
            return None

    def _get_iq_data(self, simbolo: str, timeframe: str,
                     cantidad: int) -> Optional[pd.DataFrame]:
        """Método auxiliar para obtener datos de IQ Option"""
        try:
            if self.iq_bridge:
                return self.iq_bridge.obtener_datos_tiempo_real(
                    simbolo, cantidad, timeframe)
            else:
                logger.warning(
                    "IQOptionBridge no disponible en TelegramNotifier")
                return None
        except Exception as e:
            logger.error(f"Error obteniendo datos IQ: {e}")
            return None

    def _generar_grafico_velas(
            self, df: pd.DataFrame, simbolo: str, direccion: str, confianza: float) -> str:
        """
        Genera un gráfico de velas con indicadores y lo guarda como imagen.
        Usa mplfinance para gráficos profesionales.
        """
        try:
            # Asegurar que el DataFrame tiene las columnas necesarias
            required_cols = ['open', 'high', 'low', 'close', 'volume']
            for col in required_cols:
                if col not in df.columns:
                    raise ValueError(f"Falta columna requerida: {col}")

            # Crear carpeta temporal si no existe
            temp_dir = "temp_graphs"
            os.makedirs(temp_dir, exist_ok=True)

            # Nombre del archivo
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            filename = f"{temp_dir}/{simbolo}_{direccion}_{timestamp}.png"

            # Configuración del gráfico
            style = mpf.make_mpf_style(
                base_mpf_style='charles',
                marketcolors=mpf.make_marketcolors(
                    up='green',
                    down='red',
                    edge='black',
                    wick='black',
                    volume='in',
                    inherit=True
                ),
                gridstyle='--',
                gridaxis='both',
                facecolor='white',
                edgecolor='black',
                figcolor='white'
            )

            # Indicadores (EMAs requeridos)
            ema50 = _ema_series(df['close'], 50)
            ema200 = _ema_series(df['close'], 200)

            # Agregar indicadores al gráfico
            apds = [
                mpf.make_addplot(
                    ema50,
                    color='purple',
                    width=1.8,
                    label='EMA 50'),
                mpf.make_addplot(
                    ema200,
                    color='blue',
                    width=2.0,
                    label='EMA 200'),
            ]

            # TDI (Traders Dynamic Index) en panel inferior
            # RSI
            rsi = _rsi_series(df['close'], 13)
            # Líneas TDI
            tdi_price = _ema_series(rsi, 2)
            tdi_signal = _ema_series(rsi, 7)
            basis = rsi.rolling(34).mean()
            dev = rsi.rolling(34).std()
            tdi_upper = basis + dev * 1.618
            tdi_lower = basis - dev * 1.618

            apds.extend([
                mpf.make_addplot(tdi_price, color='green', width=1.5, panel=2, label='TDI Price'),
                mpf.make_addplot(tdi_signal, color='red', width=1.5, panel=2, label='TDI Signal'),
                mpf.make_addplot(tdi_upper, color='grey', width=1.0, panel=2, linestyle='dashed', label='TDI Upper'),
                mpf.make_addplot(tdi_lower, color='grey', width=1.0, panel=2, linestyle='dashed', label='TDI Lower'),
            ])

            # Crear figura
            fig, axes = mpf.plot(
                df,
                type='candle',
                style=style,
                addplot=apds,
                volume=True,
                title=f'{simbolo} - {direccion} | Confianza: {confianza:.1f}%',
                ylabel='Precio ($)',
                ylabel_lower='Volumen',
                figsize=(16, 10),
                returnfig=True,
                panel_ratios=(3, 1, 1),
                tight_layout=True
            )

            # Añadir leyenda
            axes[0].legend(loc='upper left', fontsize=12)

            # Guardar
            fig.savefig(
                filename,
                dpi=150,
                bbox_inches='tight',
                facecolor='white')
            plt.close(fig)

            logger.info(f"Gráfico generado: {filename}")
            return filename

        except Exception as e:
            logger.error(f"Error generando gráfico de velas: {e}")
            # Intentar con método alternativo
            return self._generar_grafico_alternativo(
                df, simbolo, direccion, confianza)

    def _generar_grafico_alternativo(
            self, df: pd.DataFrame, simbolo: str, direccion: str, confianza: float) -> str:
        """
        Genera gráfico alternativo usando matplotlib si mplfinance no está disponible.
        """
        try:
            temp_dir = "temp_graphs"
            os.makedirs(temp_dir, exist_ok=True)

            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            filename = f"{temp_dir}/{simbolo}_{direccion}_{timestamp}.png"

            fig, ax = plt.subplots(figsize=(16, 10))

            # Datos de velas
            x = range(len(df))
            opens = df['open'].values
            highs = df['high'].values
            lows = df['low'].values
            closes = df['close'].values

            # Colores
            colors = [
                'green' if close > open else 'red' for open,
                close in zip(
                    opens,
                    closes)]

            # Dibujar velas
            for i in range(len(df)):
                ax.plot([x[i], x[i]], [lows[i], highs[i]],
                        color=colors[i], linewidth=1)
                ax.plot([x[i], x[i]], [opens[i], closes[i]],
                        color=colors[i], linewidth=4)

            # EMAs
            ema21 = _ema_series(df['close'], 21)
            ema50 = _ema_series(df['close'], 50)
            ema200 = _ema_series(df['close'], 200)

            ax.plot(x, ema21, color='orange', linewidth=1.8, label='EMA 21')
            ax.plot(x, ema50, color='purple', linewidth=2, label='EMA 50')
            ax.plot(x, ema200, color='blue', linewidth=2.2, label='EMA 200')

            ax.set_title(
                f'{simbolo} - {direccion} | Confianza: {confianza:.1f}%')
            ax.set_ylabel('Precio ($)')
            ax.legend()
            ax.grid(True, linestyle='--', alpha=0.7)

            # Volumen
            ax2 = ax.twinx()
            ax2.bar(x, df['volume'].values, alpha=0.3, color='gray')
            ax2.set_ylabel('Volumen', color='gray')
            ax2.tick_params(axis='y', colors='gray')

            plt.tight_layout()
            plt.savefig(filename, dpi=150, bbox_inches='tight')
            plt.close()

            logger.info(f"Gráfico alternativo generado: {filename}")
            return filename

        except Exception as e:
            logger.error(f"Error generando gráfico alternativo: {e}")
            return ""

