class _TrainingThread_DEPRECATED(QThread):
    """Hilo en segundo plano para reentrenar el modelo de IA automáticamente.
    No bloquea la interfaz gráfica.
    Envía señales de progreso y estado a la GUI."""
    # Señales para comunicarse con la GUI (main thread)
    # mensaje: "Iniciando entrenamiento..."
    training_started = pyqtSignal(str)
    training_progress = pyqtSignal(int, str)     # progreso (0-100), mensaje
    training_completed = pyqtSignal(
        bool, str, float)  # éxito, mensaje, precisión
    training_error = pyqtSignal(str)             # mensaje de error

    def __init__(self, config: ConfiguracionTrading,
                 analizador_mercado: AnalizadorMercado):
        super().__init__()
        self.config = config
        # ✅ ¡USAR EL MISMO OBJETO QUE YA EXISTE!
        self.analizador_mercado = analizador_mercado
        self.logger = logging.getLogger(__name__)

    def run(self):
        """Run the training process"""
        try:
            logger.info("Iniciando entrenamiento del modelo neuronal...")

            # Verificar si se necesitan datos reales
            if self.config.FORZAR_DATOS_REALES:
                # No necesitas verificar conexión aquí, porque el analizador_mercado ya la tiene
                # El analizador_mercado ya tiene acceso a iq_bridge a través de
                # self.analizador_mercado.iq_bridge
                pass  # No necesitas hacer nada, ya que el analizador_mercado puede obtener los datos

            logger.info(
                "Modo de entrenamiento con datos reales o cache. No se requiere conexión directa.")

            # Obtener datos de entrenamiento según perfil activo
            modo_mercado = market_resolver.resolver()
            fecha_inicio, fecha_fin = market_resolver.obtener_rango_fechas()
            logger.info(
                f"Entrenamiento en modo: {
                    modo_mercado['modo']} - Usando {
                    modo_mercado['dias_historicos']} días de historial")

            # ✅ USAR EL ANALIZADOR DE MERCADO EXISTENTE PARA OBTENER LOS DATOS
            # El analizador_mercado ya tiene acceso a iq_bridge, config, y
            # operations_repo
            dataset = self.analizador_mercado._preparar_dataset_para_entrenamiento(
                fecha_inicio, fecha_fin)

            if dataset is None or len(
                    dataset) < self.analizador_mercado.min_datos_para_entrenar:
                logger.warning("Dataset insuficiente para entrenamiento")
                self.training_error.emit(
                    "Dataset insuficiente para entrenamiento. Verifique operaciones exitosas.")
                return

            # Entrenar modelo
            exito, mensaje, precision = self.analizador_mercado._entrenar_modelo_desde_dataset(
                dataset)

            if exito:
                self.training_completed.emit(True, mensaje, precision)
                logger.info("Reentrenamiento completado exitosamente")
            else:
                self.training_error.emit(f"Error en entrenamiento: {mensaje}")
                logger.error(f"Entrenamiento fallido: {mensaje}")

        except Exception as e:
            logger.error(f"Error en hilo de entrenamiento: {e}", exc_info=True)
            self.training_error.emit(
                f"Error crítico en entrenamiento: {
                    str(e)}")

    def _ejecutar_entrenamiento(self) -> Tuple[bool, str, float]:
        """
        Ejecuta el proceso real de entrenamiento usando AutoTrainer.
        Retorna: (éxito: bool, mensaje: str, precision: float)
        """
        try:
            # Notificar progreso
            self.training_progress.emit(
                20, "🔍 Verificando disponibilidad de datos...")

            # Llamar al método real de AutoTrainer
            entrenado = self.auto_trainer.verificar_y_entrenar()

            if entrenado:
                # Obtener precisión actual del predictor
                precision = self.auto_trainer.precision_actual if hasattr(
                    self.auto_trainer, 'precision_actual') else 0.0
                mensaje = f"✅ Entrenamiento completado. Nueva precisión: {
                    precision:.1%}"
                return True, mensaje, precision
            else:
                mensaje = "⚠️ No se pudo reentrenar el modelo. Verifique los datos históricos."
                return False, mensaje, 0.0

        except Exception as e:
            return False, f"Error durante entrenamiento: {str(e)}", 0.0

    def pause(self):
        """Pausa el entrenamiento (no usado en este caso, pero mantenido por compatibilidad)"""
        self._is_paused = True
        self.training_progress.emit(0, "⏸️ Entrenamiento pausado")

    def resume(self):
        """Reanuda el entrenamiento (no usado en este caso)"""
        self._is_paused = False
        self.training_progress.emit(50, "▶️ Reanudando entrenamiento...")

    def stop(self):
        """Detiene el hilo de entrenamiento de forma segura"""
        self._force_stop = True
        self.training_progress.emit(0, "🛑 Deteniendo entrenamiento...")
        self.wait(3000)  # Esperar hasta 3 segundos a que termine

    def is_running(self):
        """Retorna si el hilo está activo"""
        return self._is_running

    def get_last_trained(self):
        """Retorna la fecha del último entrenamiento exitoso"""
        return self.last_trained_model

