class TradingRealtimeThread(QThread):
    log = pyqtSignal(str)

    def __init__(self, config: ConfiguracionTrading,
                 iq_bridge: IQOptionBridge):
        super().__init__()
        self.config = config
        self.iq_bridge = iq_bridge
        trading_manager = getattr(iq_bridge, "trading_manager", None)
        if trading_manager is None:
            trading_manager = TradingManager(config, iq_bridge)
            try:
                setattr(iq_bridge, "trading_manager", trading_manager)
            except Exception:
                pass
        self.analizador_mercado = AnalizadorMercado(
            config, iq_bridge, trading_manager
        )

        self._activo = True

    def detener(self):
        self._activo = False

    def run(self):
        logger.info("🟢 Trading automático iniciado")
        self.log.emit("🟢 Trading automático iniciado")

        while self._activo:
            try:
                for par in self.config.PARES_TRADING:
                    self.analizar_y_operar(par)

                self.msleep(self.config.INTERVALO_ESCANEO * 1000)

            except Exception as e:
                logger.error(f"Error en TradingRealtimeThread: {e}")

    def analizar_y_operar(self, par):
        resultado = self.analizador_mercado.analizar_mercado(par)

        if not resultado:
            return

        if resultado.get("accion") in ("CALL", "PUT"):
            logger.info(f"📈 Señal {resultado['accion']} en {par}")

            if self.config.AUTO_TRADING_HABILITADO:
                self.analizador_mercado.ejecutar_operacion(resultado)
            else:
                logger.info("⚠️ Auto trading deshabilitado")

