class TrainingThread(QThread):
    finished = pyqtSignal(dict)
    progress = pyqtSignal(int)

    def __init__(self, config: ConfiguracionTrading,
                 iq_bridge: IQOptionBridge):
        super().__init__()
        self.config = config
        self.iq_bridge = iq_bridge
        # ✅ CORREGIDO: AnalizadorMercado requiere (config, iq_bridge, trading_manager)
        trading_manager = getattr(iq_bridge, "trading_manager", None)
        if trading_manager is None:
            trading_manager = TradingManager(config, iq_bridge)
            try:
                setattr(iq_bridge, "trading_manager", trading_manager)
            except Exception:
                pass
        self.analizador_mercado = AnalizadorMercado(
            config, iq_bridge, trading_manager)

    def run(self):
        """Run the training process"""
        try:
            logger.info("Iniciando entrenamiento del modelo neuronal...")

            # Verificar si se necesitan datos reales
            if self.config.FORZAR_DATOS_REALES:
                if not self.iq_bridge.verificar_y_establecer_conexion():
                    self.finished.emit({
                        'success': False,
                        'error': 'No hay conexión a IQ Option y está forzado el uso de datos reales. Conecte antes de entrenar.'
                    })
                    return
            else:
                logger.info(
                    "Modo de entrenamiento con datos sintéticos o cache. No se requiere conexión a IQ Option.")

            # Obtener datos de entrenamiento según perfil activo
            # Usar MarketModeResolver para determinar el rango de fechas
            # correcto
            modo_mercado = market_resolver.resolver()
            fecha_inicio, fecha_fin = market_resolver.obtener_rango_fechas()

            logger.info(f"Entrenamiento en modo: {modo_mercado['modo']} - "
                        f"Usando {modo_mercado['dias_historicos']} días de historial")

            # Obtener datos para todos los pares
            datos_entrenamiento = {}
            pares_con_datos = 0
            total_registros = 0
            tipos_datos = {'REAL': 0, 'SINTETICO': 0, 'CACHE': 0}

            logger.info(
                f"Obteniendo datos de entrenamiento desde {
                    fecha_inicio.strftime('%Y-%m-%d')} hasta {
                    fecha_fin.strftime('%Y-%m-%d')}")

            # VERIFICAR CONEXIÓN UNA VEZ antes de iterar sobre pares
            if not self.iq_bridge.connected:
                logger.info(
                    "Reconectando a IQ Option antes de obtener datos...")
                if not self.iq_bridge.connect():
                    logger.warning(
                        "No se pudo reconectar, continuando con datos en cache/sintéticos")
                else:
                    import time
                    time.sleep(2)  # Esperar estabilización de conexión

            # Limitar pares para entrenamiento rápido - REDUCIDO para evitar
            # bloqueo
            # Reducido a 5 pares
            pares_entrenamiento = self.config.PARES_TRADING[:5]
            logger.info(
                f"Procesando {
                    len(pares_entrenamiento)} pares para entrenamiento")

            for indice, par in enumerate(pares_entrenamiento):
                try:
                    # NUEVO: Delay entre pares para evitar bloqueo de API
                    if indice > 0:
                        import time
                        time.sleep(2)  # 2 segundos entre cada par

                    logger.info(
                        f"Procesando par: {par} ({indice + 1}/{len(pares_entrenamiento)})")
                    datos = self.iq_bridge.obtener_datos_historicos(
                        par, self.config.MARCO_TIEMPO_SELECCIONADO, fecha_inicio, fecha_fin
                    )

                    # Verificar datos mínimos (MIN_DATOS_POR_PAR = 50)
                    min_datos = getattr(self.config, 'MIN_DATOS_POR_PAR', 50)
                    if datos.empty or len(datos) < min_datos:
                        logger.warning(
                            f"Par {par}: Datos insuficientes ({
                                len(datos)} < {min_datos}), saltando...")
                        continue  # Continuar con el siguiente par, no abortar

                    # Contar tipos de datos
                    if 'tipo_datos' in datos.columns:
                        tipo_dato = datos.iloc[-1]['tipo_datos']
                        tipos_datos[tipo_dato] = tipos_datos.get(
                            tipo_dato, 0) + 1

                    # Crear target ANTES de calcular indicadores
                    datos['target'] = np.where(
                        datos['close'].shift(-1) > datos['close'], 1, 0)

                    # Calcular indicadores y preparar datos
                    indicadores_resultado = self.analizador_mercado._calcular_indicadores_completos(
                        datos.copy())

                    # ✅ CORREGIDO: extraer DataFrame del resultado (que es un dict)
                    if isinstance(indicadores_resultado,
                                  dict) and 'df' in indicadores_resultado:
                        datos_con_indicadores = indicadores_resultado['df']
                    elif isinstance(indicadores_resultado, pd.DataFrame):
                        datos_con_indicadores = indicadores_resultado
                    else:
                        logger.warning(
                            f"Par {par}: Resultado de indicadores inválido, saltando...")
                        continue

                    if 'target' in datos.columns:
                        datos_con_indicadores['target'] = datos['target'].values[:len(
                            datos_con_indicadores)]

                    datos_con_indicadores.dropna(inplace=True)
                    if not datos_con_indicadores.empty:
                        datos_entrenamiento[par] = datos_con_indicadores
                        pares_con_datos += 1
                        total_registros += len(datos_con_indicadores)
                        logger.info(
                            f"Par {par}: {
                                len(datos_con_indicadores)} registros válidos agregados")
                    else:
                        logger.warning(
                            f"Par {par}: Sin datos después de calcular indicadores, saltando...")
                        continue

                except Exception as e:
                    logger.warning(
                        f"Par {par}: Error procesando ({e}), continuando con siguiente par...")
                    continue

            logger.info(
                f"Resumen de datos: {pares_con_datos}/{
                    len(pares_entrenamiento)} pares con datos, {total_registros} registros totales")
            logger.info(
                f"Tipos de datos: REAL={
                    tipos_datos.get(
                        'REAL',
                        0)}, SINTETICO={
                    tipos_datos.get(
                        'SINTETICO',
                        0)}, CACHE={
                    tipos_datos.get(
                        'CACHE',
                        0)}")

            if not datos_entrenamiento:
                self.finished.emit({
                    'success': False,
                    'error': 'No se pudieron obtener datos suficientes para el entrenamiento'
                })
                return

            # Usar el mínimo del perfil activo (OTC=15, REGULAR=15)
            min_datos_perfil = getattr(self.config, 'MIN_DATOS_POR_PAR', 50)
            if total_registros < min_datos_perfil:
                self.finished.emit({
                    'success': False,
                    'error': f'Datos insuficientes para entrenamiento. Se necesitan al menos {min_datos_perfil} registros, solo se obtuvieron {total_registros}'
                })
                return

            # Combinar todos los datos
            df_total = pd.concat(
                datos_entrenamiento.values(),
                ignore_index=True)
            logger.info(f"DataFrame combinado: {len(df_total)} registros")

            # Verificar el número de características
            columnas_caracteristicas = [col for col in df_total.columns
                                        if col not in ['target', 'time'] and
                                        pd.api.types.is_numeric_dtype(df_total[col])]

            logger.info(
                f"Número de características detectadas: {
                    len(columnas_caracteristicas)}")

            # Actualizar el tamaño de entrada si es necesario
            tamano_entrada = getattr(
                self.config, 'TAMANO_ENTRADA_NEURONAL', 27)
            if len(columnas_caracteristicas) != tamano_entrada:
                logger.warning(
                    f"Ajustando tamaño de entrada de {tamano_entrada} a {
                        len(columnas_caracteristicas)}")
                self.config.TAMANO_ENTRADA_NEURONAL = len(
                    columnas_caracteristicas)
                tamano_entrada = len(columnas_caracteristicas)

            # Preparar características y etiquetas
            df_total = df_total.dropna()

            # Seleccionar características
            X = df_total[columnas_caracteristicas].values
            y = df_total['target'].values

            logger.info(
                f"Datos preparados: X shape={
                    X.shape}, y shape={
                    y.shape}")

            # Dividir datos
            test_size = 1 - getattr(self.config,
                                    'RELACION_PRUEBA_ENTRENAMIENTO', 0.8)
            X_train, X_test, y_train, y_test = train_test_split(
                X, y, test_size=test_size, random_state=42
            )

            logger.info(
                f"Datos divididos: Train={
                    X_train.shape}, Test={
                    X_test.shape}")

            # Escalar datos
            escalador = StandardScaler()
            X_train_scaled = escalador.fit_transform(X_train)
            X_test_scaled = escalador.transform(X_test)

            # Crear y entrenar modelo con técnicas avanzadas
            if TORCH_AVAILABLE:
                modelo = RedNeuronalBinary(
                    tamano_entrada,
                    getattr(self.config, 'CAPAS_OCULTAS_NEURONAL', [64, 32]),
                    1,  # ✅ CORREGIDO: 1 salida para clasificación binaria con Sigmoid
                    getattr(self.config, 'DROPOUT_NEURONAL', 0.2)
                )

                # Convertir a tensores - ✅ CORREGIDO: y como FloatTensor para
                # BCELoss
                X_train_tensor = torch.FloatTensor(X_train_scaled)
                y_train_tensor = torch.FloatTensor(
                    y_train).unsqueeze(1)  # Shape: (N, 1)
                X_test_tensor = torch.FloatTensor(X_test_scaled)
                y_test_tensor = torch.FloatTensor(
                    y_test).unsqueeze(1)  # Shape: (N, 1)

                # Calcular peso positivo para balanceo de clases
                class_counts = np.bincount(y_train)
                pos_weight = torch.FloatTensor(
                    [class_counts[0] / (class_counts[1] + 1)])
                logger.info(
                    f"Balance de clases - PUT(0): {
                        class_counts[0]}, CALL(1): {
                        class_counts[1]}, pos_weight: {
                        pos_weight.item():.2f}")

                # Definir optimizador con weight decay y pérdida binaria
                tasa_aprendizaje = getattr(
                    self.config, 'TASA_APRENDIZAJE_NEURONAL', 0.001)
                optimizer = optim.AdamW(
                    modelo.parameters(),
                    lr=tasa_aprendizaje,
                    weight_decay=0.01)
                criterion = nn.BCELoss()  # ✅ CORREGIDO: BCELoss para salida Sigmoid

                # Scheduler para reducir learning rate
                scheduler = optim.lr_scheduler.ReduceLROnPlateau(
                    optimizer, mode='max', factor=0.5, patience=20)

                # DataLoader para mini-batches
                train_dataset = TensorDataset(X_train_tensor, y_train_tensor)
                # Ajustar batch_size si hay pocos datos
                tamano_lote = getattr(self.config, 'TAMANO_LOTE_NEURONAL', 32)
                batch_size = min(tamano_lote, len(X_train_tensor))
                if batch_size < 1:
                    batch_size = 1
                train_loader = DataLoader(
                    train_dataset,
                    batch_size=batch_size,
                    shuffle=True,
                    drop_last=False)

                # Variables para early stopping
                mejor_precision = 0
                mejor_modelo_state = None
                paciencia = getattr(self.config, 'PACIENCIA_ENTRENAMIENTO', 15)
                sin_mejora = 0
                epoch_cantidad = getattr(self.config, 'EPOCH_CANTIDAD', 100)

                # Entrenamiento con early stopping
                for epoch in range(epoch_cantidad):
                    modelo.train()
                    epoch_loss = 0
                    batch_count = 0

                    for batch_X, batch_y in train_loader:
                        optimizer.zero_grad()
                        outputs = modelo(batch_X)
                        loss = criterion(outputs, batch_y)
                        loss.backward()

                        # Gradient clipping para estabilidad
                        torch.nn.utils.clip_grad_norm_(
                            modelo.parameters(), max_norm=1.0)

                        optimizer.step()
                        epoch_loss += loss.item()
                        batch_count += 1

                    # Emitir progreso
                    progress = int((epoch + 1) / epoch_cantidad * 100)
                    self.progress.emit(progress)

                    # Validación cada 5 épocas
                    if (epoch + 1) % 5 == 0:
                        modelo.eval()
                        with torch.no_grad():
                            outputs = modelo(X_test_tensor)
                            # ✅ CORREGIDO: Umbral 0.5 para clasificación binaria con Sigmoid
                            predicted = (outputs > 0.5).float()
                            accuracy = (
                                predicted == y_test_tensor).float().mean().item()

                            # Actualizar scheduler
                            scheduler.step(accuracy)

                            avg_loss = epoch_loss / batch_count if batch_count > 0 else 0.0
                            if accuracy > mejor_precision:
                                mejor_precision = accuracy
                                mejor_modelo_state = modelo.state_dict().copy()
                                sin_mejora = 0
                                logger.info(
                                    f"Epoch {
                                        epoch + 1}/{epoch_cantidad} | Loss: {
                                        avg_loss:.4f} | Precision: {
                                        accuracy * 100:.2f}% (MEJOR)")
                            else:
                                sin_mejora += 1
                                if epoch % 20 == 0:
                                    logger.info(
                                        f"Epoch {
                                            epoch + 1}/{epoch_cantidad} | Loss: {
                                            avg_loss:.4f} | Precision: {
                                            accuracy * 100:.2f}%")

                            # Early stopping
                            if sin_mejora >= paciencia // 5:
                                logger.info(
                                    f"Early stopping en epoch {
                                        epoch + 1}, mejor precision: {
                                        mejor_precision * 100:.2f}%")
                                break

                # Cargar mejor modelo
                if mejor_modelo_state is not None:
                    modelo.load_state_dict(mejor_modelo_state)
                    accuracy = mejor_precision
                else:
                    # Evaluar modelo final
                    modelo.eval()
                    with torch.no_grad():
                        outputs = modelo(X_test_tensor)
                        # ✅ CORREGIDO: Umbral 0.5 para clasificación binaria
                        predicted = (outputs > 0.5).float()
                        accuracy = (
                            predicted == y_test_tensor).float().mean().item()

                # Determinar perfil actual según día de la semana
                from datetime import timezone
                ahora_utc = datetime.now(timezone.utc)
                dia_semana = ahora_utc.weekday()
                hora = ahora_utc.hour
                # OTC: Viernes 22:00+ hasta Domingo 22:00
                es_otc = (
                    dia_semana == 4 and hora >= 22) or dia_semana == 5 or (
                    dia_semana == 6 and hora < 22)
                perfil = "OTC" if es_otc else "REGULAR"

                # Guardar modelo como checkpoint con metadata
                checkpoint = {
                    'model_state_dict': modelo.state_dict(),
                    'perfil': perfil,
                    'precision': accuracy,
                    'accuracy': accuracy,
                    'arquitectura': 'RedNeuronalBinary_v2',
                    'n_features': tamano_entrada,
                    'capas_ocultas': getattr(self.config, 'CAPAS_OCULTAS_NEURONAL', [64, 32]),
                    'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'ultimo_entrenamiento': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'registros_usados': total_registros,
                    'pares_usados': pares_con_datos
                }

                # Usar ruta según perfil
                if perfil == "OTC":
                    ruta_modelo = self.config.PERFIL_OTC["modelo_path"]
                    ruta_escalador = self.config.PERFIL_OTC["escalador_path"]
                else:
                    ruta_modelo = self.config.PERFIL_REGULAR["modelo_path"]
                    ruta_escalador = self.config.PERFIL_REGULAR["escalador_path"]

                torch.save(checkpoint, ruta_modelo)
                with open(ruta_escalador, 'wb') as f:
                    pickle.dump(escalador, f)

                logger.info(
                    f"Modelo {perfil} guardado en {ruta_modelo} con precisión {
                        accuracy * 100:.2f}%")

                self.finished.emit({
                    'success': True,
                    'accuracy': accuracy * 100,
                    'loss': epoch_loss / batch_count if batch_count > 0 else 0,
                    'pares_usados': pares_con_datos,
                    'registros_usados': total_registros,
                    'perfil': perfil
                })
            else:
                for epoch in range(
                        getattr(self.config, 'EPOCH_CANTIDAD', 100)):
                    progress = int(
                        (epoch +
                         1) /
                        getattr(
                            self.config,
                            'EPOCH_CANTIDAD',
                            100) *
                        100)
                    self.progress.emit(progress)
                    time.sleep(0.1)

                modelo = RedNeuronalBinary(
                    getattr(self.config, 'TAMANO_ENTRADA_NEURONAL', 27),
                    getattr(self.config, 'CAPAS_OCULTAS_NEURONAL', [64, 32]),
                    getattr(self.config, 'TAMANO_SALIDA_NEURONAL', 1),
                    getattr(self.config, 'DROPOUT_NEURONAL', 0.2)
                )

                with open(getattr(self.config, 'RUTA_MODELO_NEURONAL', datos_rel('modelo_neuronal_simulado.pth')), 'w') as f:
                    f.write("modelo_simulado")

                with open(getattr(self.config, 'RUTA_ESCALADOR_NEURONAL', datos_rel('escalador_neuronal_simulado.pkl')), 'wb') as f:
                    pickle.dump(StandardScaler(), f)

                self.finished.emit({
                    'success': True,
                    'accuracy': 65.0,  # Simulado
                    'loss': 0.5,
                    'pares_usados': pares_con_datos,
                    'registros_usados': total_registros
                })

        except Exception as e:
            logger.error(f"Error en entrenamiento: {e}")
            self.finished.emit({
                'success': False,
                'error': str(e)
            })


# ========== HILO COLD START IA (AIEngineContinuous) ==========
class ColdStartAIThread(QThread):
    finished = pyqtSignal(dict)
    progress = pyqtSignal(str)

    def __init__(self, config: 'ConfiguracionTrading',
                 iq_bridge: 'IQOptionBridge'):
        super().__init__()
        self.config = config
        self.iq_bridge = iq_bridge

    def run(self):
        try:
            ai_engine = getattr(self.iq_bridge, "ai_engine", None)
            if ai_engine is None:
                self.finished.emit(
                    {"success": False, "error": "AIEngineContinuous no disponible"})
                return

            if hasattr(ai_engine,
                       "is_initialized") and ai_engine.is_initialized():
                self.finished.emit(
                    {"success": True, "skipped": True, "reason": "IA ya inicializada"})
                return

            if not getattr(self.iq_bridge, "connected", False):
                if not self.iq_bridge.connect():
                    self.finished.emit(
                        {"success": False, "error": "No conectado a IQ Option"})
                    return

            pares = []
            try:
                pares = (
                    getattr(
                        self.config,
                        "PARES_DETECTADOS_IQ",
                        None) or [])
                if not pares:
                    pares = (getattr(self.config, "PARES_TRADING", None) or [])
                if not pares:
                    pares = (
                        getattr(
                            self.config,
                            "PARES_OTC_MAYORES",
                            None) or [])
                if not pares:
                    pares = (
                        getattr(
                            self.config,
                            "PARES_14_DEFAULT",
                            None) or [])

                pares = [p for p in pares if isinstance(p, str) and p.strip()]
                vistos = set()
                pares_unicos = []
                for p in pares:
                    if p not in vistos:
                        vistos.add(p)
                        pares_unicos.append(p)
                pares = pares_unicos

                max_pares = int(
                    getattr(
                        self.config,
                        "COLDSTART_MAX_PARES",
                        0) or 0)
                if max_pares > 0:
                    pares = pares[:max_pares]
            except Exception:
                pares = []

            if not pares:
                self.finished.emit(
                    {"success": False, "error": "No hay pares para cold start"})
                return

            dias = int(getattr(self.config, "DIAS_HISTORICOS_COLDSTART", 7))
            max_velas = int(min(2000, max(300, dias * 24 * 12)))
            timeframe = 300
            end_time = time.time()

            dfs = []
            target_total = int(
                getattr(
                    self.config,
                    "COLDSTART_TARGET_VELAS_TOTAL",
                    20000) or 0)
            min_por_par = int(
                getattr(
                    self.config,
                    "COLDSTART_MIN_VELAS_POR_PAR",
                    120) or 120)
            delay_seg = float(
                getattr(
                    self.config,
                    "COLDSTART_DELAY_SEG",
                    0.35) or 0.0)
            velas_por_par = max_velas
            if target_total > 0 and len(pares) > 0:
                velas_por_par = max(min_por_par, min(
                    max_velas, int(target_total // max(1, len(pares)))))
            max_velas_par = int(
                getattr(self.config, "COLDSTART_MAX_VELAS_POR_PAR", 0) or 0)
            if max_velas_par > 0:
                velas_por_par = min(velas_por_par, max_velas_par)
            total_velas = 0

            for i, par in enumerate(pares, start=1):
                self.progress.emit(
                    f"🧊 Cold Start IA: descargando {par} ({i}/{
                        len(pares)}) | velas_par={velas_por_par} | total={total_velas}"
                )
                chunk_fetch = int(
                    getattr(self.config, "COLDSTART_CHUNK_SIZE", 600) or 600)
                if chunk_fetch < 100:
                    chunk_fetch = 100
                restantes = velas_por_par
                end_time_local = end_time
                velas = []
                while restantes > 0:
                    pedir = min(restantes, chunk_fetch)
                    velas_chunk = self.iq_bridge._sync_get_candles(
                        par, timeframe, pedir, end_time_local)
                    if not velas_chunk:
                        break
                    velas.extend(velas_chunk)
                    try:
                        oldest = min(
                            v.get("from", end_time_local) for v in velas_chunk
                            if isinstance(v, dict))
                        if isinstance(oldest, (int, float)):
                            end_time_local = float(oldest) - 1
                        else:
                            end_time_local -= timeframe * pedir
                    except Exception:
                        end_time_local -= timeframe * pedir
                    restantes -= len(velas_chunk)
                if not velas or len(velas) < 100:
                    continue
                df = pd.DataFrame(velas)
                df.rename(columns={'max': 'high', 'min': 'low'}, inplace=True)
                if {'open', 'high', 'low', 'close'}.issubset(df.columns):
                    dfs.append(df)
                    total_velas += len(df)
                if delay_seg > 0:
                    time.sleep(delay_seg)

            if not dfs:
                self.finished.emit(
                    {"success": False, "error": "Cold Start sin datos suficientes"})
                return

            combined_df = pd.concat(dfs, ignore_index=True)
            max_train_rows = int(
                getattr(self.config, "COLDSTART_MAX_TRAIN_ROWS", 0) or 0)
            if max_train_rows > 0 and len(combined_df) > max_train_rows:
                combined_df = combined_df.tail(
                    max_train_rows).reset_index(drop=True)
            self.progress.emit(
                f"🧊 Cold Start IA: entrenando con {
                    len(combined_df)} velas")
            ai_engine.cold_start_training(combined_df)

            ok = bool(getattr(ai_engine, "_is_initialized", False))
            self.finished.emit({"success": ok, "skipped": False, "velas": int(
                len(combined_df)), "pares": pares, "pares_usados": len(dfs)})
        except Exception as e:
            self.finished.emit({"success": False, "error": str(e)})


# ========== HILO DE ACTUALIZACIÓN EN VIVO ==========
class LiveUpdateWorker(QObject):
    """
    Worker para actualizaciones en tiempo real sin bloquear GUI.
    Usa QObject + moveToThread para ejecución persistente.
    """
    update_ready = pyqtSignal(dict)
    request_update = pyqtSignal(list)  # Señal para solicitar actualización

    def __init__(self, iq_bridge: 'IQOptionBridge',
                 motor_trading: 'MotorTradingOptimizado'):
        super().__init__()
        self.iq_bridge = iq_bridge
        self.motor_trading = motor_trading or get_motor_trading()
        self._is_busy = False

    def do_update(self, pares: list):
        """Ejecuta actualización para los pares dados con timeout"""
        if self._is_busy:
            return  # Ignorar si ya hay una actualización en curso

        self._is_busy = True
        start_time = time.time()
        max_time = 25.0

        try:
            resultados = {}
            cfg = getattr(self.iq_bridge, "config", None)
            min_candles = int(getattr(cfg, "MIN_CANDLES_REQUERIDAS", 50) or 50)
            # OPTIMIZACIÓN: Reducir velas para live update (más rápido)
            candles = 30 
            candles = max(candles, min_candles, 30)

            pares = [
                p for p in (
                    pares or []) if isinstance(
                    p, str) and p.strip()]
            pares = list(dict.fromkeys(pares))

            abiertos = None
            try:
                if getattr(self.iq_bridge, "connected", False) and getattr(
                        self.iq_bridge, "api", None):
                    open_time_info = self.iq_bridge._sync_get_all_open_time()
                    if isinstance(open_time_info, dict):
                        abiertos = set()
                        for mercado in ("binary", "turbo", "digital"):
                            m = open_time_info.get(mercado, {})
                            if not isinstance(m, dict):
                                continue
                            for par, info in m.items():
                                if isinstance(info, dict) and (
                                        info.get("open") or info.get("is_open")):
                                    abiertos.add(par)
            except Exception:
                abiertos = None

            for i, par in enumerate(pares):
                # OPTIMIZACIÓN: Liberar GIL cada 5 pares para evitar congelamiento de hilos
                if i > 0 and i % 5 == 0:
                    time.sleep(0.05)

                # Verificar timeout global
                if time.time() - start_time > max_time:
                    logger.debug(
                        f"[LIVE] Timeout alcanzado, procesados {
                            len(resultados)} pares")
                    break

                try:
                    if isinstance(abiertos, set) and par not in abiertos:
                        resultados[par] = {
                            'accion': 'CERRADO',
                            'ia_pct': 0.0,
                            'tec_pct': 0.0,
                            'confianza': 0.0,
                            'precio': 0.0,
                            'fortaleza': 'CERRADO',
                            'tipo_datos': 'CERRADO',
                            'indicadores': {}
                        }
                        continue

                    # Obtener datos frescos (1M, 5M, 15M para confluencia)
                    datos_5m = self.iq_bridge.obtener_datos_tiempo_real(
                        par, cantidad=candles, timeframe="5")
                    datos_1m = self.iq_bridge.obtener_datos_tiempo_real(
                        par, cantidad=candles, timeframe="1")
                    datos_15m = self.iq_bridge.obtener_datos_tiempo_real(
                        par, cantidad=candles, timeframe="15")

                    if (datos_5m is None or len(datos_5m) < min_candles or
                        datos_1m is None or len(datos_1m) < min_candles or
                            datos_15m is None or len(datos_15m) < min_candles):
                        resultados[par] = {
                            'accion': 'ESPERAR',
                            'ia_pct': 0.0,
                            'tec_pct': 0.0,
                            'confianza': 0.0,
                            'precio': 0.0,
                            'fortaleza': 'SIN_DATOS',
                            'tipo_datos': 'ERROR',
                            'indicadores': {}
                        }
                        continue

                    indicadores = ind_tec.get_analysis_pack(datos_5m)
                    if not indicadores:
                        resultados[par] = {
                            'accion': 'ESPERAR',
                            'ia_pct': 0.0,
                            'tec_pct': 0.0,
                            'confianza': 0.0,
                            'precio': 0.0,
                            'fortaleza': 'SIN_DATOS',
                            'tipo_datos': 'ERROR',
                            'indicadores': {}
                        }
                        continue

                    # Calcular señal MULTI-TIMEFRAME
                    senal = self.motor_trading.validar_confluencia_timeframes(
                        datos_1m, datos_5m, datos_15m, expiracion_segundos=300
                    )

                    # Extraer valores
                    accion = senal.get('accion', 'ESPERAR')
                    confianza_total = senal.get('confianza', 0)
                    ia_conf = senal.get('ia_confianza', None)
                    tec_conf = senal.get('tecnico_confianza', None)
                    if ia_conf is None or tec_conf is None:
                        ia_score = float(senal.get('ia_score', 0) or 0)
                        tecnico_score = float(
                            senal.get('tecnico_score', 0) or 0)
                        ia_conf = max(0.0, min(100.0, abs(ia_score) * 100.0))
                        tec_conf = max(
                            0.0, min(
                                100.0, abs(tecnico_score) * 100.0))

                    ia_pct = float(ia_conf)
                    tec_pct = float(tec_conf)

                    # Precio actual
                    precio = datos_5m['close'].iloc[-1] if 'close' in datos_5m.columns else 0
                    tipo_datos = None
                    try:
                        if 'tipo_datos' in datos_5m.columns:
                            tipo_datos = str(datos_5m['tipo_datos'].iloc[-1])
                    except Exception:
                        tipo_datos = None

                    # Fortaleza
                    umbral_destacada = getattr(
                        cfg, "UMBRAL_SEÑAL_DESTACADA", 85.0)
                    umbral_confirmada = getattr(
                        cfg, "UMBRAL_SEÑAL_CONFIRMADA", 92.0)

                    if confianza_total >= umbral_confirmada:
                        fortaleza = 'CONFIRMADA'
                    elif confianza_total >= umbral_destacada:
                        fortaleza = 'DESTACADA'
                    elif confianza_total >= 70:
                        fortaleza = 'FUERTE'
                    elif confianza_total >= 55:
                        fortaleza = 'MODERADA'
                    else:
                        fortaleza = 'DÉBIL'

                    resultados[par] = {
                        'accion': accion,
                        'ia_pct': ia_pct,
                        'tec_pct': tec_pct,
                        'confianza': confianza_total,
                        'precio': precio,
                        'fortaleza': fortaleza,
                        'tipo_datos': tipo_datos or 'REAL',
                        'indicadores': indicadores
                    }

                except Exception as e:
                    logger.debug(f"[LIVE] Error {par}: {e}")
                    resultados[par] = {
                        'accion': 'ERROR',
                        'ia_pct': 0.0,
                        'tec_pct': 0.0,
                        'confianza': 0.0,
                        'precio': 0.0,
                        'fortaleza': 'ERROR',
                        'tipo_datos': 'ERROR',
                        'indicadores': {}
                    }
                    continue

            # Emitir resultados
            if resultados:
                # Obtener balance actualizado (agregado para validación
                # constante)
                try:
                    if getattr(self.iq_bridge, "connected", False):
                        balance = self.iq_bridge.obtener_balance_actual()
                        resultados['__balance__'] = balance
                except Exception:
                    pass

                self.update_ready.emit(resultados)

        except Exception as e:
            logger.debug(f"[LIVE] Error general: {e}")
        finally:
            self._is_busy = False


# ========== HILO DE VERIFICACIÓN DE PARES ==========
class VerificarParesThread(QThread):
    """
    Hilo separado para verificar pares de 5 minutos sin bloquear la GUI.
    """
    finished = pyqtSignal(dict, dict)  # resultado_estado, resultado_5min
    error = pyqtSignal(str)
    progress = pyqtSignal(str)

    def __init__(self, config: 'ConfiguracionTrading'):
        super().__init__()
        self.config = config

    def run(self):
        """Ejecuta la verificación en un hilo separado"""
        try:
            self.progress.emit("Conectando a IQ Option...")
            iq_bridge_temp = IQOptionBridge(self.config)

            if iq_bridge_temp.connect():
                self.progress.emit("Obteniendo estado de pares...")
                resultado_estado = iq_bridge_temp.verificar_estado_pares()

                self.progress.emit("Verificando pares de 5 minutos...")
                resultado_5min = iq_bridge_temp.verificar_pares_5min()

                self.progress.emit("Desconectando...")
                try:
                    iq_bridge_temp.disconnect()
                except BaseException:
                    pass

                self.finished.emit(resultado_estado, resultado_5min)
            else:
                self.error.emit("No se pudo conectar a IQ Option")
                self.finished.emit({}, {})

        except Exception as e:
            logger.error(f"[VERIFICAR_PARES_THREAD] Error: {e}")
            self.error.emit(str(e))
            self.finished.emit({}, {})


# ========== HILO DE ESCANEO DE MERCADO ==========
class ScanThread(QThread):
    """
    Hilo separado para analizar pares de mercado sin bloquear la GUI.

    RESPONSABILIDAD ÚNICA:
    - Analizar una lista de pares YA VALIDADA
    - Emitir progreso y resultados

    NO HACE:
    - Obtener pares desde IQ Option
    - Decidir timeframes
    - Ejecutar trades
    - Controlar loops globales
    """

    finished = pyqtSignal(dict)
    progress = pyqtSignal(str, int, int)  # par, indice, total
    error = pyqtSignal(str)

    def __init__(
        self,
        config: 'ConfiguracionTrading',
        iq_bridge: 'IQOptionBridge',
        analizador_mercado: 'AnalizadorMercado',
        pares_a_analizar: Optional[List[str]] = None
    ):
        super().__init__()
        self.config = config
        self.iq_bridge = iq_bridge
        self.analizador_mercado = analizador_mercado
        self.pares_a_analizar = pares_a_analizar or []

        self._is_running = True

    # -------------------------------------------------
    # Control seguro del hilo
    # -------------------------------------------------
    def stop(self):
        """Detiene el escaneo de forma segura"""
        self._is_running = False

    # -------------------------------------------------
    # Ejecución principal del hilo
    # -------------------------------------------------
    def run(self):
        try:
            logger.info("[SCAN_THREAD] Iniciando escaneo de mercado...")

            # Callback seguro para progreso (Qt thread-safe)
            def callback_progreso(par: str, indice: int, total: int):
                if self._is_running:
                    self.progress.emit(par, indice, total)

            # Ejecutar análisis de mercado
            resultados = self.analizador_mercado.analizar_mercado_completo(
                iq_bridge=self.iq_bridge,
                pares=self.pares_a_analizar or None,
                callback_progreso=callback_progreso
            )

            if not self._is_running:
                logger.info("[SCAN_THREAD] Escaneo detenido manualmente.")
                self.finished.emit({})
                return

            if resultados:
                senales_detectadas = resultados.get('senales_detectadas') or []
                logger.info(
                    f"[SCAN_THREAD] Escaneo finalizado. "
                    f"Pares analizados: {
                        resultados.get(
                            'pares_analizados', 0)} | "
                    f"Señales detectadas: {len(senales_detectadas)}"
                )
                self.finished.emit(resultados)
            else:
                logger.warning(
                    "[SCAN_THREAD] Escaneo completado sin resultados.")
                self.finished.emit({})

        except Exception as e:
            logger.error(
                f"[SCAN_THREAD] Error crítico en escaneo: {e}",
                exc_info=True)
            self.error.emit(str(e))
            self.finished.emit({})


class PostScanThread(QThread):
    log = pyqtSignal(str)

    def __init__(self, config: 'ConfiguracionTrading', seguimiento_senales: 'SeguimientoSenales',
                 notificaciones: 'NotificacionesBot', senales: List[Dict[str, Any]]):
        super().__init__()
        self.config = config
        self.seguimiento_senales = seguimiento_senales
        self.notificaciones = notificaciones
        self.senales = senales or []

    def run(self):
        try:
            for senal in self.senales:
                try:
                    confianza = float(senal.get('confianza', 0) or 0)
                    if confianza < getattr(
                            self.config, 'UMBRAL_SEÑAL_DESTACADA', 0):
                        continue

                    par = senal.get('simbolo', '')
                    if not par:
                        continue

                    direccion = (
                        senal.get(
                            'señal',
                            'ESPERAR') or 'ESPERAR').upper()
                    if direccion in ['COMPRA', 'CALL']:
                        direccion = 'CALL'
                    elif direccion in ['VENTA', 'PUT']:
                        direccion = 'PUT'
                    else:
                        continue

                    precio = float(senal.get('precio_actual', 0) or 0)
                    indicadores = senal.get('indicadores', {}) or {}

                    senal_id = self.seguimiento_senales.registrar_senal_destacada(
                        par=par,
                        direccion=direccion,
                        confianza=confianza,
                        indicadores=indicadores,
                        precio_entrada=precio
                    )

                    if senal_id:
                        self.log.emit(
                            f"[SEGUIMIENTO] {par} {direccion} iniciado - ID: {senal_id}")
                        if getattr(
                                self.config, 'NOTIFICAR_SEÑALES_FUERTES', False):
                            try:
                                self.notificaciones.notificar_senal_fuerte(
                                    senal)
                            except Exception as notify_err:
                                logger.warning(
                                    f"Error notificando señal fuerte: {notify_err}")
                except Exception as e:
                    logger.warning(f"Error en post-procesado de señal: {e}")
        except Exception as e:
            logger.error(f"Error en PostScanThread: {e}", exc_info=True)


# ========== DIÁLOGOS DE CONFIGURACIÓN (NIVEL GLOBAL) ==========
class CredencialesIQDialog(QDialog):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("Configuración de Credenciales IQ Option")
        self.setFixedSize(400, 250)
        self.init_ui()

    def init_ui(self):
        layout = QVBoxLayout()

        # Formulario
        form_layout = QFormLayout()

        self.email_input = QLineEdit()
        self.email_input.setPlaceholderText("tu@email.com")
        form_layout.addRow("Email:", self.email_input)

        self.password_input = QLineEdit()
        self.password_input.setEchoMode(QLineEdit.Password)
        self.password_input.setPlaceholderText("Tu contraseña")
        form_layout.addRow("Contraseña:", self.password_input)

        layout.addLayout(form_layout)

        # Tipo de cuenta
        tipo_cuenta_layout = QHBoxLayout()
        tipo_cuenta_layout.addWidget(QLabel("Tipo de cuenta:"))

        self.tipo_practica = QRadioButton("Práctica (Demo)")
        self.tipo_real = QRadioButton("Real")

        self.tipo_practica.setChecked(True)

        tipo_cuenta_layout.addWidget(self.tipo_practica)
        tipo_cuenta_layout.addWidget(self.tipo_real)
        tipo_cuenta_layout.addStretch()

        layout.addLayout(tipo_cuenta_layout)

        # Botones
        buttons_layout = QHBoxLayout()

        self.btn_guardar = QPushButton("Guardar")
        self.btn_guardar.clicked.connect(self.guardar_credenciales)
        self.btn_guardar.setStyleSheet("""
            QPushButton {
                background-color: #4CAF50;
                color: white;
                border: none;
                padding: 8px 16px;
                border-radius: 4px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #45a049;
            }
        """)

        self.btn_cancelar = QPushButton("Cancelar")
        self.btn_cancelar.clicked.connect(self.reject)
        self.btn_cancelar.setStyleSheet("""
            QPushButton {
                background-color: #f44336;
                color: white;
                border: none;
                padding: 8px 16px;
                border-radius: 4px;
                font-weight: bold;
            }
            QPushButton:hover {
                background-color: #da190b;
            }
        """)

        buttons_layout.addWidget(self.btn_guardar)
        buttons_layout.addWidget(self.btn_cancelar)

        layout.addLayout(buttons_layout)
        self.setLayout(layout)

    def guardar_credenciales(self):
        email = self.email_input.text().strip()
        password = self.password_input.text().strip()

        if not email or not password:
            QMessageBox.warning(
                self,
                "Advertencia",
                "Por favor, introduce email y contraseña")
            return

        # Determinar tipo de cuenta
        tipo_cuenta = "PRACTICE" if self.tipo_practica.isChecked() else "REAL"

        credenciales = {
            'email': email,
            'password': password,
            'tipo_cuenta': tipo_cuenta
        }

        try:
            with open('iq_creds.json', 'w') as f:
                json.dump(credenciales, f, indent=4)

            QMessageBox.information(
                self, "Éxito", "Credenciales guardadas correctamente")
            self.accept()
        except Exception as e:
            QMessageBox.critical(
                self, "Error", f"No se pudieron guardar las credenciales: {e}")


