        self.config.AUTO_EJECUTAR_COOLDOWN_GLOBAL_SEG = self.auto_ejecutar_cooldown_global.value()
        self.config.AUTO_EJECUTAR_COOLDOWN_PAR_SEG = self.auto_ejecutar_cooldown_par.value()

