        # Configuración de Capital e Interés Compuesto
        self.config.CAPITAL_INICIAL = self.capital_inicial.value()
        self.config.MONTO_OPERACION = self.monto_operacion.value()
        self.config.PORCENTAJE_INVERSION = self.porcentaje_inversion.value() / 100.0
        self.config.INTERES_COMPUESTO_ACTIVO = self.interes_compuesto_activo.isChecked()

        # Configuración de Objetivo Diario
        self.config.OBJETIVO_GANANCIA_DIARIA = self.objetivo_ganancia_diaria.value()
        self.config.PAUSA_AL_OBJETIVO = self.pausa_al_objetivo.isChecked()
        self.config.REACTIVACION_AUTOMATICA = self.reactivacion_automatica.isChecked()

        # Configuración Multi-Timeframe
        self.config.USAR_TF_1M = self.usar_tf_1m.isChecked()
        self.config.USAR_TF_15M = self.usar_tf_15m.isChecked()
        self.config.UMBRAL_ALINEACION_TF = int(self.umbral_alineacion.value())

        # Configuración de Tipos de Pares - Mayores y Menores
        self.config.USAR_PARES_FOREX_MAYORES = self.usar_forex_mayores.isChecked()
        self.config.USAR_PARES_FOREX_MENORES = self.usar_forex_menores.isChecked()
        self.config.USAR_PARES_OTC_MAYORES = self.usar_otc_mayores.isChecked()
