        def escanear_activos_5min_disponibles(self, lista_pares):
            """
            Escanea los pares disponibles usando self.api
            """
            self.log_message(
                ">>> ESCANEANDO PLATAFORMA: Buscando pares habilitados (5 min)...")
            pares_validos = []

            try:
                all_info = self.iq_bridge._sync_get_all_open_time() if hasattr(self,
                                                                               "iq_bridge") else None

                if not all_info:
                    self.log_message(
                        "No se pudo obtener info de tiempos. Usando lista por defecto.")
                    return lista_pares

                for par in lista_pares:
                    bin_info = all_info.get(
                        'binary',
                        {}).get(
                        par,
                        {}) if isinstance(
                        all_info,
                        dict) else {}
                    tur_info = all_info.get(
                        'turbo',
                        {}).get(
                        par,
                        {}) if isinstance(
                        all_info,
                        dict) else {}
                    dig_info = all_info.get(
                        'digital',
                        {}).get(
                        par,
                        {}) if isinstance(
                        all_info,
                        dict) else {}
                    bin_open = bool(
                        isinstance(
                            bin_info, dict) and (
                            bin_info.get('open') or bin_info.get('is_open')))
                    tur_open = bool(
                        isinstance(
                            tur_info, dict) and (
                            tur_info.get('open') or tur_info.get('is_open')))
                    dig_open = bool(
                        isinstance(
                            dig_info, dict) and (
                            dig_info.get('open') or dig_info.get('is_open')))
                    if bin_open or tur_open or dig_open:
                        pares_validos.append(par)

            except Exception as e:
                self.log_message(f"Error en escaneo: {e}")
                return lista_pares

            if pares_validos:
                self.log_message(f"*** PARES HABILITADOS: {pares_validos} ***")
                return pares_validos
            else:
                self.log_message(
                    ">>> ALERTA: No hay pares disponibles para 5 min ahora mismo.")
                return []

        def _cargar_pares_iniciales_tabla(self):
            """✅ Carga los 14 pares predefinidos en la tabla inmediatamente al iniciar"""
            try:
                # Usar pares estáticos para mostrar inmediatamente
                es_fin_de_semana = datetime.now().weekday() >= 5
                if es_fin_de_semana:
                    pares_iniciales = self.config.PARES_OTC_MAYORES.copy()
                else:
                    pares_iniciales = self.config.PARES_FOREX_MAYORES.copy()

                # Añadir pares OTC también durante días laborables para mostrar
                # los 14
                if not es_fin_de_semana:
                    pares_iniciales.extend(self.config.PARES_OTC_MAYORES)

                self.log_mensaje(
                    f"✅ Cargando {
                        len(pares_iniciales)} pares en tabla...")

                # Limpiar y llenar tabla
                self.tabla_analisis.setRowCount(0)
                for fila, par in enumerate(pares_iniciales):
                    self.tabla_analisis.insertRow(fila)
                    self.tabla_analisis.setItem(fila, 0, QTableWidgetItem(par))
                    self.tabla_analisis.setItem(
                        fila, 1, QTableWidgetItem("ANALIZANDO..."))
                    self.tabla_analisis.setItem(
                        fila, 2, QTableWidgetItem("50.0%"))
                    self.tabla_analisis.setItem(
                        fila, 3, QTableWidgetItem("50.0%"))
                    self.tabla_analisis.setItem(
                        fila, 4, QTableWidgetItem("50.0%"))
                    self.tabla_analisis.setItem(
                        fila, 5, QTableWidgetItem("0.00000"))
                    self.tabla_analisis.setItem(
                        fila, 6, QTableWidgetItem("PENDIENTE"))
                    self.tabla_analisis.setItem(
                        fila, 7, QTableWidgetItem("PENDIENTE"))

                self.log_mensaje(
                    f"✅ {
                        len(pares_iniciales)} pares cargados en GUI")
            except Exception as e:
                logger.error(f"Error cargando pares iniciales: {e}")

        def refrescar_pares_gui(self):
            """Lee los pares disponibles del bridge y actualiza la Tabla de Análisis."""
            try:
                # 1. Obtener pares del bridge
                # Usamos config.PARES_TRADING que se actualiza cuando se llama
                # a _obtener_pares_disponibles_ahora
                pares = self.config.PARES_TRADING

                if not pares:
                    self.log_mensaje(
                        "No hay pares disponibles para mostrar en la GUI.")
                    return

                self.log_mensaje(f"Actualizando GUI con {len(pares)} pares...")

                # 2. Actualizar Tabla de Análisis
                self.tabla_analisis.setRowCount(0)  # Limpiar tabla

                for fila, par in enumerate(pares):
                    # Columna 0: Par
                    self.tabla_analisis.insertRow(fila)
                    item_par = QTableWidgetItem(par)
                    self.tabla_analisis.setItem(fila, 0, item_par)

                    # Columna 1: Señal (Inicial: Pendiente)
                    item_senal = QTableWidgetItem("PENDIENTE")
                    self.tabla_analisis.setItem(fila, 1, item_senal)

                    # Columna 2: IA % (Inicial: 0)
                    item_ia = QTableWidgetItem("0.0%")
                    self.tabla_analisis.setItem(fila, 2, item_ia)

                    # Columna 3: Tecnico % (Inicial: 0)
                    item_tec = QTableWidgetItem("0.0%")
                    self.tabla_analisis.setItem(fila, 3, item_tec)

                    # Columna 4: Confianza % (Inicial: 0)
                    item_conf = QTableWidgetItem("0.0%")
                    self.tabla_analisis.setItem(fila, 4, item_conf)

                    # Columna 5: Precio (Inicial: 0)
                    item_precio = QTableWidgetItem("0.00000")
                    self.tabla_analisis.setItem(fila, 5, item_precio)

                    # Columna 6: Fortaleza
                    item_fuerza = QTableWidgetItem("-")
                    self.tabla_analisis.setItem(fila, 6, item_fuerza)

                    # Columna 7: Tipo Datos
                    item_tipo = QTableWidgetItem("DESCONOCIDO")
                    self.tabla_analisis.setItem(fila, 7, item_tipo)

                self.log_mensaje("Tabla de análisis actualizada.")

                # 3. Actualizar Combo del Gráfico (si existe y está visible)
                if hasattr(
                        self, 'combo_par_grafico') and self.combo_par_grafico is not None:
                    self.combo_par_grafico.clear()
                    self.combo_par_grafico.addItems(pares)

                # 4. Actualizar Etiqueta de Estadísticas
                if hasattr(self, 'lbl_pares_stats'):
                    txt_stats = None
                    try:
                        with open("iq_option_pares_completos.json", "r", encoding="utf-8") as f:
                            snapshot = json.load(f)
                        conteos = snapshot.get(
                            "conteos", {}) if isinstance(
                            snapshot, dict) else {}
                        total = int(conteos.get("total_activos", len(pares)))
                        forex = int(conteos.get("forex", 0))
                        otc = int(conteos.get("otc", 0))
                        crypto = int(conteos.get("crypto", 0))
                        indices = int(conteos.get("indices", 0))
                        binarias = int(conteos.get("binarias", 0))
                        turbo = int(conteos.get("turbo", 0))
                        digitales = int(conteos.get("digitales", 0))
                        txt_stats = f"📊 Pares activos: {total} (Forex: {forex}, OTC: {otc}, Crypto: {crypto}, Índices: {indices} | Binarias: {binarias}, Turbo: {turbo}, Digitales: {digitales})"
                    except Exception:
                        txt_stats = f"📊 Pares activos: {len(pares)}"
                    self.lbl_pares_stats.setText(txt_stats)
                    self.lbl_pares_stats.setStyleSheet(
                        "color: #4CAF50; font-weight: bold;")

            except Exception as e:
                self.log_mensaje(f"Error actualizando GUI con pares: {e}")
                import traceback
                logger.error(f"Traceback GUI Pares: {traceback.format_exc()}")

        def start_bot(self):
            """
            Inicia el bot:
            - Conecta a IQ Option
            - Detecta pares abiertos reales (1m / 5m)
            - Ejecuta Cold Start Training (GUI FIX)
            - Lanza el trading automático
            """

            # ==================================================
            # 1. LOG DE INICIO
            # ==================================================
            self.log_message(">>> INICIANDO SISTEMA DE TRADING <<<")

            # ==================================================
            # 2. CONEXIÓN A IQ OPTION
            # 1️⃣ Conectar a IQ Option
            # ==================================================
            if not self.api.connected:
                self.log_message("Conectando a IQ Option...")
                if not self.api.connect():
                    self.log_message(
                        "❌ Error: No se pudo conectar a IQ Option.")
                    return
                self.log_message("✅ Conectado a IQ Option")
            else:
                self.log_message("✅ Conexión activa detectada")

            # 2️⃣ 👉 CREAR CONSOLA FLOTANTE (AQUÍ ES EL LUGAR CORRECTO)
            if not hasattr(self, "consola"):
                self.consola = ConsolaFlotante(
                    ai_engine=self.api.ai_engine,
                    log_file="IQ_Option 2.8.6_pro.log"
                )
            # ==================================================
            # 3. DETECCIÓN DE PARES ABIERTOS (REAL)
            # ==================================================
            self.log_message(
                "🔍 Escaneando pares activos (BINARIAS 1m / 5m)...")
            pares_habilitados = self.api.obtener_pares_disponibles_ahora()

            if not pares_habilitados:
                self.log_message("⚠️ No se encontraron pares habilitados")
                self.log_message(
                    "Posibles causas: mercado cerrado / mantenimiento")
                return

            self.log_message(
                f"✅ {
                    len(pares_habilitados)} pares habilitados detectados")

            # ==================================================
            # 4. ACTUALIZAR CONFIGURACIÓN GLOBAL
            # ==================================================
            self.config.PARES_TRADING = pares_habilitados
            self.config.ACTIVO = pares_habilitados[0]

            self.log_message(f"🎯 Activo principal: {self.config.ACTIVO}")

            # ==================================================
            # 5. COLD START TRAINING (🔥 FIX CRÍTICO GUI)
            # ==================================================
            self.log_message("=" * 55)
            self.log_message("🧊 INICIANDO COLD START TRAINING (MODO GUI)")
            self.log_message("=" * 55)

            ai_engine = getattr(self.api, "ai_engine", None)

            if not ai_engine:
                self.log_message(
                    "❌ AI Engine no disponible. Abortando inicio.")
                return

            if ai_engine.is_initialized():
                self.log_message("ℹ️ IA ya entrenada. Cold Start omitido.")
            else:
                dias_historicos = getattr(self.config, "DIAS_HISTORICOS", 7)
                timeframe_segundos = 300  # 5 minutos
                max_velas = min(
                    2000, dias_historicos * 24 * 12)  # 12 velas/hora

                training_pairs = pares_habilitados[:5]  # Top 5 pares reales
                all_training_data = []

                for par in training_pairs:
                    try:
                        self.log_message(
                            f"📥 Descargando histórico REAL: {par}")
                        velas = self.api._sync_get_candles(
                            par,
                            timeframe_segundos,
                            max_velas,
                            time.time()
                        )

                        if not velas or len(velas) < 100:
                            self.log_message(f"⚠️ {par}: datos insuficientes")
                            continue

                        df = pd.DataFrame(velas)
                        df.rename(
                            columns={
                                "max": "high",
                                "min": "low",
                                "open": "open",
                                "close": "close",
                                "volume": "volume"
                            },
                            inplace=True
                        )

                        all_training_data.append(df)
                        self.log_message(f"✅ {par}: {len(df)} velas cargadas")

                    except Exception as e:
                        self.log_message(f"⚠️ {par}: error histórico → {e}")

                if not all_training_data:
                    self.log_message(
                        "❌ Cold Start abortado: no se obtuvieron datos reales")
                    return

                combined_df = pd.concat(all_training_data, ignore_index=True)
                self.log_message(
                    f"📊 Total histórico: {
                        len(combined_df)} velas")

                try:
                    ai_engine.cold_start_training(combined_df)
                    self.log_message("✅ Cold Start Training COMPLETADO")
                except Exception as e:
                    self.log_message(f"❌ Error en Cold Start Training: {e}")
                    return

            # ==================================================
            # 6. INICIAR TRADING AUTOMÁTICO
            # ==================================================
            self.is_running = True
            self.trade_thread = threading.Thread(
                target=self.run_trading_thread,
                daemon=True
            )
            self.trade_thread.start()

            self.log_message("🚀 BOT INICIADO – IA ACTIVA Y ENTRENADA")

            # ==================================================
            # 7. ACTUALIZAR UI (SI EXISTE)
            # ==================================================
            if hasattr(self, "btn_start"):
                self.btn_start.setEnabled(False)
            if hasattr(self, "btn_stop"):
                self.btn_stop.setEnabled(True)

            # === CONSOLA FLOTANTE ===
            self.consola = ConsolaFlotante("IQ_Option 2.8.6_pro.log")

            gui_handler = LogHandlerGUI(self.consola)
            gui_handler.setLevel(logging.INFO)

            formatter = logging.Formatter(
                "%(asctime)s - %(name)s - %(levelname)s - %(message)s"
            )
            gui_handler.setFormatter(formatter)

            logging.getLogger().addHandler(gui_handler)

            # ==========================================
            # BUCLE PRINCIPAL DE TRADING (Hilo Segundo)
            # ==========================================
        def run_trading_thread(self):
            """
            Este método corre en un hilo separado para no congelar la ventana.
            """
            # Asumimos que tienes variables self.trading_activos y
            # self.stop_thread
            self.trading_activos = 0

            while self.is_running:
                try:
                    # 1. Límite de operaciones
                    if self.trading_activos >= self.config.MAX_OPERACIONES:
                        time.sleep(5)
                        continue

                    # 2. Obtener Velas (Usando self.ACTIVO actual)
                    try:
                        velas = self.api.get_candles(
                            self.config.ACTIVO, 60, 100, time.time())
                    except Exception as e:
                        time.sleep(2)
                        continue

                    if not velas:
                        time.sleep(1)
                        continue

                    # 3. Procesar Datos
                    df = pd.DataFrame(velas)
                    df.columns = [
                        'date', 'open', 'close', 'min', 'high', 'volume']
                    df.rename(columns={'min': 'low'}, inplace=True)
                    df.set_index('date', inplace=True)

                    # 4. Análisis (Motor + IA)
                    resultado = self.motor.calcular_senal_final(
                        df, self.config.TIEMPO_EXPIRACION)

                    # Mostrar en GUI (Log o Label)
                    self.log_message(
                        f"{
                            self.config.ACTIVO} | IA: {
                            resultado['confianza']:.1f}% | {
                            resultado['accion']}")

                    # 5. Ejecutar Orden
                    if resultado['accion'] in ['CALL', 'PUT']:
                        direction = resultado['accion'].lower()
                        id_compra = None
                        try:
                            usar_emulacion = bool(
                                getattr(
                                    self.config,
                                    "HABILITAR_EMULACION_HUMANA",
                                    True)) and bool(
                                getattr(
                                    self.config,
                                    "USAR_EJECUTOR_HUMANO",
                                    True))
                        except Exception:
                            usar_emulacion = True
                        if usar_emulacion:
                            try:
                                if not hasattr(
                                        self, "human_executor") or self.human_executor is None:
                                    self.human_executor = HumanMouseExecutor()
                            except Exception:
                                self.human_executor = HumanMouseExecutor()
                            id_compra = self.human_executor.ejecutar_orden_humana(
                                self.api, self.config.ACTIVO, resultado['accion'], float(
                                    self.config.MONTO_OPERACION), int(
                                    self.config.TIEMPO_EXPIRACION or 5))
                        else:
                            res = self.api.buy(
                                float(
                                    self.config.MONTO_OPERACION), self.config.ACTIVO, direction, int(
                                    self.config.TIEMPO_EXPIRACION or 5))
                            if isinstance(res, tuple) and len(res) >= 2:
                                ok, oid = res[0], res[1]
                                if ok and oid:
                                    id_compra = oid
                            elif res:
                                id_compra = res

                        if id_compra:
                            self.log_message(
                                f">>> ENTRADA: {
                                    direction.upper()} | ID: {id_compra}")
                            self.trading_activos += 1

                            # Esperar resultado
                            time.sleep(self.config.TIEMPO_EXPIRACION + 2)

                            # Feedback a IA
                            is_win = False
                            try:
                                ganancia = self.api.check_win_v3(id_compra)
                                if ganancia is not None:
                                    is_win = ganancia > 0
                                    self.log_message(
                                        f"{'WIN' if is_win else 'LOSS'}: {ganancia}")
                            except BaseException:
                                # Fallback simulado si falla la API
                                import random
                                is_win = random.choice([True, True, False])

                            self.ai_engine.learn_from_result(is_win)
                            self.trading_activos -= 1

                    time.sleep(1)

                except Exception as e:
                    self.log_message(f"Error en hilo trading: {e}")
                    time.sleep(5)

        def init_ui(self):
            """Inicializa la interfaz gráfica"""
            self.setWindowTitle(
                "IQ_Option v 2.2 - Sistema Automático de Trading Bynario- Creado por Lic: Aguirre Adolfo Daniel.")
