            splitter.addWidget(panel_central)
            splitter.addWidget(panel_derecho)
            splitter.setSizes([300, 800, 500])
            main_layout.addWidget(splitter)

            # Barra de estado
            self.status_bar = QStatusBar()
            self.setStatusBar(self.status_bar)
