            self.lbl_tipo_cuenta = QLabel("📊 Tipo: No definido")
            self.lbl_tipo_cuenta.setStyleSheet(
                "color: #888888; font-weight: bold;")
            estado_layout.addWidget(self.lbl_tipo_cuenta)
            self.lbl_balance = QLabel("💰 Balance: $0.00")
            self.lbl_balance.setStyleSheet(
                "color: #888888; font-weight: bold;")
            estado_layout.addWidget(self.lbl_balance)
            self.lbl_modelo = QLabel("🔴 Modelo no entrenado")
