        def _instalar_log_stream_gui(self):
            try:
                if not hasattr(self, "text_logs") or self.text_logs is None:
                    return
                if not hasattr(
                        self, "_gui_log_queue") or self._gui_log_queue is None:
                    self._gui_log_queue = Queue()

                def _cb(msg: str):
                    try:
                        self._gui_log_queue.put_nowait(msg)
                    except Exception:
                        pass
                
                # Usar señal segura si está disponible
                global _safe_log_emitter
                if _safe_log_emitter:
                    try:
                        _safe_log_emitter.new_log.connect(_cb)
                    except Exception:
                        pass
                
                if not hasattr(
                        self, "_gui_log_timer") or self._gui_log_timer is None:
                    self._gui_log_timer = QTimer()
                    self._gui_log_timer.timeout.connect(
                        self._flush_gui_log_queue)
                    self._gui_log_timer.start(200)
            except Exception:
                pass

        def _flush_gui_log_queue(self):
            try:
                if not hasattr(self, "text_logs") or self.text_logs is None:
                    return
                if not hasattr(
                        self, "_gui_log_queue") or self._gui_log_queue is None:
                    return
                drained = 0
                while drained < 80:
                    try:
                        msg = self._gui_log_queue.get_nowait()
                    except Empty:
                        break
                    except Exception:
                        break
                    try:
                        self.text_logs.append(msg)
                    except Exception:
                        break
                    drained += 1
                if drained:
                    try:
                        cursor = self.text_logs.textCursor()
                        cursor.movePosition(cursor.End)
                        self.text_logs.setTextCursor(cursor)
                    except Exception:
                        pass
            except Exception:
                pass

