    def _init_ui(self):
        # Configurar Estilos TTK
        style = ttk.Style()
        style.theme_use('clam')

        # Notebook (Tabs)
        style.configure("TNotebook", background=self.color_bg, borderwidth=0)
        style.configure("TNotebook.Tab",
                        background=self.color_panel,
                        foreground=self.color_fg,
                        padding=[15, 8],
                        font=("Consolas", 10))

        style.map("TNotebook.Tab",
                  background=[("selected", self.color_accent)],
                  foreground=[("selected", "white")])

        # Scrollbar (Intentar oscurecer)
        style.configure("Vertical.TScrollbar",
                        background=self.color_panel,
                        troughcolor=self.color_bg,
                        bordercolor=self.color_bg,
                        arrowcolor=self.color_fg)

        # --- LAYOUT PRINCIPAL ---
        main_frame = tk.Frame(self.window, bg=self.color_bg)
        main_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        # Header
        header = tk.Frame(main_frame, bg=self.color_bg)
        header.pack(fill=tk.X, pady=(0, 10))
        tk.Label(header, text="CONFIGURACIÓN DEL SISTEMA",
                 bg=self.color_bg, fg="white", font=("Consolas", 14, "bold")).pack(side=tk.LEFT)

        # Notebook
        self.notebook = ttk.Notebook(main_frame)
        self.notebook.pack(expand=True, fill='both')

        # Crear pestañas
        self._init_tab_senales()
        self._init_tab_trading()
        self._init_tab_entrenamiento()
        self._init_tab_general()
        self._init_tab_capital()
        self._init_tab_timeframe()
        self._init_tab_pares()
        self._init_tab_telegram()
        self._init_tab_iq_creds()

        # Botones de Acción
        btn_frame = tk.Frame(self.window, bg=self.color_bg)
        btn_frame.pack(fill=tk.X, pady=15, padx=20)

        def _btn_hover(btn, color_enter, color_leave):
            btn.bind("<Enter>", lambda e: btn.config(bg=color_enter))
            btn.bind("<Leave>", lambda e: btn.config(bg=color_leave))

        # Botón Guardar
        btn_save = tk.Button(btn_frame, text="GUARDAR CAMBIOS", command=self.guardar,
                             bg=self.color_success, fg="white", font=("Consolas", 10, "bold"),
                             relief="flat", padx=20, pady=10, cursor="hand2")
        btn_save.pack(side=tk.RIGHT)
        _btn_hover(btn_save, "#45a049", self.color_success)

        # Botón Cancelar
        btn_cancel = tk.Button(btn_frame, text="CANCELAR", command=self.window.destroy,
                               bg=self.color_danger, fg="white", font=("Consolas", 10),
                               relief="flat", padx=15, pady=10, cursor="hand2")
        btn_cancel.pack(side=tk.RIGHT, padx=15)
        _btn_hover(btn_cancel, "#d32f2f", self.color_danger)

    def _create_scrollable_frame(self, parent):
        canvas = tk.Canvas(parent, bg=self.color_panel, highlightthickness=0)
        scrollbar = ttk.Scrollbar(
            parent, orient="vertical", command=canvas.yview)
        scrollable_frame = tk.Frame(canvas, bg=self.color_panel)

        scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )

        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)

        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")

        # Bind mousewheel
        def _on_mousewheel(event):
            canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        # Bind solo cuando el mouse está encima
        canvas.bind(
            "<Enter>",
            lambda _: canvas.bind_all(
                "<MouseWheel>",
                _on_mousewheel))
        canvas.bind("<Leave>", lambda _: canvas.unbind_all("<MouseWheel>"))

        return scrollable_frame

    def _add_entry(self, parent, label, config_key, default, width=15):
        frame = tk.Frame(parent, bg=self.color_panel)
        frame.pack(fill=tk.X, pady=5, padx=10)

        tk.Label(frame, text=label, **self.style_lbl).pack(side=tk.LEFT)

        val = getattr(self.config, config_key, default)
        var = tk.StringVar(value=str(val))

        entry = tk.Entry(
            frame,
            textvariable=var,
            width=width,
            **self.style_entry)
        entry.pack(side=tk.RIGHT)

        self.vars[config_key] = var
        return var

    def _add_checkbox(self, parent, label, config_key, default):
        val = getattr(self.config, config_key, default)
        var = tk.BooleanVar(value=bool(val))

        frame = tk.Frame(parent, bg=self.color_panel)
        frame.pack(fill=tk.X, pady=2, padx=10)

        cb = tk.Checkbutton(frame, text=label, variable=var,
                            bg=self.color_panel, fg=self.color_fg,
                            selectcolor=self.color_bg,  # Mejor contraste en dark mode
                            activebackground=self.color_panel,
                            activeforeground="white",
                            font=("Consolas", 10),
                            cursor="hand2")
        cb.pack(anchor="w")
        self.vars[config_key] = var
        return var

    def _add_title(self, parent, text, color=None):
        if color is None:
            color = self.color_accent
        tk.Label(parent, text=text, bg=self.color_panel, fg=color,
                 font=("Consolas", 11, "bold"), pady=15, padx=5).pack(anchor="w")

        # Separador visual
        sep = tk.Frame(parent, bg=self.color_border, height=1)
        sep.pack(fill=tk.X, padx=5, pady=(0, 10))

    def _add_info(self, parent, text):
        tk.Label(parent, text=f"ℹ {text}", bg=self.color_panel, fg="#888888",
                 font=("Consolas", 9, "italic"), justify=tk.LEFT, padx=15).pack(anchor="w", pady=(0, 5))

